/**
 * Synthesize the team-setup compendium: one agent per theme distills the raw,
 * redundant docs-sweep extractions (claims + best practices + gotchas) into a clean,
 * dense, organized reference section. Returns { [theme]: markdown }.
 */
export const meta = {
  name: "synthesize-compendium",
  description: "Distill per-theme docs extractions into a clean compendium section",
  phases: [{ title: "Synthesize" }],
};

const CHUNK = {"Config & memory (CLAUDE.md, settings)": {"pages": ["artifacts", "claude-directory", "debug-your-config", "env-vars", "fullscreen", "interactive-mode", "keybindings", "memory", "model-config", "output-styles", "settings", "statusline", "terminal-config"], "bestPractices": ["Record design tokens (colors, fonts, spacing) in the project's CLAUDE.md or a theme file so artifacts match product branding automatically — Claude treats your design system as higher precedence than its own defaults.", "To keep one shared artifact updated across sessions, always pass the artifact URL into the new session; otherwise you fragment into duplicate artifacts.", "Reduce artifact token cost: prefer SVG/HTML/CSS for diagrams over raster images, omit unneeded interactivity, and have the page summarize large datasets rather than inline them in full.", "For org governance, use the audit log (claude_artifact_* events) and the Compliance API to inventory/delete artifacts; set distinct retention periods for private vs shared artifacts.", "In CI/non-interactive contexts (Agent SDK, GitHub Action, MCP server) artifacts are already off by default; to hard-disable org-wide use the admin Capabilities toggle, and per-session use disableArtifact / CLAUDE_CODE_DISABLE_ARTIFACT / permissions.deny Artifact.", "Ask Claude explicitly for a specific title and emoji icon if branding matters — Claude auto-picks both and they appear in the gallery and shared links.", "Keep CLAUDE.md under ~200 lines: longer files still load fully but reduce adherence. When it approaches 200 lines, split into .claude/rules/*.md.", "Move anything that only matters for specific tasks OUT of CLAUDE.md into a skill or a path-scoped rule (paths: frontmatter) so it loads only when needed — CLAUDE.md loads into EVERY session.", "List your most-used commands (build, test, lint, format) in CLAUDE.md so Claude knows them without being told each time.", "For team-shared config, commit CLAUDE.md, .claude/settings.json, .mcp.json, skills/, agents/, rules/, workflows/, output-styles/; keep personal overrides in settings.local.json (gitignored) and CLAUDE.local.md.", "Use ${ENV_VAR} references for MCP secrets in .mcp.json so tokens never land in committed files.", "Restrict subagent tool access with the tools: frontmatter (e.g. a read-only reviewer limited to Read, Grep, Glob) to prevent unintended edits.", "Keep global ~/.claude/CLAUDE.md short and limited to cross-project preferences (response style, commit format) since it loads alongside every project's CLAUDE.md.", "For enterprise governance use managed-settings.json (overrides everything) to enforce permissions and policy users cannot override.", "Reduce plaintext-transcript exposure by lowering cleanupPeriodDays, setting CLAUDE_CODE_SKIP_PROMPT_HISTORY, and adding permission deny rules for credential files.", "Set disable-model-invocation: true on destructive skills (e.g. /deploy) so only a human can trigger them; use user-invocable: false to let Claude auto-invoke a skill while hiding it from the / menu.", "Use .worktreeinclude to copy gitignored files like .env into new worktrees so parallel/isolated sessions are not missing local config.", "When a configured feature isn't taking effect, run /context first to confirm what actually loaded, then drill into the specific category command (/memory, /skills, /hooks, /mcp, /permissions).", "Run /doctor to validate config files and surface invalid keys/schema errors; run /status to see active settings sources and whether managed (org) settings are overriding yours.", "Use CLAUDE.md for 'we do it this way here' guidance; use permissions or hooks for security boundaries and anything that must never happen — they enforce regardless of what Claude decides.", "For team policy that must be guaranteed (not just guidance), deploy managed settings — they always win over user/project/local and partially apply even in --safe-mode and clean config dirs.", "Isolate config problems with a two-step bisect: first 'claude --safe-mode' (disables all customizations but keeps auth/perms); if the problem disappears, a customization surface is the cause. If it persists, run a fully clean session via CLAUDE_CONFIG_DIR pointed at an empty dir launched from a clean directory, then reintroduce files one at a time.", "Define hooks only under the \"hooks\" key in settings.json (not a standalone file), use a single string matcher with | for multiple tools, and capitalize tool names exactly (Bash/Edit/Write/Read).", "Use absolute paths for local MCP server scripts in .mcp.json command/args; relative paths break when launching from a different directory.", "Set MCP server environment variables in per-server env blocks inside .mcp.json, not in settings.json env.", "Don't rely on Bash(rm *)-style prefix deny rules as a hard guarantee — they only match the literal string; use a PreToolUse hook or sandbox to actually block destructive commands.", "When delegating to built-in Explore/Plan subagents, restate critical CLAUDE.md instructions in the prompt since those agents don't load CLAUDE.md.", "Set shared team env config (timeouts, model IDs, disable flags) in the source-controlled `.claude/settings.json` `env` block rather than relying on each member's shell exports — this distributes config via the repo.", "For LLM-gateway/proxy setups, set `ENABLE_TOOL_SEARCH=true` (since `ANTHROPIC_BASE_URL` disables MCP tool search on non-first-party hosts), `CLAUDE_CODE_ATTRIBUTION_HEADER=0` to improve prompt-cache hit rate, and `CLAUDE_CODE_DISABLE_EXPERIMENTAL_BETAS=1` if the proxy rejects beta headers.", "Use `ANTHROPIC_DEFAULT_HAIKU_MODEL` (not the deprecated `ANTHROPIC_SMALL_FAST_MODEL`) to control the cheap background-task model, lowering cost on title/summary/background work.", "Tune long-session context cost with `CLAUDE_AUTOCOMPACT_PCT_OVERRIDE` (lower-only) or `CLAUDE_CODE_AUTO_COMPACT_WINDOW` to compact earlier on large codebases.", "For locked-down/air-gapped or compliance environments, set `CLAUDE_CODE_DISABLE_NONESSENTIAL_TRAFFIC=1` (one switch) plus `CLAUDE_CODE_DISABLE_1M_CONTEXT=1` for compliance and `CLAUDE_CODE_DISABLE_POLICY_SKILLS=1` for CI/containers.", "Use `apiKeyHelper` + `CLAUDE_CODE_API_KEY_HELPER_TTL_MS` for centralized, rotating credential delivery instead of pasting static API keys into each developer's config.", "In CI / non-interactive pipelines, prefer `claude -p` with `ANTHROPIC_API_KEY` set (used without an approval prompt), and detect nested execution via `CLAUDECODE=1` in hooks/scripts.", "Raise `API_TIMEOUT_MS` and `BASH_MAX_TIMEOUT_MS` in the project `env` block when the team works behind slow proxies or runs long builds, instead of having members hit defaults.", "For long-running agent sessions and large codebases where context grows, enable fullscreen rendering (/tui fullscreen) to keep memory flat and stop scroll-jumping/flicker in VS Code terminal, tmux, and iTerm2.", "If your team relies on native terminal selection/search (common over SSH or in tmux), set CLAUDE_CODE_NO_FLICKER=1 CLAUDE_CODE_DISABLE_MOUSE=1 to get flat-memory benefits without losing native copy-on-select.", "Standardize CLAUDE_CODE_SCROLL_SPEED=3 (vim default) for terminals like the VS Code integrated terminal that send one scroll event per notch.", "Add `set -g mouse on` to shared ~/.tmux.conf so wheel scrolling reaches Claude Code in tmux setups.", "Use `! <cmd>` shell mode for quick build/test/git operations: on v2.1.186+ Claude auto-explains the output (e.g. `! npm test` -> failure analysis) without a second prompt, keeping conversation context intact.", "Run long builds/tests/dev servers in the background (prompt Claude to background, or press Ctrl+B) so the session stays responsive; Claude retrieves output via the Read tool when ready.", "Use `/btw` for quick lookups during a long-running task to avoid cluttering or derailing the main context; fork with `f` if you need to continue with tool access.", "For multi-agent/multi-session work on one project, set CLAUDE_CODE_TASK_LIST_ID to a shared name so all sessions track the same task list under ~/.claude/tasks/.", "In automation/print mode, use `--prompt-suggestions --output-format stream-json --verbose` to capture prompt_suggestion messages, or set CLAUDE_CODE_ENABLE_PROMPT_SUGGESTION=false to suppress them.", "Use Ctrl+R reverse search and Ctrl+S to scope across all projects / this project / this session when reusing prior prompts.", "Open the transcript viewer with Ctrl+O to expand collapsed MCP calls (shown as 'Called X N times') when debugging tool usage.", "For team-portable keybindings, bind to `ctrl`/`meta` modifiers rather than `cmd`/super, since most terminals do not report the Super modifier.", "Avoid binding Ctrl+B / Ctrl+A / Ctrl+Z in shared configs since they collide with tmux/screen/shell job-control; use Ctrl+X chords (the built-in pattern) when a multiplexer-safe binding is needed.", "Run `/doctor` after editing keybindings to catch parse errors, invalid contexts, reserved/multiplexer conflicts, and duplicate bindings.", "Keep each CLAUDE.md under 200 lines; longer files consume more context and reduce adherence. Imports do NOT reduce context (they load at launch) — use path-scoped rules to actually defer context.", "Write concrete, verifiable instructions: 'Use 2-space indentation' / 'Run npm test before committing' / 'API handlers live in src/api/handlers/' — not vague directives.", "Use markdown headers and bullets to group rules; Claude scans structure like a reader.", "Add to CLAUDE.md when: Claude repeats a mistake, a review catches something it should know, you retype a correction from last session, or a new teammate would need the same context.", "Put project-level team standards in project CLAUDE.md (source-controlled); keep personal prefs in CLAUDE.local.md (gitignored) or ~/.claude/CLAUDE.md.", "For large/monorepo projects, split instructions into .claude/rules/ with paths: frontmatter so they load only for matching files.", "In monorepos, use claudeMdExcludes in .claude/settings.local.json to skip other teams' ancestor CLAUDE.md files.", "Periodically review CLAUDE.md, nested CLAUDE.md, and .claude/rules/ for outdated or contradictory instructions — conflicts make Claude pick arbitrarily.", "Reuse existing AGENTS.md by importing it (@AGENTS.md at top of CLAUDE.md) rather than duplicating; add Claude-specific instructions below.", "For org governance: use managed settings (permissions.deny, sandbox.enabled, env, forceLoginMethod) for technical ENFORCEMENT and managed CLAUDE.md for behavioral GUIDANCE.", "For anything that must run at a fixed lifecycle point (before commit, after edit) or be hard-blocked, use a hook (PreToolUse / lifecycle hooks), not CLAUDE.md — CLAUDE.md is not enforcement.", "Run /init (or CLAUDE_CODE_NEW_INIT=1 for the interactive flow) to bootstrap a project CLAUDE.md, then refine with things Claude can't discover itself.", "Use /memory to verify which instruction files are actually loaded when Claude isn't following instructions; add conversation-only instructions to CLAUDE.md so they survive /compact.", "Use block-level HTML comments in CLAUDE.md for human-maintainer notes — they're stripped before entering context and cost no tokens.", "Share rules across projects via symlinks into .claude/rules/ pointing at a central company-standards directory.", "For teams on Bedrock/Vertex/Foundry/Claude Platform on AWS, pin model versions via ANTHROPIC_DEFAULT_*_MODEL with version-specific IDs as part of initial setup, so admins control when users move to new models rather than aliases lagging or pointing to unavailable models.", "To fully control which model users run (not just initial selection), combine all four in managed/policy settings: 'model' (initial), 'availableModels' (allowlist), 'enforceAvailableModels': true (makes Default obey allowlist), and ANTHROPIC_DEFAULT_*_MODEL env (pins what an allowed alias resolves to). Using 'model' alone is bypassable via the Default picker option.", "Enforce a strict org allowlist by setting availableModels in MANAGED or POLICY settings (it replaces lower-precedence lists); user/project settings can only merge/widen, and only v2.1.175+ supports strict managed replacement.", "Use opusplan (or opusplan[1m]) to get Opus reasoning during planning and cheaper/faster Sonnet during execution automatically — a built-in cost optimization at the plan/execution boundary.", "Use the ANTHROPIC_DEFAULT_HAIKU_MODEL to pin the fast/background model (replaces deprecated ANTHROPIC_SMALL_FAST_MODEL) and CLAUDE_CODE_SUBAGENT_MODEL to standardize subagent/agent-team models org-wide.", "For cost-sensitive workloads, lower the effort level (medium/low) rather than always running default high/xhigh; reserve max for demanding tasks and test before adopting broadly since it can overthink with diminishing returns.", "Use the literal keyword 'ultrathink' in a prompt for one-off deeper reasoning instead of permanently raising effort; ordinary phrasings like 'think hard' are not recognized.", "When pinning provider-specific model IDs (Bedrock ARNs etc.), set _SUPPORTED_CAPABILITIES so effort/thinking features aren't silently disabled by failed pattern matching, and _NAME/_DESCRIPTION for a readable picker.", "In CI/non-interactive pipelines, don't parse stderr for model warnings under JSON output; read the actual model from the modelUsage field of the result message (stderr warnings are suppressed for json/stream-json).", "With Fable 5 in security/biology codebases, expect frequent first-turn fallback to Opus from CLAUDE.md/git context; use claude --safe-mode to isolate whether your customizations are the trigger.", "Append [1m] per env variable (ANTHROPIC_DEFAULT_OPUS_MODEL='claude-opus-4-8[1m]') to enable extended context on third-party providers; the suffix is per-variable, so a same model without [1m] elsewhere stays at 200K.", "Use an output style when you keep re-prompting for the same voice/format every turn; for project conventions or codebase context use CLAUDE.md instead, not an output style.", "For a non-coding role (writing assistant, data analyst), omit keep-coding-instructions so the SWE instructions are dropped; for a still-coding-but-different-communication style (e.g. diagrams-first), set keep-coding-instructions: true.", "Distribute team-wide output styles via the project .claude/output-styles directory (or a plugin's output-styles/), and enforce with the managed-policy .claude/output-styles directory in the managed settings dir.", "Commit a chosen team style by setting outputStyle in a shared project settings file rather than relying on each user picking it in /config (which writes to settings.local.json).", "After changing output style, run /clear or start a new session - the change does not apply mid-session since the system prompt is read once at session start.", "Use --append-system-prompt for one-off system-prompt additions instead of creating a full output style.", "Be aware Explanatory and Learning styles intentionally produce longer responses (higher output token cost); use Default when minimizing tokens matters.", "Commit .claude/settings.json (shared permissions, env, model policy, hooks) and .mcp.json (approved MCP servers) to the repo; keep .claude/settings.local.json gitignored for personal overrides.", "Lock model/cost team-wide by setting availableModels AND enforceAvailableModels:true together — availableModels alone does not lock the default model.", "Write deny rules for secrets explicitly: Read(./.env), Read(./.env.*), Read(./secrets/**), plus Bash(curl *) and Bash(rm -rf *); deny always beats allow across all scopes.", "For enterprise governance, deploy managed-settings.json in the system dir (or via MDM/registry) with allowManagedPermissionRulesOnly:true and allowManagedMcpServersOnly:true + allowedMcpServers to prevent user/project overrides.", "Use the managed-settings.d/ drop-in directory with numeric-prefixed fragments (10-telemetry.json, 20-security.json) to compose policy modularly instead of one monolithic file.", "Pin versions in managed settings with requiredMinimumVersion/requiredMaximumVersion and set forceRemoteSettingsRefresh:true to fail-closed until policy is fetched.", "Restrict HTTP hooks with allowedHttpHookUrls and limit env interpolation to httpHookAllowedEnvVars; set allowManagedHooksOnly:true to block untrusted user/project hooks.", "Put team-wide instructions in the managed/project claudeMd key (and use claudeMdExcludes to skip vendored CLAUDE.md files) rather than relying on each developer's local memory.", "Run claude doctor to validate settings before rolling config out to a fleet.", "Use `workspace.current_dir` rather than `cwd` for consistency with `workspace.project_dir` (both hold the same value).", "Cache slow operations (git status/diff) to a temp file refreshed every ~5s; the script runs frequently and slow scripts cause lag. Key the cache filename on `session_id` (stable per session, unique across sessions) — NOT on PID/`$$`/`os.getpid()`, which change every invocation and defeat the cache.", "Always guard against null/absent fields with fallbacks: jq `// 0` for numbers, `// empty` for optional fields like `rate_limits`; use optional chaining (`?.`) in JS and `.get(...) or 0` in Python.", "Keep status line output short — limited width truncates or wraps; system notifications (MCP errors, auto-updates, context-low warning, verbose token counter) share the right side of the same row and can truncate output on narrow terminals.", "Set `refreshInterval` when displaying time-based data (clock) or when background subagents mutate git state while the main session is idle, since event triggers go quiet during idle waits.", "Test scripts independently with mock JSON input before configuring (e.g. `echo '{...}' | ./statusline.sh`).", "Use `printf '%b'` instead of `echo -e` for ANSI/OSC 8 escape sequences — more reliable across shells.", "Set `hideVimModeIndicator: true` if your script renders `vim.mode` itself, to avoid showing the mode twice.", "Prefer single-line plain-text output when robustness matters; multi-line + escape codes are more prone to rendering glitches that overlap with other UI updates.", "For team distribution, commit the status line script and a project `.claude/settings.json` with the `statusLine` config so the whole team gets a consistent bar; plugins can ship a default `subagentStatusLine`.", "For long-running tasks, configure a Notification hook (hooks.Notification in ~/.claude/settings.json) or set preferredNotifChannel so the team gets bell/desktop alerts when Claude finishes or needs a permission decision — lets people switch to other work.", "On large codebases or flickery sessions, default to fullscreen rendering by putting CLAUDE_CODE_NO_FLICKER=1 in the settings.json env block; it keeps memory flat as scrollback grows.", "For large inputs (whole files, long logs), write content to a file and have Claude read it by path instead of pasting — keeps the transcript readable and lets later turns reference the file. Mandatory in the VS Code integrated terminal where large pastes can lose characters.", "Standardize terminal env in settings.json env block so the same notification/fullscreen behavior applies for everyone; settings.json is the shareable surface for these terminal-related env vars and hooks.", "If a team uses tmux, distribute the three ~/.tmux.conf lines (allow-passthrough on + extended-keys) so Shift+Enter and notifications work for everyone."], "gotchas": ["Artifacts silently degrade: when any availability condition fails Claude just writes a LOCAL HTML file or says it cannot publish — a local HTML file with no link means the tool is not enabled, not a bug.", "An artifact is a capture, NOT an application — no backend, no form storage, no view-time API calls, no multiple routes; relative links don't resolve.", "A new session without the artifact URL creates a NEW artifact rather than updating the existing one — easy to accidentally orphan versions.", "Bedrock/Vertex/Foundry and API-key/gateway-token/cloud-credential auth all silently block artifacts even on a Team/Enterprise plan; you must be /login-authenticated to claude.ai with the Anthropic API provider.", "Styled artifact pages are more token-intensive than terminal text; embedded raster images as data URIs are the biggest hidden token (and 16 MiB size) cost.", "CMEK, HIPAA, or Zero Data Retention org settings disable artifacts entirely — a compliance posture decision blocks the feature.", "managed-settings.json overrides EVERYTHING — including CLI flags like --permission-mode and --settings; users cannot override org policy.", "Global vs project CLAUDE.md are both loaded into context (not key-merged), but settings.json files ARE merged key-by-key — different mechanics for two file types that look similar.", "settings merge: arrays (permissions.allow) combine across all scopes, but scalars (model) silently take only the most-local value — a project model can override your global default without warning.", "output-styles by default DROP the built-in software-engineering instructions; forgetting keep-coding-instructions: true can degrade coding behavior. Style changes also only apply NEXT session (prompt frozen at startup).", "If a skill and command share a name the skill wins; project workflow/output-style beats same-named global one — name collisions resolve by precedence, not error.", "settings.local.json is auto-added to ~/.config/git/ignore, but a custom core.excludesFile won't get it automatically and it isn't added to project .gitignore — teammates may accidentally commit their own.", ".worktreeinclude is git-only: if you use a WorktreeCreate hook for another VCS, the file is silently ignored and you must copy files inside the hook.", "MCP servers in .claude.json are personal-only; putting a server there expecting the team to get it won't work — team servers must go in .mcp.json.", "Transcripts are plaintext and unencrypted: a single tool read of a .env or a command printing a secret writes that secret to disk in <session>.jsonl.", "claude project purge requires v2.1.124+; --all deletes history.jsonl outright (not filtered) and shell-snapshots/ + backups/ are never purged because they are not project-scoped.", "Auto memory (MEMORY.md) and subagent agent-memory only load the first 200 lines / 25KB — content past that cap is silently not loaded at startup.", "Some env vars override their equivalent setting and some don't — behavior varies per-variable, so you can't assume an env var wins.", "Config added to ~/.claude.json (permissions/hooks/env) is silently ignored — those keys belong in ~/.claude/settings.json.", "Hook matcher as a JSON array, lowercase tool name, or hooks in a standalone file all fail silently or get dropped; array values are schema errors that drop the hook entry.", "settings.local.json silently overrides settings.json (and both override user settings) — a value can appear 'ignored' because a closer scope set it.", "MCP relative paths in command/args resolve against the launch directory, not .mcp.json's location — server fails to start from some directories.", "settings.json env does NOT propagate to MCP child processes; servers start missing expected env unless set in .mcp.json per-server env.", "settings.json has no mcpServers key — MCP servers added there never appear.", ".mcp.json placed under .claude/ or in Claude Desktop format never loads; it must be at repo root.", "Bash(rm *) deny rules don't block /bin/rm or find -delete because prefix rules match the literal command string, not the executable.", "Built-in Explore and Plan subagents skip CLAUDE.md, so they ignore project conventions unless restated in the delegating prompt.", "A skill placed as .claude/skills/name.md (flat file) won't show in /skills; a skill with disable-model-invocation: true won't be auto-invoked (shows 'user-only').", "A missing project-MCP approval prompt (dismissed) leaves the server disabled with no obvious error.", "Managed org settings still apply in --safe-mode and in clean CLAUDE_CONFIG_DIR sessions, so policy-configured hooks/status line can still run when you think you've isolated everything.", "Env vars are read at startup only — editing settings.json or exports does not affect the running session; you must restart `claude`.", "`CLAUDE_CODE_DEBUG_LOGS_DIR` is a FILE path, not a directory, despite the name; and it requires a separate debug-enable flag to actually write logs.", "`CLAUDE_AUTOCOMPACT_PCT_OVERRIDE` can only LOWER the compaction threshold — values above the default are silently ignored.", "`CLAUDE_CODE_AUTO_COMPACT_WINDOW` affects only compaction, NOT the status-line `used_percentage`, so the displayed context % decouples from the actual compaction trigger.", "`API_TIMEOUT_MS` values above 2147483647 cause immediate failure rather than being clamped.", "`ANTHROPIC_API_KEY` set in interactive mode requires approval and silently overrides a Pro/Max/Team subscription — a surprise source of unexpected API billing.", "`ANTHROPIC_BASE_URL` (proxy) silently disables MCP tool search on non-first-party hosts unless `ENABLE_TOOL_SEARCH=true` is explicitly set.", "Disabling telemetry (`DISABLE_TELEMETRY`/`DO_NOT_TRACK`) also disables feedback surveys unless `CLAUDE_CODE_ENABLE_FEEDBACK_SURVEY_FOR_OTEL=1` re-enables them.", "`CLAUDE_CODE_DISABLE_CRON=1` stops already-scheduled tasks from firing, not just new ones.", "Nested/child interactive sessions (`CLAUDE_CODE_CHILD_SESSION=1`) are excluded from `--resume`/`--continue`/history/`claude agents` unless `CLAUDE_CODE_FORCE_SESSION_PERSISTENCE=1` is set.", "`CLAUDE_CODE_CONNECT_TIMEOUT_MS` was removed (v2.1.186+) and is now a no-op — use `API_TIMEOUT_MS` instead.", "Fullscreen mode breaks terminal-native Cmd+f and tmux search/copy because the conversation lives in the alternate screen buffer, not scrollback; you must use Ctrl+o transcript mode and `[` to recover searchable text.", "Mouse capture in fullscreen disables your terminal's native copy-on-select; over SSH/tmux this is the most common friction. Hold the terminal-specific override key (Fn for Terminal.app, Option for iTerm2, Shift for VS Code/most terminals) for a one-off native selection, or set CLAUDE_CODE_DISABLE_MOUSE=1.", "Incompatible with iTerm2's tmux integration mode (tmux -CC): mouse wheel does nothing and double-click can corrupt terminal state. Regular tmux inside iTerm2 (without -CC) works.", "tmux requires `set -g mouse on` in ~/.tmux.conf for wheel scrolling; without it wheel events go to tmux not Claude Code. tmux lacks synchronized output so more flicker may appear, especially over SSH.", "iTerm2 requires per-profile 'Enable mouse reporting' (Settings → Profiles → Terminal) for wheel scrolling, click-to-expand, and text selection.", "Over SSH, clipboard copy falls back to OSC 52 escape sequences which some terminals (e.g. iTerm2) block by default until enabled; /terminal-setup enables it for iTerm2.", "Background/attached sessions (agent view or `claude attach`) always use fullscreen rendering; the `tui` setting and CLAUDE_CODE_DISABLE_ALTERNATE_SCREEN do not apply to them.", "JetBrains IDE terminal ignores CLAUDE_CODE_SCROLL_SPEED and /scroll-speed is unavailable there; 2025.2 has scroll-wheel bugs (upgrade to 2025.3+).", "v2.1.186+ behavior change: `! <command>` now triggers an automatic Claude response (and a full-prompt cost) instead of silently adding output to context; teams relying on the old quiet behavior must set respondToBashCommands=false.", "Background tasks are killed if output exceeds 5GB and are cleaned up on exit — don't rely on them surviving the session.", "tmux users: Ctrl+B is the tmux prefix, so backgrounding requires pressing Ctrl+B twice.", "`/btw` has NO tool access — it cannot read files, run commands, or search; it only answers from what is already in context.", "Reverse search (Ctrl+R) defaults scope to prompts from ALL projects, so prior prompts from unrelated repos may surface unless you narrow scope with Ctrl+S.", "Block-wise visual mode (Ctrl+V) is unsupported in vim editor mode.", "Session recap and prompt suggestions are on by default and consume tokens (small, cache-reused), but recap is skipped in non-interactive mode and suggestions are off in print mode by default.", "macOS Option/Alt shortcuts (Alt+B/F/Y/M/P) require configuring Option as Meta in the terminal, or they won't work.", "Keybindings are user-scope only (~/.claude/keybindings.json) — there is no documented project-level, enterprise-managed, or team-distributable keybindings mechanism, so they can't be centrally governed like settings.json.", "`cmd`/super-modified bindings silently won't fire in most terminals because they don't transmit the Super modifier.", "Uppercase letter alone implies Shift (e.g. `K` == `shift+k`), but an uppercase letter WITH a modifier does NOT (e.g. `ctrl+K` == `ctrl+k`).", "Unbinding only some chords on a shared prefix still leaves the prefix in chord-wait mode for the remaining bindings.", "In vim mode, Escape switches INSERT->NORMAL and does NOT trigger `chat:cancel`; vim and keybindings operate at different layers.", "CLAUDE.md is loaded in full regardless of size; only auto memory's MEMORY.md is truncated (200 lines / 25KB). Large CLAUDE.md silently degrades adherence rather than being cut.", "@path imports do NOT save context — imported files fully expand into context at launch. Only path-scoped rules defer loading.", "@path imports resolve relative to the file containing the import, NOT the working directory — easy to get wrong.", "The # quick-add shortcut / 'remember this' goes to AUTO MEMORY, not CLAUDE.md; people expecting it in CLAUDE.md will not find it there.", "Subdirectory (below cwd) CLAUDE.md files are NOT loaded at launch and do NOT re-inject after /compact — they load only when Claude reads a file in that subdir, so nested instructions can silently be absent.", "After /compact only the project-root CLAUDE.md is re-injected; nested CLAUDE.md and conversation-only instructions can be lost until a subdir file is read.", "--add-dir does not load CLAUDE.md from extra dirs unless CLAUDE_CODE_ADDITIONAL_DIRECTORIES_CLAUDE_MD=1 is set.", "Declining the external-import approval dialog the first time permanently disables imports for that project (dialog never reappears).", "CLAUDE.md is delivered as a user message after the system prompt — there is no strict compliance; vague or conflicting instructions get picked arbitrarily.", "Auto memory is machine-local and not synced across machines or cloud environments, despite being shared across worktrees of the same repo.", "Managed policy CLAUDE.md cannot be excluded by claudeMdExcludes or user settings — org instructions always apply.", "claudeMd inline key only works in managed/policy settings; placing it in user/project/local settings silently has no effect.", "On Windows, AGENTS.md symlink needs Administrator or Developer Mode; use @AGENTS.md import instead.", "Auto memory requires v2.1.59+; older clients silently lack it.", "autoMemoryDirectory set in project settings is only honored after accepting the workspace trust dialog.", "The 'model' setting is initial selection only, NOT enforcement: a user can open /model and pick Default, resolving to their tier's system default regardless of 'model'. You must add enforceAvailableModels (and env pins) to actually constrain it.", "availableModels by default does NOT restrict the Default option — only enforceAvailableModels:true (with non-empty list, v2.1.175+) closes this gap. Even with availableModels:[], users keep Default for their tier.", "availableModels merges across user/project/local but managed/policy REPLACES the merged result — entries in user/project cannot widen a managed allowlist. Strict replacement only works on v2.1.175+; earlier versions merge managed with lower-precedence entries (allowlist leaks).", "Aliases (opus/sonnet) resolve to OLDER versions on Bedrock/Vertex/Foundry (e.g. opus=4.6, sonnet=4.5) than on the Anthropic API (opus=4.8, sonnet=4.6) — selecting 'opus' gives different models depending on provider unless pinned.", "Resumed sessions keep their saved model regardless of your current 'model' setting, which can surprise you if you changed defaults between sessions.", "You are billed for all thinking tokens even when collapsed or redacted; thinking cannot be disabled at all on Fable 5.", "Sonnet with 1M context is excluded from the automatic Opus 1M upgrade and always consumes usage credits — even on Max — unlike Opus which is included on Max/Team/Enterprise.", "Fable 5 content fallback can trigger on the very first request before you send anything unusual, because that request carries CLAUDE.md and git status; a security/biology repo trips the classifier on context alone.", "CLAUDE_CODE_EFFORT_LEVEL env var overrides all other effort settings (including frontmatter and configured level), which can mask a project's intended effort if set in the shell environment.", "On Bedrock/Vertex/Foundry the [1m] suffix is read per env variable, not per model: the same model ID without [1m] in another variable still uses 200K context.", "When opusplan runs but availableModels excludes Opus, it silently stays on Sonnet in plan mode (no Opus reasoning phase); likewise a Haiku session won't upgrade to Sonnet in plan mode if Sonnet is excluded.", "ANTHROPIC_BASE_URL does NOT change which model answers — only where requests go; people expecting it to switch models will be wrong.", "In non-interactive/SDK mode that can't show a prompt, a Fable-5-flagged request ends the turn with a refusal instead of switching — can break automated pipelines using Fable 5.", "Custom output styles silently DROP the built-in software-engineering instructions unless keep-coding-instructions: true is set - a custom style can unintentionally make Claude stop scoping changes, writing comments, and verifying work.", "Output style changes do NOT take effect mid-session; they require /clear or a new session because the system prompt is read once at start.", "Selecting a style via /config writes to .claude/settings.local.json (local, typically gitignored), so it does not propagate to teammates unless you set outputStyle in a shared/committed settings file.", "A plugin with force-for-plugin: true overrides the user's own outputStyle setting; with multiple such plugins enabled, the first loaded silently wins.", "The standalone /output-style command no longer exists (removed in v2.1.91) - older docs/muscle-memory will fail; use /config or edit outputStyle.", "On nested project .claude/output-styles directories, same-named styles collide and the closest-to-working-directory one wins (only resolved this way as of v2.1.178).", "Output styles changing the system prompt invalidate prompt caching for that session segment (see prompt-caching docs).", "Local settings (.claude/settings.local.json) override both project and user settings — easy to accidentally lock in test/personal config that beats the committed team config.", "Permission rules MERGE across scopes (they don't replace), so a managed/user deny can silently override a project allow; reason about the deny>ask>allow precedence, not file order alone.", "~/.claude.json holds OAuth tokens and per-project state — never commit it. .claude/settings.local.json is auto-gitignored only when Claude creates it; if you create it manually you must add it yourself.", "availableModels without enforceAvailableModels:true does NOT lock the default model — cost lockdown is incomplete.", "enableAllProjectMcpServers:true auto-approves all .mcp.json servers (handy for CI, dangerous for untrusted/cloned repos); cloned .mcp.json servers require workspace-trust acceptance before loading.", "claude.ai MCP connectors auto-fetch by default — set disableClaudeAiConnectors or allowManagedMcpServersOnly to stop them.", "deniedMcpServers takes precedence over allowedMcpServers — you cannot force-allow a denied server.", "fallbackModel is capped at 3 entries; extra entries are silently ignored.", "Invalid managed-settings.json entries are tolerated (stripped + warned) since v2.1.169, BUT security fields like allowedMcpServers fail closed and become an empty list = full lockdown if malformed.", "Hook failures don't block the turn and aren't surfaced to the user — they're only logged, so a broken CI/governance hook can pass silently.", "forceRemoteSettingsRefresh:true causes the CLI to EXIT if the remote settings fetch fails (fail-closed by design).", "NO_COLOR/FORCE_COLOR in the env key are passed to subprocesses but do NOT change Claude Code's own UI; set them in the shell before launch to affect the interface.", "Legacy Windows managed path C:\\ProgramData\\ClaudeCode\\ stopped working as of v2.1.75 — migrate to C:\\Program Files\\ClaudeCode\\.", "Status line is silently disabled if `disableAllHooks: true` is set anywhere in settings — easy to miss when troubleshooting a blank bar.", "Requires workspace trust acceptance (same gate as hooks); without it you get `statusline skipped · restart to fix` and must restart to accept the trust prompt.", "Editing the script does not take effect immediately — changes appear only on the next interaction that triggers an update.", "Scripts that exit non-zero or produce no output cause the status line to go blank. Output must go to stdout, not stderr.", "`cost.total_cost_usd` is a client-side estimate and may differ from your actual bill.", "`tput cols` and width-detection libraries return wrong/empty values inside the script because output is captured, not attached to a TTY — must use `COLUMNS`/`LINES` env vars (v2.1.153+).", "Semantics of `context_window.total_input_tokens`/`total_output_tokens` changed in v2.1.132 from cumulative session totals to current context usage — scripts written against older versions may double-count.", "`used_percentage` excludes output tokens; manually summing all of `current_usage` (including output) will not match the displayed percentage.", "Status line `used_percentage` may differ from `/context` output because of when each is calculated.", "On Windows with Git Bash, unquoted backslashes in the `command` path are consumed as escapes and the script fails silently with no visible error — use forward slashes.", "`rate_limits` only exists for Pro/Max subscribers and only after the first API response; absent for API-key users, so don't rely on it.", "OSC 8 links render as literal `\\e]8;;` text in terminals without hyperlink support or when SSH/tmux strip OSC sequences; Terminal.app never supports them.", "/terminal-setup must run in the host terminal, not inside tmux or screen, because it writes to the host terminal's config file.", "Inside tmux, Shift+Enter and notifications/progress bar silently break until ~/.tmux.conf passthrough + extended-keys are set — even if the outer terminal supports Shift+Enter.", "VS Code integrated terminal can drop characters from very large pastes before they reach Claude Code (data loss); use file-based workflows.", "Vim motions are not remappable through the keybindings file, and Enter still submits in INSERT mode unlike real Vim.", "gnome-terminal and JetBrains IDEs (PyCharm, Android Studio) cannot do Shift+Enter at all; users must use Ctrl+J or \\ then Enter.", "On macOS most terminals don't send Option as a modifier by default, so Option-key shortcuts (Option+Enter newline, Option+P model switch) silently do nothing until 'Use Option as Meta Key' / Esc+ is enabled.", "Notification hooks run alongside the built-in notification rather than replacing it.", "Invalid/unknown theme tokens or color values are silently ignored (a typo won't break rendering but also won't apply)."], "claims": ["Artifacts require a Team or Enterprise plan and are in beta. On Team plans artifacts are ON by default; on Enterprise plans an admin must enable them in claude.ai admin settings.", "Artifacts require a session signed in to claude.ai via /login. Sessions using an API key, LLM gateway token, or cloud-provider credential CANNOT publish artifacts.", "Artifacts require the Anthropic API model provider — NOT available on Amazon Bedrock, Google Vertex AI, or Microsoft Foundry.", "Artifacts are unavailable when the org has Customer-Managed Encryption Keys (CMEK), HIPAA, or Zero Data Retention enabled.", "Artifacts are OFF by default in Agent SDK, GitHub Action, and MCP-server contexts, and when CLAUDE_CODE_DISABLE_NONESSENTIAL_TRAFFIC env var is set. Desktop app requires version 1.13576.0 or later.", "Disable artifacts per-session via any of: settings file \"disableArtifact\": true; env var CLAUDE_CODE_DISABLE_ARTIFACT=1; or permission rule adding 'Artifact' to permissions.deny.", "Env var CLAUDE_CODE_ARTIFACT_AUTO_OPEN=0 stops the browser from auto-opening when a new artifact is published.", "Publishing a NEW artifact prompts for permission (e.g. 'Claude wants to publish ... to a private page on claude.ai'); republishing an already-approved artifact does NOT prompt again. Press Ctrl+] to reopen the most recent artifact from the terminal.", "Sharing is org-scoped only: viewers must sign in to claude.ai as a member of the same org; there is no way to share an artifact outside the org (share the raw HTML file for external recipients). Artifacts are view-only, not co-edited; the author remains sole writer.", "Published source file must be .html, .htm, or .md (Markdown renders as styled HTML). Rendered page must be <= 16 MiB; large embedded images are the usual cause of size-failure.", "Artifacts are served under a strict CSP: no external requests (scripts, stylesheets, fonts, images blocked from other hosts; fetch/XHR/WebSocket blocked), no backend, single page (relative links don't resolve; uses in-page anchors). CSS/JS inlined, images embedded as data URIs.", "Org admin controls: claude.ai admin-settings/claude-code; Settings > Claude Code > Capabilities > Artifacts toggle enables/disables org-wide. Enterprise RBAC can scope artifacts per-role via Settings > Roles > Artifacts permission under Claude Code group.", "Retention policy set at Settings > Data & privacy controls, with separate retention periods for still-private vs shared artifacts. Artifact content stored on Anthropic-operated infrastructure, visible only to authenticated members of the publishing org.", "Audit log records publish/share/delete events under claude_artifact_* event types.", "Viewer loads artifacts from a sandboxed *.claudeusercontent.com origin; orgs restricting outbound network must allowlist that domain alongside claude.ai.", "Compliance API endpoints: GET /v1/compliance/code/artifacts (list), GET /v1/compliance/code/artifacts/{artifact_id}/versions/{version_id} (retrieve version content), DELETE /v1/compliance/code/artifacts/{artifact_id} (delete).", "To update an artifact from a different session you MUST give Claude the artifact's URL; without the URL a new session always creates a new artifact instead of updating. Each publish creates a version; the Share control selects which version viewers see.", "Claude applies a built-in design skill when building artifacts; it looks for an existing project design system FIRST. Precedence: your prompt > your project design system (e.g. CLAUDE.md design tokens) > Claude's own choices.", "Project-scope config lives under .claude/ in the repo, EXCEPT CLAUDE.md, .mcp.json, and .worktreeinclude which live at the project root. Global-scope config lives in ~/.claude/ and applies across all projects.", "CLAUDE.md is loaded into context at the start of every session. It also works at .claude/CLAUDE.md if you prefer to keep the project root clean.", "Project CLAUDE.md and global ~/.claude/CLAUDE.md are BOTH loaded into context together (not merged key-by-key); when instructions conflict, project-level takes priority.", "CLAUDE.local.md (project root) holds your private per-project preferences, loaded alongside CLAUDE.md; create it manually and add it to .gitignore. It is not shown in the explorer.", "settings.json (project and global) holds permissions, hooks, statusLine, model, env, outputStyle. Precedence (lowest to highest): global settings.json < project settings.json < project settings.local.json < CLI flags (e.g. --permission-mode, --settings) < managed-settings.json.", "Settings merge rule: array settings like permissions.allow COMBINE across all scopes; scalar settings like model use the MOST SPECIFIC value (most local wins).", "managed-settings.json is system-level (location varies by OS), enterprise-enforced, and takes precedence over EVERYTHING including CLI flags. See server-managed settings.", "remote-settings.json under ~/.claude/ is a cached copy of server-managed (organization) settings, refreshed on each launch; only present when the org has configured them.", "settings.local.json is project-only, gitignored. Claude Code adds it to ~/.config/git/ignore the first time it writes one; with a custom core.excludesFile you must add the pattern there too. To share the ignore rule, also add it to project .gitignore.", ".mcp.json (project root, committed) holds team-shared, project-scoped MCP servers. MCP tool schemas are DEFERRED by default and load on demand via tool search.", "Personal MCP servers go in ~/.claude.json: user scope applies across all projects, local scope is per-project but not committed. claude mcp add --scope user writes to ~/.claude.json; team-shared servers go in .mcp.json.", "MCP env secrets use shell-environment variable references like ${GITHUB_TOKEN}, read when Claude Code starts the server, so the token never lands in the file.", ".claude/rules/*.md: rules WITHOUT paths: frontmatter load at session start (like CLAUDE.md); rules WITH paths: globs load only when Claude reads a matching file. Subdirectories (e.g. .claude/rules/frontend/react.md) are auto-discovered. Rules are guidance, not enforced.", "Skills live at skills/<name>/SKILL.md (a folder, can bundle supporting files). Frontmatter description determines auto-invocation; disable-model-invocation: true makes it user-only (/name); user-invocable: false hides it from the / menu but Claude can still invoke it.", "Skills/commands accept arguments: /deploy staging passes 'staging' as $ARGUMENTS; positional access via $0, $1, etc. A line of form !`shell command` runs the command and injects its output into the prompt. ${CLAUDE_SKILL_DIR} placeholder references bundled scripts.", "commands/*.md are single-file prompts invoked with /name; same mechanism as skills and both can be auto-invoked. If a skill and command share a name, the SKILL takes precedence. Docs recommend new workflows use skills/ instead.", "agents/*.md define subagents, each running in its own fresh context window with its own system prompt (the file body), optional model, and tool access restricted via tools: frontmatter (e.g. tools: Read, Grep, Glob). @-mention to delegate.", "workflows/*.js are dynamic workflow scripts (written by Claude, saved from /workflows with 's'); each file becomes a /<name> command. A project workflow takes precedence over a personal ~/.claude/workflows/ one with the same name.", "Subagent persistent memory: memory: project frontmatter writes to .claude/agent-memory/<agent>/MEMORY.md (committed, team-shared); memory: local writes to .claude/agent-memory-local/; memory: user writes to ~/.claude/agent-memory/. First 200 lines (capped 25KB) of MEMORY.md load into the subagent system prompt.", "Auto memory (main session) lives at ~/.claude/projects/<project>/memory/MEMORY.md; Claude writes it itself. On by default; toggle with /memory or autoMemoryEnabled setting. First 200 lines OR 25KB (whichever first) of MEMORY.md load at session start; topic files (e.g. debugging.md) read on demand.", "output-styles/*.md append a section to the system prompt and BY DEFAULT drop the built-in software-engineering task instructions; set keep-coding-instructions: true to keep them. Changes take effect only on the next session (system prompt fixed at startup for caching). Built-in styles: Explanatory, Learning. Project styles override global same-name styles.", ".worktreeinclude (project root, committed) lists gitignored files (.gitignore syntax) to copy into new worktrees created via --worktree, the EnterWorktree tool, or subagent isolation: worktree. Only files that match AND are gitignored are copied. Git-only: a WorktreeCreate hook for another VCS does NOT read this file.", "~/.claude.json holds app state: theme, OAuth session, per-project trust decisions, personal MCP servers, UI toggles (autoConnectIde, externalEditorContext). Managed via /config. The projects key tracks per-project trust and last-session metrics.", "~/.claude/plugins holds cloned marketplaces, installed plugin versions, and per-plugin data, managed by claude plugin commands. Orphaned plugin versions are deleted 7 days after a plugin update or uninstall.", "Transcripts and history under ~/.claude are PLAINTEXT and not encrypted at rest; OS file permissions are the only protection. Anything passing through a tool (file contents, command output, pasted text, a .env read) lands in projects/<project>/<session>.jsonl.", "Auto-cleanup: files under projects/, file-history/, plans/, debug/, paste-cache/, image-cache/, session-env/, tasks/, shell-snapshots/, backups/, feedback-bundles/ are deleted on startup once older than cleanupPeriodDays (default 30 days).", "Persist indefinitely (not auto-cleaned): history.jsonl (every prompt typed, for up-arrow recall), stats-cache.json (token/cost for /usage), remote-settings.json.", "CLAUDE_CODE_SKIP_PROMPT_HISTORY env var skips writing transcripts and prompt history in any mode. Non-interactive: --no-session-persistence with -p, or persistSession: false in the Agent SDK.", "claude project purge <path> deletes per-project state (transcripts, auto memory, tasks/debug/file-history entries, matching history.jsonl lines, the ~/.claude.json entry). Requires Claude Code v2.1.124+. Flags: --dry-run, --yes (skip confirm), --all (purge every project), -i (step through). Leaves shell-snapshots/ and backups/ alone.", "Do NOT delete ~/.claude.json, ~/.claude/settings.json, or ~/.claude/plugins/ — they hold auth, preferences, and installed plugins.", "Some environment variables take precedence over their equivalent setting, but this varies per-variable; check the env-vars reference for each one.", "plans/ holds plan files written during plan mode; debug/ logs written only when started with --debug or via /debug.", "/context shows everything occupying the context window for the current session, broken down by category: system prompt, memory files, skills, MCP tools, conversation messages. Run it first to confirm CLAUDE.md/rules/skill descriptions are present.", "Per-category inspection commands: /memory (which CLAUDE.md and rules files loaded + auto-memory), /skills (project/user/plugin skills), /agents (subagents), /hooks (active hooks), /mcp (connected servers + status), /permissions (resolved allow/deny rules in effect), /doctor (config diagnostics: invalid keys, schema errors, install health), /debug [issue] (enables debug logging + diagnoses), /status (active settings sources incl. whether managed settings are in effect).", "Subdirectory CLAUDE.md files load on demand when Claude reads a file in that directory with the Read tool — not at session start, and not when writing/creating files there.", "Settings precedence: managed settings always win when present. Among the rest, closer scope overrides broader in order: local, then project, then user. CLI flags and environment variables act as another override layer.", "settings.local.json overrides settings.json, and both override ~/.claude/settings.json.", "In /doctor, press 'f' to send the diagnostic report to Claude to walk through fixes.", "Project-scoped MCP servers in .mcp.json require a one-time approval; if the prompt was dismissed the server stays disabled until approved from /mcp.", "MCP relative paths in command/args resolve against the directory Claude Code was launched from, NOT the location of .mcp.json — a frequent cause of failed servers. Use absolute paths for local scripts; PATH executables like npx/uvx work as-is.", "An MCP server connected but listing zero tools: select Reconnect from /mcp; if still zero, run 'claude --debug mcp' to see the server's stderr.", "Hooks must go under the \"hooks\" key in a settings file (settings.json), not a standalone file. Only plugins load a separate hooks/hooks.json. If a hook doesn't appear in /hooks it isn't being read.", "Hook matcher is a single STRING using | to match multiple tools, e.g. \"Edit|Write\". An array value is a schema error: Claude shows a settings error, /doctor reports it, and the hook entry is dropped. Matching is case-sensitive; tool names are capitalized (Bash, Edit, Write, Read) — \"bash\" never matches.", "Edits to settings.json take effect in the running session after a brief file-stability delay; no restart needed. If /hooks shows the old definition after a few seconds, run /hooks again to refresh.", "'claude --debug hooks' watches hook evaluation live: logs each event, which matchers were checked, and the hook's exit code and output.", "'claude --safe-mode' (min-version 2.1.169) launches a session with all customizations disabled: CLAUDE.md, skills, plugins, hooks, MCP servers, custom commands and agents. Authentication, model selection, built-in tools, and permissions still work. Managed settings deployed by an org still partially apply, so policy-configured hooks and status line run even in safe mode.", "Clean-config test: point CLAUDE_CONFIG_DIR at an empty dir to bypass everything under ~/.claude, and launch from a dir with no .claude folder/.mcp.json/CLAUDE.md. Example: 'cd /tmp && CLAUDE_CONFIG_DIR=/tmp/claude-clean claude'.", "Managed settings still apply even in a clean CLAUDE_CONFIG_DIR session because they live at a system path outside ~/.claude.", "With a clean CLAUDE_CONFIG_DIR on Linux/Windows you'll be prompted to log in again (credentials stored under the config dir); on macOS credentials are in the Keychain and carry over.", "~/.claude.json holds app state and UI toggles. permissions, hooks, and env belong in ~/.claude/settings.json — these are two different files. Config added to ~/.claude.json is ignored.", "settings.json does NOT read an mcpServers key. Define project servers in .mcp.json at repo root, or run 'claude mcp add --scope user' for user-scoped servers.", "Project .mcp.json goes at the repository root, NOT inside .claude/, and not in Claude Desktop's config format.", "Skills must be a folder with SKILL.md inside: .claude/skills/name/SKILL.md — a flat .claude/skills/name.md will not appear in /skills.", "A skill with 'disable-model-invocation: true' in frontmatter shows a \"user-only\" badge in /skills and Claude won't trigger it on its own.", "MCP env vars in settings.json 'env' do NOT propagate to MCP child processes; set per-server env inside .mcp.json instead.", "Bash prefix deny rules (e.g. Bash(rm *)) match the literal command string, not the underlying executable — they don't block /bin/rm or 'find -delete'. Add explicit patterns per variant, or use a PreToolUse hook or the sandbox for a hard guarantee.", "Built-in Explore and Plan subagents skip CLAUDE.md; custom subagents load it like the main conversation. For Explore/Plan, restate the instruction in the delegating prompt; for custom subagents put critical instructions in the agent file body (becomes the agent's system prompt).", "Session-end cleanup logic requires a SessionEnd hook in settings.json.", "Env vars can be set via the `env` block in settings files (e.g. `{\"env\": {\"API_TIMEOUT_MS\": \"1200000\"}}`); the four settings tiers are `~/.claude/settings.json` (user/all projects), `.claude/settings.json` (team/project, source-controlled), `.claude/settings.local.json` (user/this project only), and managed settings (org-wide, admin-deployed).", "Precedence: environment variables override settings.json fields; CLI flags (`--model`) and slash commands (`/model`) override env vars; `CLAUDE_CODE_EFFORT_LEVEL` overrides `/effort`. Env vars are read at startup only — changes take effect on the next `claude` run.", "`ANTHROPIC_API_KEY` overrides Claude Pro/Max/Team/Enterprise auth; in interactive mode it requires approval, but in non-interactive `-p` mode it is always used without prompt.", "`CLAUDE_CODE_DISABLE_CLAUDE_MDS=1` skips loading ALL CLAUDE.md memory files (user, project, auto-memory). `CLAUDE_CODE_DISABLE_AUTO_MEMORY` toggles auto-memory (0=force on, 1=force off).", "`CLAUDE_CODE_ADDITIONAL_DIRECTORIES_CLAUDE_MD=1` loads memory (`CLAUDE.md`, `.claude/CLAUDE.md`, `.claude/rules/*.md`, `CLAUDE.local.md`) from `--add-dir` directories; not loaded by default.", "`CLAUDE_CODE_AUTO_COMPACT_WINDOW` sets context capacity for auto-compaction (default = model's full window: 200K standard, 1M extended); lower values trigger compaction earlier, capped at the model's actual window. `CLAUDE_AUTOCOMPACT_PCT_OVERRIDE` (1-100) sets the auto-compaction trigger percentage and can only LOWER the threshold (higher values ignored); applies to main conversations and subagents.", "`CLAUDE_CODE_EFFORT_LEVEL` accepts `low|medium|high|xhigh|max|auto` and overrides both `/effort` and the `effortLevel` setting.", "`API_TIMEOUT_MS` default is 600000 (10 min), max 2147483647; values above max cause immediate failure. `BASH_DEFAULT_TIMEOUT_MS` default 120000 (2 min); `BASH_MAX_TIMEOUT_MS` default 600000 (10 min) caps model-settable bash timeout. `BASH_MAX_OUTPUT_LENGTH` saves full output to a file when exceeded, giving Claude path+preview.", "Governance toggles: `CLAUDE_CODE_DISABLE_1M_CONTEXT=1` (compliance — disables 1M model variants), `CLAUDE_CODE_DISABLE_POLICY_SKILLS=1` (skip system-wide managed skills, for container/CI), `CLAUDE_CODE_DISABLE_BUNDLED_SKILLS=1` (removes built-in skills; plugin/.claude/skills/.claude/commands skills unaffected), `CLAUDE_CODE_DISABLE_WORKFLOWS=1`.", "Telemetry: `DISABLE_TELEMETRY` and `DO_NOT_TRACK` disable telemetry; `CLAUDE_CODE_DISABLE_NONESSENTIAL_TRAFFIC` is a single switch equivalent to setting `DISABLE_AUTOUPDATER`, `DISABLE_FEEDBACK_COMMAND`, `DISABLE_ERROR_REPORTING`, and `DISABLE_TELEMETRY` together.", "`apiKeyHelper` setting handles credential rotation; `CLAUDE_CODE_API_KEY_HELPER_TTL_MS` sets the credential refresh interval.", "`ANTHROPIC_BASE_URL` (proxy/gateway override) disables MCP tool search by default on non-first-party hosts; set `ENABLE_TOOL_SEARCH=true` if the proxy forwards `tool_reference` blocks.", "Haiku-class model for background tasks set via `ANTHROPIC_DEFAULT_HAIKU_MODEL`; `ANTHROPIC_SMALL_FAST_MODEL` is DEPRECATED in favor of it. `ANTHROPIC_DEFAULT_{SONNET,OPUS,HAIKU,FABLE}_MODEL` set model IDs per class.", "`CLAUDE_CODE_ATTRIBUTION_HEADER=0` omits the attribution block from the system prompt, improving prompt-cache hit rates on LLM gateways (no effect on direct Anthropic API). `CLAUDE_CODE_DISABLE_EXPERIMENTAL_BETAS=1` strips `anthropic-beta` headers for proxy compatibility.", "`CLAUDECODE=1` is set in spawned subprocesses (Bash/PowerShell tools, tmux, hooks, status line commands, stdio MCP servers, IDE integrated terminals) — use it to detect subprocess execution. `CLAUDE_CODE_CHILD_SESSION=1` marks direct child sessions (excluded from `--resume`/`--continue`/history unless `CLAUDE_CODE_FORCE_SESSION_PERSISTENCE=1`).", "`CLAUDE_CODE_DISABLE_CRON=1` disables scheduled tasks (the `/loop` skill and cron tools become unavailable; already-scheduled tasks stop firing). `CLAUDE_CODE_DISABLE_BACKGROUND_TASKS=1` disables `run_in_background`, auto-backgrounding, and Ctrl+B.", "`CLAUDE_CODE_DISABLE_GIT_INSTRUCTIONS=1` removes commit/PR instructions and the git status snapshot from the system prompt (takes precedence over the `includeGitInstructions` setting).", "`CLAUDE_CODE_DISABLE_OFFICIAL_MARKETPLACE_AUTOINSTALL=1` (set on first run) skips auto-adding the official plugin marketplace.", "`CLAUDE_CODE_DEBUG_LOGS_DIR` is actually a FILE path (default `~/.claude/debug/<session-id>.txt`) despite its name; requires a separate debug enable (`--debug`, `/debug`, or `DEBUG` env var). `CLAUDE_CODE_DEBUG_LOG_LEVEL` default is `debug` (values `verbose|debug|info|warn|error`).", "Fullscreen rendering is an opt-in research preview requiring Claude Code v2.1.89 or later; enable with /tui fullscreen (saves the `tui` setting and relaunches preserving the conversation), or set CLAUDE_CODE_NO_FLICKER=1 on versions before v2.1.110.", "The `tui` setting and CLAUDE_CODE_NO_FLICKER env var are equivalent. /tui with no argument prints the active renderer; /tui default turns fullscreen off.", "Fullscreen draws on the terminal's alternate screen buffer and renders only visible messages, keeping memory flat in long conversations and eliminating flicker; most beneficial in VS Code integrated terminal, tmux, and iTerm2.", "Because the conversation lives in the alternate screen buffer (not native scrollback), terminal Cmd+f and tmux search cannot see it. Use Ctrl+o for transcript mode then `/` to search, or `[` to write the full conversation (tool output expanded) into native scrollback, or `v` to open it in $VISUAL/$EDITOR.", "CLAUDE_CODE_SCROLL_SPEED multiplies base scroll distance (range 1-20, fractional values <1 like 0.5 allowed; 3 matches vim default); persisted to ~/.claude/settings.json. /scroll-speed adjusts interactively. JetBrains IDE terminal ignores this var.", "wheelScrollAccelerationEnabled=false in settings.json disables scroll acceleration (requires v2.1.174+).", "CLAUDE_CODE_DISABLE_MOUSE=1 opts out of mouse capture while keeping flicker-free rendering and flat memory (combine with CLAUDE_CODE_NO_FLICKER=1); loses click-to-expand, URL clicking, click-to-position, and wheel scrolling inside Claude Code.", "CLAUDE_CODE_DISABLE_ALTERNATE_SCREEN=1 forces the classic renderer regardless of the saved `tui` setting, keeping the conversation in native scrollback.", "As of v2.1.181 a plain click without Cmd/Ctrl no longer opens links (matches native terminal behavior). Use Cmd-click on macOS, Ctrl-click on Linux/Windows to open URLs/file paths.", "Ctrl+L twice within 2 seconds runs /clear; on macOS Cmd+K double-press also clears. /focus toggles a quieter transcript view (persists across sessions).", "Copy-on-select toggled via 'Copy on select' in /config; with it off, Ctrl+Shift+c copies manually (Cmd+c works on kitty-keyboard-protocol terminals: kitty, WezTerm, Ghostty, iTerm2). Auto-scroll/auto-follow togglable in /config.", "As of v2.1.186, shell mode (`! <command>`) makes Claude automatically respond to the command output once it lands in the transcript (e.g. `! npm test` yields a failure explanation with no second prompt); this costs the same as a normal prompt.", "Set `respondToBashCommands` to `false` in settings.json to restore the pre-2.1.186 behavior where `!` shell-mode output is added to context without Claude responding.", "Set env var `CLAUDE_CODE_DISABLE_BACKGROUND_TASKS=1` to disable all background task functionality.", "Background tasks are automatically terminated if their output exceeds 5GB (with a note in stderr), and are auto-cleaned up when Claude Code exits.", "`Ctrl+B` backgrounds a running bash command/agent; tmux users must press it twice (tmux prefix-key collision).", "`Ctrl+X Ctrl+K` stops all running background subagents in the session; press twice within 3 seconds to confirm.", "Set `CLAUDE_CODE_TASK_LIST_ID=<name>` to share a task list across sessions via a named directory in `~/.claude/tasks/` (e.g. `CLAUDE_CODE_TASK_LIST_ID=my-project claude`).", "Task lists persist across context compactions; `Ctrl+T` toggles the view, which shows up to 5 tasks at a time.", "Disable prompt suggestions by setting `export CLAUDE_CODE_ENABLE_PROMPT_SUGGESTION=false` or toggling it in `/config`.", "`--prompt-suggestions` with `--output-format stream-json --verbose` emits a `prompt_suggestion` message after each turn (for programmatic/print-mode use); suggestions are off by default in print mode.", "Input history is stored per working directory and resets when you run `/clear`; reverse search (`Ctrl+R`) defaults to prompts from all projects, and `Ctrl+S` cycles scope through this-session, this-project, all-projects.", "History expansion (`!`) is disabled by default in command history.", "Vim editor mode is enabled via `/config` → Editor mode; block-wise visual mode (`Ctrl+V`) is not supported.", "`/btw <question>` asks a side question that has full visibility into the current conversation but never enters conversation history, has NO tool access (answers only from existing context), gives a single response, and reuses the parent prompt cache (low cost). Press `f` to fork it into a real session with full tool access.", "`Ctrl+O` toggles the transcript viewer and expands MCP calls, which otherwise collapse to a single line like \"Called slack 3 times\" by default.", "`Shift+Tab` cycles permission modes: `default`, `acceptEdits`, `plan`, plus any enabled modes such as `auto` or `bypassPermissions`.", "PR review status badge in the footer requires the `gh` CLI installed and authenticated (`gh auth login`); it refreshes every 60 seconds and immediately after a `gh pr` or `git push` runs.", "Session recap is on by default for every plan/provider, generates in the background after 3+ minutes idle with the terminal unfocused (needs 3+ turns), is skipped in non-interactive mode, and is disabled via `/config` → Session recap. `/recap` generates one on demand.", "`/terminal-setup` installs the Shift+Enter multiline binding for VS Code, Cursor, Devin Desktop, Alacritty, and Zed; `Ctrl+J` gives multiline in any terminal without configuration.", "Prompt-input suggestions run as a background request reusing the parent conversation's prompt cache; Claude Code skips suggestion generation when the cache is cold to avoid cost.", "Customizable keyboard shortcuts require Claude Code v2.1.18 or later; check with `claude --version`.", "Keybindings config lives at `~/.claude/keybindings.json` (user-scope only; no documented project/managed/team scope). Open/create it via `/keybindings`.", "The config is an object with a `bindings` array; each block has a `context` and a `bindings` map of keystroke->action (e.g. `\"ctrl+e\": \"chat:externalEditor\"`). Optional `$schema` and `$docs` keys.", "Changes to keybindings.json are auto-detected and applied without restarting Claude Code.", "Set an action to `null` to unbind a default shortcut; works for chords too. Unbinding all chords sharing a prefix frees that prefix for a single-key binding.", "Reserved (non-rebindable) shortcuts: Ctrl+C (interrupt), Ctrl+D (exit), Ctrl+M (== Enter, both send CR), Caps Lock (not delivered to terminal).", "Terminal multiplexer conflicts: Ctrl+B (tmux prefix), Ctrl+A (GNU screen prefix), Ctrl+Z (Unix SIGTSTP suspend).", "`task:background` adds chord Ctrl+X Ctrl+B (v2.1.169+) specifically to avoid the tmux Ctrl+B prefix conflict.", "`permission:toggleDebug` default Ctrl+D was removed in v2.1.146 because it shadowed `app:exit`.", "`/doctor` surfaces keybinding warnings; the validator flags parse errors, invalid context names, reserved-shortcut conflicts, multiplexer conflicts, and duplicate bindings in the same context.", "The `cmd`/super modifier group is only detected in terminals reporting Super (Kitty keyboard protocol or xterm modifyOtherKeys); most terminals don't send it, so use `ctrl` or `meta` for portable bindings.", "`chat:clearInput` (Ctrl+L) or `chat:clearScreen` (Cmd+K) pressed twice within two seconds in fullscreen rendering runs `/clear`.", "`chat:killAgents` (Ctrl+X Ctrl+K) stops all running background subagents in the session.", "CLAUDE.md load order, broadest to most specific (project loads AFTER user): (1) Managed policy, (2) User instructions ~/.claude/CLAUDE.md, (3) Project ./CLAUDE.md or ./.claude/CLAUDE.md, (4) Local ./CLAUDE.local.md.", "Managed policy CLAUDE.md paths: macOS /Library/Application Support/ClaudeCode/CLAUDE.md; Linux/WSL /etc/claude-code/CLAUDE.md; Windows C:\\Program Files\\ClaudeCode\\CLAUDE.md. This file cannot be excluded by individual settings.", "Project CLAUDE.md may be at ./CLAUDE.md OR ./.claude/CLAUDE.md. Local personal file is ./CLAUDE.local.md (add to .gitignore).", "CLAUDE.md discovery walks UP the directory tree from cwd, loading every CLAUDE.md and CLAUDE.local.md found. All discovered files are concatenated (not overriding). Ordering is filesystem-root-down to cwd, so the file closest to launch dir is read LAST. Within a directory, CLAUDE.local.md is appended after CLAUDE.md.", "CLAUDE.md/CLAUDE.local.md in subdirectories BELOW cwd are NOT loaded at launch; they load on demand when Claude reads a file in that subdirectory.", "CLAUDE.md files are loaded in FULL regardless of length (the 200-line/25KB limit applies only to MEMORY.md auto memory).", "Import syntax @path/to/import; both relative (resolve relative to the file containing the import, not cwd) and absolute paths allowed. Imports expand and load into context at launch. Max recursion depth is four hops.", "Import parsing skips Markdown code spans and fenced code blocks. Wrap a path in backticks (e.g. `@README`) to mention it literally without importing.", "First time Claude Code encounters external imports in a project it shows an approval dialog; if declined, imports stay disabled and the dialog does not reappear.", "Home-dir import @~/.claude/my-project-instructions.md can share personal instructions across git worktrees (since gitignored CLAUDE.local.md exists only in the worktree where created).", "Claude Code reads CLAUDE.md, NOT AGENTS.md. To reuse AGENTS.md: put @AGENTS.md import at top of CLAUDE.md (or symlink ln -s AGENTS.md CLAUDE.md; on Windows symlinks need Admin/Developer Mode so use the import).", "/init generates a starting CLAUDE.md; if one exists it suggests improvements rather than overwriting. It also reads AGENTS.md, .cursorrules, .devin/rules/, .windsurfrules and incorporates them.", "Set CLAUDE_CODE_NEW_INIT=1 to enable an interactive multi-phase /init: asks which artifacts (CLAUDE.md, skills, hooks), explores codebase with a subagent, asks follow-ups, presents a reviewable proposal before writing files.", ".claude/rules/ holds modular instruction .md files, discovered recursively (subdirectories allowed). Rules without paths frontmatter load at launch with same priority as .claude/CLAUDE.md.", "Path-specific rules use YAML frontmatter 'paths:' with glob patterns (e.g. src/api/**/*.ts, brace expansion src/**/*.{ts,tsx}); they load only when Claude reads files matching the pattern, not on every tool use.", ".claude/rules/ supports symlinks (resolved and loaded normally; circular symlinks detected/handled). Can link a shared dir or individual file across projects.", "User-level rules ~/.claude/rules/*.md apply to every project and load BEFORE project rules, giving project rules higher priority.", "claudeMdExcludes setting skips ancestor CLAUDE.md/rules by path or glob, matched against absolute paths. Configurable at any settings layer (user/project/local/managed); arrays merge across layers. Managed policy CLAUDE.md cannot be excluded.", "managed-settings.json claudeMd key embeds managed CLAUDE.md content inline (alternative to deploying a separate file). Honored only in managed/policy settings; setting claudeMd in user/project/local has no effect. Loads before user and project CLAUDE.md.", "--add-dir does NOT load CLAUDE.md from extra dirs by default. Set env CLAUDE_CODE_ADDITIONAL_DIRECTORIES_CLAUDE_MD=1 to load CLAUDE.md, .claude/CLAUDE.md, .claude/rules/*.md, and CLAUDE.local.md from the added dir (CLAUDE.local.md skipped if 'local' excluded from --setting-sources).", "Block-level HTML comments (<!-- ... -->) in CLAUDE.md are stripped before injection into context (save context for human-only notes). Comments inside code blocks are preserved; comments remain visible when opened with the Read tool.", "Auto memory requires Claude Code v2.1.59+. On by default. Disable via /memory toggle, autoMemoryEnabled:false in settings, or env CLAUDE_CODE_DISABLE_AUTO_MEMORY=1.", "Auto memory storage: ~/.claude/projects/<project>/memory/ with MEMORY.md entrypoint plus topic files. <project> derived from git repo, so all worktrees/subdirs of one repo share one auto memory dir. Machine-local; not shared across machines or cloud.", "Only the first 200 lines OR first 25KB of MEMORY.md (whichever comes first) load at session start; content beyond is not loaded. Topic files (debugging.md etc.) are NOT loaded at startup — Claude reads them on demand.", "autoMemoryDirectory setting overrides storage location; must be absolute or start with ~/. Read from any settings scope. When set in project .claude/settings.json or settings.local.json, honored only after accepting the workspace trust dialog.", "Saying '# <text>' / asking Claude to remember (e.g. 'always use pnpm') saves to AUTO MEMORY, not CLAUDE.md. To put it in CLAUDE.md, ask 'add this to CLAUDE.md' or edit via /memory.", "/memory lists all loaded CLAUDE.md, CLAUDE.local.md, and rules files in the session, toggles auto memory, and links to the auto memory folder; selecting a file opens it in editor.", "CLAUDE.md is delivered as a USER message after the system prompt, not part of the system prompt; no strict-compliance guarantee. --append-system-prompt injects at system-prompt level but must be passed every invocation.", "Project-root CLAUDE.md survives /compact (re-read from disk and re-injected). Nested subdirectory CLAUDE.md files are NOT re-injected after compaction; they reload only on next file read in that subdir.", "InstructionsLoaded hook logs exactly which instruction files load, when, and why — for debugging path-specific/lazy-loaded rules. PreToolUse hook is the way to hard-block an action regardless of Claude's decision.", "Subagents can maintain their own auto memory (see sub-agents 'enable persistent memory').", "Model setting precedence (highest to lowest): in-session /model command, --model flag at startup, ANTHROPIC_MODEL env var, then the 'model' field in settings file.", "As of v2.1.153, /model saves your choice as the default for new sessions by writing the 'model' field in user settings. In the picker: Enter switches and saves as default; 's' switches for this session only. Project and managed settings still take precedence and reapply on next launch.", "--model flag and ANTHROPIC_MODEL env var apply only to the session launched with them. To run different models in different terminals simultaneously, launch each with its own --model flag rather than switching with /model.", "Model aliases: default (clears override, reverts to recommended for account type), best (Fable 5 where available else latest Opus), fable (Claude Fable 5), sonnet, opus, haiku, sonnet[1m], opus[1m], opusplan (Opus in plan mode then Sonnet for execution).", "On the Anthropic API, opus resolves to Opus 4.8 and sonnet to Sonnet 4.6. On Claude Platform on AWS, opus=Opus 4.7, sonnet=Sonnet 4.6. On Bedrock/Vertex/Foundry, opus=Opus 4.6, sonnet=Sonnet 4.5.", "Aliases point to the recommended version per provider and change over time. To pin a version use the full model name (e.g. claude-opus-4-8) or set ANTHROPIC_DEFAULT_OPUS_MODEL / ANTHROPIC_DEFAULT_SONNET_MODEL / ANTHROPIC_DEFAULT_HAIKU_MODEL / ANTHROPIC_DEFAULT_FABLE_MODEL.", "Default model by account type: Max/Team Premium/Enterprise pay-as-you-go/Anthropic API default to Opus 4.8; Claude Platform on AWS defaults to Opus 4.7; Pro/Team Standard/Enterprise subscription seats default to Sonnet 4.6; Bedrock/Vertex/Foundry default to Sonnet 4.5.", "Fable 5 is never the default; select with /model fable, the best alias, or a model setting. Fable 5 requires Claude Code v2.1.170+. Opus 4.8 requires v2.1.154+. Fable 5 is unavailable under zero data retention.", "Enterprise admins restrict model selection with 'availableModels' in managed/policy settings. It applies to /model, --model, ANTHROPIC_MODEL, alias-resolution env vars, /fast, subagent model frontmatter + Agent tool model param + CLAUDE_CODE_SUBAGENT_MODEL, advisorModel, and fallback chain elements (out-of-list elements dropped).", "availableModels does NOT by default restrict the Default picker option. Set 'enforceAvailableModels': true (with non-empty availableModels) to make Default obey the allowlist; requires v2.1.175+. When tier default not in allowlist, Default resolves to the first allowed entry. Empty availableModels array never engages enforcement.", "The 'model' setting is initial selection, not enforcement — users can pick Default which resolves to the tier system default regardless of 'model'. Full control requires combining model + availableModels + enforceAvailableModels + ANTHROPIC_DEFAULT_*_MODEL env vars.", "Merge behavior: availableModels set only in user/project/local settings is merged+deduplicated. Set in managed/policy settings, the managed value REPLACES the merged result entirely (cannot be widened by user/project). Strict allowlist enforcement via managed/policy replacement requires v2.1.175+; earlier versions merge.", "Fallback model chains: --fallback-model accepts comma-separated list (e.g. claude --fallback-model sonnet,haiku); persisted via 'fallbackModel' settings array. Flag takes precedence over setting. 'default' expands to default model. Chains capped at 3 models after dedup; extras ignored. Switch lasts current turn only. Auth/billing/rate-limit/request-size/transport errors never trigger fallback.", "Effort levels control adaptive reasoning. Fable 5/Opus 4.8/Opus 4.7 support low,medium,high,xhigh,max; Opus 4.6/Sonnet 4.6 support low,medium,high,max. Default effort is high (Fable5/Opus4.8/Opus4.6/Sonnet4.6) and xhigh (Opus 4.7). Setting an unsupported level falls back to highest supported at-or-below.", "Set effort via /effort (slider or level name or 'auto'), --effort flag (single session), CLAUDE_CODE_EFFORT_LEVEL env var (or 'auto'), 'effortLevel' settings key (only low/medium/high/xhigh; not max/ultracode), or skill/subagent frontmatter 'effort' field. Precedence: env var > configured level > model default. low/medium/high/xhigh persist; max is session-only.", "Include the keyword 'ultrathink' anywhere in a prompt for deeper one-off reasoning (adds in-context instruction; API effort level unchanged). Phrases like 'think', 'think hard', 'think more' are NOT recognized keywords and pass through as ordinary text.", "ultracode (in /effort menu or 'ultracode': true via --settings) is a Claude Code setting not a model effort level: sends xhigh plus orchestrates dynamic workflows; session-only; not part of effortLevel/--effort/CLAUDE_CODE_EFFORT_LEVEL.", "Extended thinking: toggle session with Option+T (mac)/Alt+T (Win/Linux); global default via /config toggle saved as 'alwaysThinkingEnabled' in ~/.claude/settings.json; MAX_THINKING_TOKENS=0 disables thinking on Anthropic API except Fable 5. Ctrl+O toggles verbose thinking display. You are charged for all thinking tokens even when collapsed/redacted. Set showThinkingSummaries:true to get full summaries.", "Thinking cannot be turned off on Fable 5; session toggle, alwaysThinkingEnabled, and MAX_THINKING_TOKENS=0 have no effect there.", "On Opus 4.6/Sonnet 4.6 only, CLAUDE_CODE_DISABLE_ADAPTIVE_THINKING=1 reverts to fixed thinking budget controlled by MAX_THINKING_TOKENS. Opus 4.7+ and Fable 5 always use adaptive reasoning and ignore this.", "1M context window supported by Fable 5, Opus 4.6+, Sonnet 4.6. On Max/Team/Enterprise, Opus auto-upgrades to 1M (both Team Standard and Premium). On Anthropic API, Fable5/Opus4.8/Opus4.7 always run 1M. Sonnet 1M is NOT in the auto-upgrade and requires usage credits on every plan including Max. 1M uses standard pricing with no premium beyond 200K.", "Disable 1M context with CLAUDE_CODE_DISABLE_1M_CONTEXT=1 (removes 1M variants from picker). Use [1m] suffix on aliases or full names (e.g. /model opus[1m], opusplan[1m], claude-opus-4-8[1m]).", "CLAUDE_CODE_SUBAGENT_MODEL sets the model for all subagents and agent teams; overrides per-invocation model param and subagent frontmatter 'model'. Set to 'inherit' for normal model resolution. ANTHROPIC_SMALL_FAST_MODEL is deprecated in favor of ANTHROPIC_DEFAULT_HAIKU_MODEL (which also controls background functionality).", "modelOverrides settings key maps individual Anthropic model IDs to provider-specific strings (Bedrock ARN/Vertex version/Foundry deployment) for governance, cost allocation, regional routing. Keys must be exact Anthropic model IDs (with date suffix); unknown keys ignored. Allowlist (availableModels) is evaluated against the Anthropic model ID, not the override value.", "For third-party deployments (Bedrock/Vertex/Foundry/Claude Platform on AWS), pin model versions via ANTHROPIC_DEFAULT_*_MODEL env vars with version-specific IDs before rollout, so admins control when users move to new models. Append [1m] to the env var value to enable 1M context; suffix is stripped before sending and is read per-variable not per-model.", "Pinned third-party model display/capabilities set via ANTHROPIC_DEFAULT_<FAMILY>_MODEL_NAME, _DESCRIPTION, _SUPPORTED_CAPABILITIES (comma-separated: effort, xhigh_effort, max_effort, thinking, adaptive_thinking, interleaved_thinking). When _SUPPORTED_CAPABILITIES is set, only listed capabilities are enabled. _NAME/_DESCRIPTION also work behind an LLM gateway but not against api.anthropic.com directly.", "ANTHROPIC_CUSTOM_MODEL_OPTION adds one custom entry to /model picker (+ optional _NAME, _DESCRIPTION). Validation is skipped for its model ID. For LLM gateways, set CLAUDE_CODE_ENABLE_GATEWAY_MODEL_DISCOVERY=1 to populate the picker from the gateway's /v1/models endpoint.", "ANTHROPIC_BASE_URL changes where requests are sent, not which model answers them; use LLM gateway configuration to route Claude through a gateway.", "Prompt caching is automatic. Disable globally with DISABLE_PROMPT_CACHING=1 (precedence over per-model), or per tier with DISABLE_PROMPT_CACHING_HAIKU / _SONNET / _OPUS / _FABLE = 1.", "Resumed sessions (claude --resume, --continue, /resume) keep the model from when the transcript was saved, regardless of current 'model' setting; if that model is retired it falls through normal precedence. This prevents another session's /model choice from affecting resume.", "Retirement/remapping warnings: shown as startup notice interactively; from v2.1.182 written to stderr in non-interactive mode with default text output. Suppressed for --output-format json/stream-json — read actual model from modelUsage field of the result message instead. Check covers subagent frontmatter model.", "Fable 5 content-based automatic fallback: safety classifiers (cybersecurity/biology) re-run flagged request on default Opus (Opus 4.8 on Anthropic API/gateway, Opus 4.7 on Claude Platform on AWS) and continue there; return to Fable with /model fable. Can trigger on first request from workspace context (CLAUDE.md, git status). Disable auto-switch via /config 'switch models when a message is flagged'.", "claude --safe-mode disables customizations (CLAUDE.md, skills, MCP servers, hooks) to test whether they trigger Fable 5 fallback; git status and directory names are still included.", "On Bedrock/Vertex/Foundry, Fable 5 automatic fallback only works if Claude Code can identify both models: current model recognized as Fable 5 (ID contains claude-fable-5, matches ANTHROPIC_DEFAULT_FABLE_MODEL, or mapped via modelOverrides) and target resolves to Opus. Set ANTHROPIC_DEFAULT_FABLE_MODEL and ANTHROPIC_DEFAULT_OPUS_MODEL to enable it.", "Check current model via status line (if configured) or /status (also shows account info). Effort level is displayed next to the logo/spinner, e.g. 'with low effort'.", "Output styles modify Claude Code's system prompt directly (instructions added to the end); they change how Claude responds, not what it knows.", "Built-in output styles: Default (the standard SWE system prompt), Proactive, Explanatory, and Learning.", "Proactive style executes immediately and prefers action over planning; it is stronger autonomous-execution guidance than auto mode but still shows permission prompts before tools run (does not change permission mode).", "Explanatory style adds educational 'Insights' between SWE tasks; Learning style adds Insights plus inserts TODO(human) markers asking the user to write small strategic code pieces.", "Activate a style via /config -> Output style menu; selection is saved to .claude/settings.local.json (local project level) in the outputStyle field.", "Can set style without the menu by editing the outputStyle field directly in a settings file, e.g. {\"outputStyle\": \"Explanatory\"}.", "Custom output styles are Markdown files saved at one of three levels: User ~/.claude/output-styles, Project .claude/output-styles, or Managed policy .claude/output-styles inside the managed settings directory.", "The custom-style file name becomes the style name unless overridden by the frontmatter 'name' field.", "Frontmatter fields: name, description (shown in /config picker), keep-coding-instructions (default false), force-for-plugin (default false).", "By default custom output styles REMOVE Claude Code's built-in software engineering instructions; set keep-coding-instructions: true to retain them.", "Plugins can ship output styles in an output-styles/ directory. force-for-plugin: true applies a plugin's style automatically when the plugin is enabled, overriding the user's outputStyle setting; if multiple enabled plugins set it, the first loaded wins.", "Output style is part of the system prompt, read once at session start; changes take effect only after /clear or a new session.", "Project output styles load from every .claude/output-styles/ between the working directory and repo root; as of v2.1.178, on same-name collisions the one closest to the working directory wins.", "The standalone /output-style command was deprecated in v2.1.73 and removed in v2.1.91; use /config or edit outputStyle directly.", "Feature distinction: output styles modify the system prompt; CLAUDE.md adds a user message after the system prompt; --append-system-prompt appends to the system prompt for a single invocation without removing anything; Agents run a subagent with its own system prompt/model/tools; Skills load task-specific instructions on demand.", "All output styles trigger periodic reminders during the conversation for Claude to adhere to the style instructions.", "Documentation references max-version 2.1.90 and min-version 2.1.178 markers, indicating version-gated behavior current as of these releases.", "Settings precedence, highest to lowest: Managed > command-line args > Local (.claude/settings.local.json) > Project (.claude/settings.json) > User (~/.claude/settings.json).", "Settings file locations: User = ~/.claude/settings.json; Project (git-shared) = .claude/settings.json; Local (gitignored) = .claude/settings.local.json. On Windows ~/.claude resolves to %USERPROFILE%\\.claude.", "Permission rules MERGE across scopes rather than override. Permission resolution precedence: Managed deny > user/project deny > Managed ask > user/project ask > Managed allow > user/project allow. Deny always wins over allow.", "Permission rule syntax: Tool(pattern), e.g. Bash(npm run test *), Read(~/.zshrc), Read(./secrets/**), Bash(curl *). Wildcards: * single component, ** recursive. Keys: permissions.allow, permissions.deny, permissions.ask (arrays).", "Bash permission patterns match the command literally, not args: Bash(npm run *) does NOT cover args; use Bash(npm run test *) to allow test with any args.", "File-based managed settings system directories: macOS = /Library/Application Support/ClaudeCode/; Linux/WSL = /etc/claude-code/; Windows = C:\\Program Files\\ClaudeCode\\ (legacy C:\\ProgramData\\ removed as of v2.1.75).", "Managed settings files: managed-settings.json (base), managed-mcp.json (MCP config), and managed-settings.d/ drop-in directory. Drop-in merge: managed-settings.json first, then *.json alphabetically (use numeric prefixes like 10-, 20-); hidden files ignored. Scalars override, arrays concatenate+dedupe, objects deep-merge.", "Managed settings delivery mechanisms with precedence server > MDM > file. macOS MDM domain: com.anthropic.claudecode plist. Windows admin: HKLM\\SOFTWARE\\Policies\\ClaudeCode (value 'Settings' = JSON); Windows user-level (lowest): HKCU\\SOFTWARE\\Policies\\ClaudeCode.", "MCP config locations: user = ~/.claude.json (mcpServers key); project = .mcp.json; managed = managed-mcp.json in system dir. ~/.claude.json also holds OAuth session, per-project state, caches — do NOT version-control it.", "Managed MCP control keys: allowedMcpServers (allowlist; undefined=no restriction, empty=lockdown), deniedMcpServers (takes precedence over allowlist), allowManagedMcpServersOnly, disableClaudeAiConnectors (v2.1.182+), allowAllClaudeAiMcps.", "Project-scope MCP approval keys (settings.json): enabledMcpjsonServers (string[] approve), disallowedMcpjsonServers (string[] reject), enableAllProjectMcpServers (bool auto-approve all .mcp.json servers).", "Model governance keys: model (default), availableModels (string[] allowlist), enforceAvailableModels (v2.1.175+ locks default to allowlist), fallbackModel (string[] chain, max 3 entries, extras silently ignored). availableModels without enforceAvailableModels does NOT lock the default.", "Managed-only governance keys: claudeMd (org instructions), forceLoginMethod ('claudeai'|'console'), forceLoginOrgUUID, requiredMinimumVersion, requiredMaximumVersion, forceRemoteSettingsRefresh (blocks startup until remote fetch; CLI exits if fetch fails), allowManagedPermissionRulesOnly, allowManagedHooksOnly, policyHelper (v2.1.136+), parentSettingsBehavior 'merge'|'first-wins' (v2.1.133+).", "Hooks configured under settings.json 'hooks' key by lifecycle event. Hook types: exec (local command), http (POST webhook), sdk. HTTP hook security: allowedHttpHookUrls (undefined=no restriction, empty=block all), httpHookAllowedEnvVars (allowlist env vars for interpolation; arrays merge across scopes). disableAllHooks disables all hooks + status line.", "Lifecycle hook events include: ConfigChange, BeforeBash/AfterBash, BeforeRead/AfterRead, BeforeWrite/AfterWrite, BeforeApiCall/AfterApiCall, SessionStart/SessionEnd.", "Env vars (set via settings env key): CLAUDE_CODE_ENABLE_TELEMETRY (default 0), OTEL_METRICS_EXPORTER, CLAUDE_CODE_API_KEY_HELPER_TTL_MS (default 3600000), DISABLE_AUTOUPDATER, DISABLE_AUTO_COMPACT, CLAUDE_CODE_DISABLE_AUTO_MEMORY, CLAUDE_CODE_SKIP_PROMPT_HISTORY, ANTHROPIC_MODEL (one-session override), ANTHROPIC_API_KEY, ANTHROPIC_AUTH_TOKEN, MAX_THINKING_TOKENS (0=disabled), CLAUDE_CODE_EFFORT_LEVEL (low/medium/high/xhigh).", "claudeMdExcludes (string[]): glob patterns to skip loading CLAUDE.md files, e.g. **/node_modules/**/CLAUDE.md.", "cleanupPeriodDays (default 30, min 1) auto-deletes session files older than threshold at startup; value 0 rejected with validation error.", "Skill/workflow lockdown keys: disableBundledSkills, disableSkillShellExecution (disables inline shell in skills except bundled/managed), disableWorkflows, plus env equivalents CLAUDE_CODE_DISABLE_BUNDLED_SKILLS / CLAUDE_CODE_DISABLE_WORKFLOWS.", "Plugin marketplace governance (managed): blockedMarketplaces (checked before download), strictKnownMarketplaces, pluginSuggestionMarketplaces, allowedChannelPlugins, pluginTrustMessage.", "claude doctor validates config and lists invalid managed settings entries; useful before fleet deployment.", "enforceAvailableModels introduced v2.1.175; disableClaudeAiConnectors v2.1.182+; policyHelper v2.1.136+; parentSettingsBehavior v2.1.133+; legacy Windows C:\\ProgramData path removed v2.1.75. Version-gated; verify against current release.", "As of v2.1.169+ typos in managed-settings.json strip the bad entry and warn rather than blocking startup, EXCEPT security fields like allowedMcpServers which fail closed (treated as empty list = lockdown).", "Status line is configured via the `statusLine` field in settings.json, with `type` set to `\"command\"` and `command` pointing to a script path or inline shell command. Lives in user settings (`~/.claude/settings.json`) or project settings.", "`statusLine` supports optional fields: `padding` (extra horizontal spacing in characters, default 0), `refreshInterval` (re-runs command every N seconds in addition to event-driven updates, minimum 1), and `hideVimModeIndicator` (true suppresses built-in `-- INSERT --` text).", "The `/statusline` command accepts natural-language instructions; Claude Code generates a script in `~/.claude/` and updates settings automatically. `/statusline delete|clear|remove` removes it.", "Status line script receives JSON session data on stdin and displays whatever it prints to stdout. Runs locally; does NOT consume API tokens.", "Script runs after each new assistant message, after `/compact` finishes, when permission mode changes, or when vim mode toggles. Updates debounced at 300ms. If a new update triggers while the script is still running, the in-flight execution is cancelled.", "Settings reload automatically but status line changes won't appear until the next interaction with Claude Code.", "Multiple lines: each echo/print is a separate row. Colors via ANSI escape codes (e.g. `\\033[32m` green, `\\033[0m` reset). Clickable links via OSC 8 escape sequences (requires terminal support: iTerm2, Kitty, WezTerm; Terminal.app does NOT support).", "`tput cols` / language-level width detection do not work inside the script because Claude Code captures output instead of attaching a TTY. Read `COLUMNS` and `LINES` env vars instead (Claude Code sets them; requires v2.1.153+).", "Key JSON input fields: `model.id`, `model.display_name`, `cwd`, `workspace.current_dir` (preferred), `workspace.project_dir`, `workspace.added_dirs`, `workspace.git_worktree`, `workspace.repo.{host,owner,name}`, `session_id`, `session_name`, `transcript_path`, `version`, `output_style.name`.", "Cost fields: `cost.total_cost_usd` (client-side estimate, may differ from bill), `cost.total_duration_ms`, `cost.total_api_duration_ms`, `cost.total_lines_added`, `cost.total_lines_removed`.", "Context fields: `context_window.total_input_tokens`/`total_output_tokens` (current context usage, not cumulative as of v2.1.132; before that they were cumulative session totals), `context_window_size` (200000 default, 1000000 for extended), `used_percentage`, `remaining_percentage`, `current_usage.{input_tokens,output_tokens,cache_creation_input_tokens,cache_read_input_tokens}`, plus top-level `exceeds_200k_tokens`.", "`used_percentage` is computed from input tokens only (input + cache_creation + cache_read), excluding output_tokens. Manual calculation should use the same input-only formula to match.", "`rate_limits.{five_hour,seven_day}.{used_percentage,resets_at}` are present ONLY for Claude.ai Pro/Max subscribers after the first API response; each window may be independently absent. `effort.level` (low/medium/high/xhigh/max; ultracode reports as xhigh) present only when model supports it. `thinking.enabled`, `vim.mode`, `agent.name` (with --agent), `pr.{number,url,review_state}`, and `worktree.*` (only during --worktree sessions) are conditionally present.", "`context_window.current_usage`, `used_percentage`, and `remaining_percentage` may be null before the first API call and again after `/compact` until the next API call repopulates them. Handle with fallbacks (jq `// 0`, `// empty`).", "If `disableAllHooks` is `true` in settings, the status line is also disabled (status line shares the hooks trust/disable gates).", "The status line command only runs if the workspace trust dialog has been accepted for the directory (same trust acceptance as hooks). If not accepted, shows `statusline skipped · restart to fix`.", "`subagentStatusLine` setting (same `type`/`command` shape) overrides the per-subagent row in the agent panel. Command runs once per refresh tick; receives base hook fields plus `columns` and a `tasks` array (each task: id, name, type, status, description, label, startTime, tokenCount, tokenSamples, cwd). Output one JSON line per row: `{\"id\":\"<task id>\",\"content\":\"<row body>\"}`; omit id to keep default, empty content to hide. Plugins can ship a default subagentStatusLine in their settings.json.", "On Windows, status line commands run through Git Bash if installed, else PowerShell. Use forward slashes in the `command` path (Git Bash consumes unquoted backslashes silently). To run PowerShell: `powershell -NoProfile -File C:/.../statusline.ps1`.", "`claude --debug` logs the exit code and stderr from the first status line invocation. `FORCE_HYPERLINK=1 claude` forces OSC 8 hyperlink support when terminal auto-detection fails (e.g. Windows Terminal).", "`footerLinksRegexes` setting adds clickable link badges to the footer when an ID appears in the conversation, without writing a status line script.", "/terminal-setup writes Shift+Enter and other keybindings into the host terminal's config file for VS Code, Cursor, Devin Desktop, Alacritty, and Zed; run it once, and run it in the host terminal NOT inside tmux/screen.", "In VS Code/Cursor/Devin Desktop, /terminal-setup also sets terminal.integrated.gpuAcceleration to \"off\" (prevents garbled text) and adjusts terminal.integrated.mouseWheelScrollSensitivity; undo GPU change by setting it back to \"auto\" and reloading.", "Ctrl+J or typing \\ then Enter inserts a newline in every terminal with no setup; plain Enter submits.", "Notification/bell: by default Claude Code sends a desktop notification only in Ghostty, Kitty, and iTerm2. In other terminals set preferredNotifChannel to \"terminal_bell\", or configure a Notification hook.", "Desktop notifications reach the local machine over SSH, so remote sessions still alert.", "A Notification hook is configured under hooks.Notification in ~/.claude/settings.json with {\"type\":\"command\",\"command\":\"...\"}; it runs ALONGSIDE the built-in notification, not replacing it.", "Inside tmux, both Shift+Enter newline and notifications/progress bar break by default. Fix by adding to ~/.tmux.conf: set -g allow-passthrough on; set -s extended-keys on; set -as terminal-features 'xterm*:extkeys'; then tmux source-file ~/.tmux.conf. allow-passthrough fixes notifications/progress; extended-keys lines fix Shift+Enter.", "Fullscreen rendering mode keeps memory usage flat and adds mouse scroll/selection; enable per-session with /tui fullscreen, or make default by setting env var CLAUDE_CODE_NO_FLICKER=1 (e.g. in settings.json env block) before start.", "Pasting more than 10,000 characters collapses the input to a [Pasted text] placeholder; full content is still sent on submit.", "The VS Code integrated terminal can DROP characters from very large pastes before they reach Claude Code; prefer file-based workflows there.", "Vim editor mode: enable via /config → Editor mode or by setting editorMode to \"vim\" in ~/.claude/settings.json; set to \"normal\" to disable. Vim motions are NOT remappable via the keybindings file. Enter still submits in INSERT mode (use o/O or Ctrl+J for newline).", "Custom themes are JSON files in ~/.claude/themes/ (filename slug = theme slug, stored as custom:<slug>); fields name/base/overrides; Claude Code watches the dir and hot-reloads. Requires Claude Code v2.1.118+.", "Plugins can contribute themes that appear in /theme.", "chat:newline and chat:submit actions can be remapped in the keybindings file to swap Enter/Shift+Enter behavior."]}, "Optimal use, context & cost": {"pages": ["best-practices", "checkpointing", "common-workflows", "context-window", "costs", "fast-mode", "features-overview", "how-claude-code-works", "large-codebases", "prompt-caching", "sessions", "ultraplan", "ultrareview", "workflows"], "bestPractices": ["Give Claude a check it can run (test suite, build exit code, linter, fixture diff, browser screenshot) so it closes the verification loop itself instead of stopping at 'looks done'.", "Have Claude show evidence (test output, command + return, screenshot) rather than asserting success — reviewing evidence is faster and works for unattended sessions.", "Escalate the verification gate to match autonomy: in-prompt 'run the check and iterate' for any task; /goal condition for across-a-session; Stop hook for a deterministic gate; verification subagent for an independent second opinion.", "Use the four-phase workflow for non-trivial work: Explore (plan mode, read-only) → Plan (detailed implementation plan, edit with Ctrl+G) → Implement → Commit/PR.", "Skip plan mode for small clear-scope tasks (typo, log line, rename) — if you could describe the diff in one sentence, skip the plan. Plan when uncertain, multi-file, or unfamiliar code.", "Write specific prompts: scope the file/scenario/testing prefs, point to source (git history), reference existing codebase patterns by file, and describe the symptom + likely location + what 'fixed' looks like.", "Keep CLAUDE.md short and human-readable; for each line ask 'would removing this cause Claude to make mistakes?' and cut if not — bloated CLAUDE.md causes Claude to ignore real instructions.", "Put only broadly-applicable context in CLAUDE.md; move sometimes-relevant domain knowledge/workflows into skills so they load on demand without bloating every conversation.", "Include in CLAUDE.md: non-guessable bash commands, non-default code style, test instructions, repo etiquette, project-specific architecture, env quirks, non-obvious gotchas. Exclude: anything inferable from code, standard conventions, detailed API docs (link instead), frequently-changing info.", "Add emphasis ('IMPORTANT', 'YOU MUST') in CLAUDE.md to improve adherence; check CLAUDE.md into git for team contribution; treat it like code — review, prune, and test that behavior actually shifts.", "If Claude ignores a CLAUDE.md rule, the file is probably too long; if Claude asks questions answered in it, the phrasing is ambiguous.", "Install and tell Claude to use CLI tools (gh, aws, gcloud, sentry-cli) — most context-efficient way to hit external services; gh avoids unauthenticated GitHub API rate limits.", "Use hooks for actions that must happen every time with zero exceptions (CLAUDE.md is only advisory, hooks are deterministic). Convert reliably-needed CLAUDE.md rules into hooks.", "Run /clear between unrelated tasks; after two failed corrections on the same issue, /clear and restart with a better prompt incorporating what you learned (clean session beats long polluted one).", "Customize compaction in CLAUDE.md (e.g. 'When compacting, always preserve the full list of modified files and any test commands') so critical context survives summarization.", "Delegate research and verification to subagents ('use subagents to investigate X', 'use a subagent to review this code for edge cases') so file reads happen in a separate context and don't consume the main window.", "For larger features, have Claude interview you with the AskUserQuestion tool, write a self-contained SPEC.md (named files/interfaces, out-of-scope, end-to-end verification step), then start a fresh session to implement.", "Use parallel sessions for a Writer/Reviewer pattern — a fresh context reviewer isn't biased toward code it just wrote; pick git worktrees for isolated checkouts so edits don't collide.", "For large migrations, fan out: have Claude list all files, then loop 'claude -p' per file with scoped --allowedTools; test on 2-3 files and refine the prompt before running at scale.", "Add an adversarial review step before declaring done — review the diff in a fresh subagent against the plan; tell the reviewer to flag only gaps affecting correctness or stated requirements to avoid over-engineering.", "Track context usage continuously (custom status line) since performance degrades as the context window fills; manage context as the fundamental constraint.", "Treat checkpoints as session-level local undo only; continue using Git for commits, branches, and permanent history — checkpoints complement, not replace, version control.", "Use 'Summarize from here' / 'Summarize up to here' to reclaim context window space mid-session (e.g. compress a verbose debugging stretch while keeping initial instructions in full detail) instead of a full /compact.", "Because bash-driven file changes (rm/mv/cp, build steps, generators) are not checkpointed, rely on Git — not rewind — to recover from those operations.", "Use rewind to safely explore alternative implementations or recover from a bug-introducing edit, knowing you can revert to a working state.", "When you want to try a different approach without destroying the current session, fork it (claude --continue --fork-session) rather than restoring/summarizing in place.", "For exploring large codebases, delegate to a subagent ('use a subagent to investigate ...') so only the summary returns and the main context stays clean.", "Use plan mode (`--permission-mode plan` or Shift+Tab) for any change you want to review before it touches disk; Claude proposes a plan and makes no edits until you approve.", "Use git worktrees (`claude --worktree <name>`) to run concurrent sessions (e.g. feature work + bug fix) without edits colliding, each on its own branch/checkout.", "Use @ references to inject specific files/dirs instead of waiting for Claude to discover them; note this also pulls in CLAUDE.md from that file's directory tree.", "For scheduled/autonomous tasks, write prompts that are explicit about what success looks like and what to do with results, since the task can't ask clarifying questions (e.g. specify which PRs, where to post the summary).", "Resume across sittings with `claude --continue` (most recent) or `claude --resume`/`/resume` (pick from list) rather than re-explaining context.", "Refactor in small, testable increments and verify with tests after each change.", "Choose the right scheduler: Routines for tasks that must run when your machine is off; Desktop scheduled tasks when local file/uncommitted access is needed; GitHub Actions for repo-event-driven tasks; `/loop` only for quick polling within an open session.", "Install a code-intelligence plugin for your language to give Claude precise go-to-definition / find-references navigation.", "Start codebase exploration broad (overview) then narrow; ask for coding conventions, key data models, and a glossary of project-specific terms.", "Keep project CLAUDE.md under 200 lines; move reference content to skills or path-scoped rules so it loads only when needed.", "Put the project CLAUDE.md in the project root so the whole team gets the same instructions automatically.", "Set disable-model-invocation: true on skills with side effects (commit, deploy, send messages) so they stay out of context entirely until explicitly invoked with /name.", "Put the most important instructions near the TOP of SKILL.md, because post-compaction skill re-injection truncates to the per-skill 5,000-token cap by keeping the start of the file.", "Be specific in prompts (e.g. name the exact file 'fix the bug in auth.ts') so Claude reads fewer files and consumes less context.", "Delegate research-heavy or large-file-read work to a subagent so the file contents stay in the subagent's context window, not the main one; only a small summary returns.", "Run /compact with a focus instruction before starting a long new task to control what the summary keeps.", "Run /clear when switching to unrelated work, since stale conversation crowds out needed files and costs tokens on every message.", "If a path-scoped rule must persist across compaction, drop its paths: frontmatter or move it into the project-root CLAUDE.md (path-scoped rules and nested CLAUDE.md are summarized away and only reload when a matching file is re-read).", "Keep PostToolUse hook additionalContext output concise since it enters context without truncation.", "Use ENABLE_TOOL_SEARCH=auto to keep MCP schema context cost bounded (loads schemas only when they fit within 10% of the window) rather than ENABLE_TOOL_SEARCH=false which loads all schemas upfront.", "Run /context periodically to see actual per-category usage and act before the automatic compaction pass fires.", "For teams needing very long sessions, select a [1m]-context model variant rather than relying on repeated compaction.", "Run a small pilot group with the tracking tools to establish a per-developer cost baseline before wider team rollout.", "Set Claude API workspace spend limits and a workspace rate limit on the auto-created 'Claude Code' workspace to cap its share and protect other production API workloads.", "Use the team-size rate-limit table to size TPM/RPM requests: total TPM = users x per-user TPM (e.g., 200 users x 20k = 4M TPM).", "On Bedrock/Vertex/Foundry, deploy LiteLLM as a gateway to get spend-by-key cost metrics, since Claude Code sends none from those clouds.", "For agent teams: use Sonnet for teammates, keep teams small, keep spawn prompts focused, and shut down teammates when their work is done (each consumes tokens until it exits).", "Use /clear between unrelated tasks to drop stale context; /rename + /resume to keep recoverable sessions.", "Keep CLAUDE.md under 200 lines (essentials only); move workflow-specific instructions (PR reviews, migrations) into on-demand skills so their tokens aren't always loaded.", "Default to Sonnet for coding; reserve Opus for complex architecture/multi-step reasoning; haiku for simple subagents.", "Prefer CLI tools (gh, aws, gcloud, sentry-cli) over MCP servers — they add no per-tool listing to context; run /mcp to disable unused servers and /context to audit consumers.", "Write preprocessing hooks (e.g., PreToolUse Bash matcher) to grep/filter verbose output (logs, test results) so only relevant lines enter context.", "Delegate verbose operations (tests, doc fetching, log processing) to subagents so only a summary returns to the main conversation.", "Use plan mode (Shift+Tab) before implementing complex tasks; course-correct early with Escape, and /rewind or double-Escape to restore a checkpoint.", "Write specific prompts (name the file/function) instead of vague ones ('improve this codebase') to avoid broad scanning and excessive file reads.", "Install code intelligence plugins for typed languages so symbol navigation replaces grep-and-read-many-files, and type errors are reported automatically after edits.", "Lower extended thinking effort (/effort, /config, or MAX_THINKING_TOKENS) for simple tasks that don't need deep reasoning.", "Enable fast mode at the START of a session, not mid-conversation: the first enable charges full fast-mode uncached input price for the entire context so far, which grows the deeper you are.", "Use fast mode for interactive, latency-sensitive work (rapid iteration, live debugging, tight deadlines); use standard mode for long autonomous tasks, batch/CI-CD pipelines, and cost-sensitive workloads.", "For maximum speed on straightforward tasks, combine fast mode with a lower effort level.", "For Team/Enterprise cost control with concurrent sessions, set fastModePerSessionOptIn:true in managed settings so fast mode resets off each session.", "To hard-disable fast mode org-wide or per-machine, set env var CLAUDE_CODE_DISABLE_FAST_MODE=1.", "Admins must explicitly enable fast mode AND turn on org usage credits before Team/Enterprise users can use it; also ensure the fast-mode Opus model is in the availableModels allowlist or /fast will be refused.", "Keep CLAUDE.md under 200 lines; move reference material to skills (on-demand) and split language/directory guidance into .claude/rules/ with 'paths' frontmatter so it only loads for matching files.", "Make guardrails hooks, not prompt instructions: a PreToolUse hook that blocks editing .env or rejects 'rm -rf /' is enforcement; 'never edit .env' in CLAUDE.md is only a request.", "Set 'disable-model-invocation: true' on skills with side effects so only humans trigger them and they cost zero context until invoked; use 'skillOverrides' in settings to do the same for skills you didn't author.", "Route side tasks that flood the conversation with output you won't reference (large file reads, broad searches) through a subagent to keep the main context clean.", "Build the setup incrementally by trigger: a convention Claude gets wrong twice -> CLAUDE.md; a repeated prompt -> user-invocable skill; a pasted multi-step playbook (3rd time) -> skill; data from a system Claude can't see -> MCP server; many file reads to locate a symbol -> code-intelligence plugin; a repo needing the same setup -> package as a plugin.", "Package a setup as a plugin (distributed via a marketplace) once a second repository needs the same skills/hooks/subagents/MCP servers, so it is reused rather than re-created.", "Use /mcp to inspect per-server token cost and connection status; disconnect MCP servers you're not actively using.", "Pair MCP with a skill: MCP provides the connection/auth, a skill documents the schema, query patterns, and which tables/tools to use — neither alone is sufficient.", "Install a code-intelligence (LSP) plugin for typed/large codebases so symbol lookups replace broad file reads (often net-reducing context).", "Switch from parallel subagents to an agent team only when subagents hit context limits or need to communicate with each other; otherwise subagents are cheaper (results summarized vs each teammate a full Claude instance).", "Treat a recurring mistake or repeated review comment as a CLAUDE.md/skill edit, not a one-off chat correction.", "Put persistent rules in CLAUDE.md, not conversation history — early-conversation instructions can be lost during compaction.", "Add a 'Compact Instructions' section to CLAUDE.md to control what survives compaction, or use '/compact focus on X' before a long stretch.", "Run /context to audit context usage and /mcp to find expensive MCP servers; trim large MCP surfaces since their tool names still cost context.", "Set 'disable-model-invocation: true' on manually-invoked skills (and skillOverrides for third-party skills) to keep descriptions out of context until needed.", "Offload research and large/long tasks to subagents so their context stays isolated and only a summary returns to the main session — key for long sessions.", "Pre-allow trusted commands (npm test, git status) in .claude/settings.json to avoid repeated permission prompts; scope policies org-wide down to personal.", "Use Plan mode (Shift+Tab twice) to separate research from coding on complex tasks: read/understand first, produce a plan, refine, then implement.", "Be specific upfront — reference exact files, constraints, and example patterns — to succeed on the first attempt and reduce steering.", "Give Claude something to verify against (test cases, expected output, screenshots) and ask it to run tests, so it can self-check.", "Steer mid-task: Esc to stop and cancel the current tool; or type a correction + Enter to adjust without interrupting the running tool.", "Use git worktrees to run parallel Claude sessions across branches without cross-contaminating conversation context.", "Use /init to bootstrap CLAUDE.md, /agents to configure subagents, and /doctor to diagnose install issues.", "Split CLAUDE.md by directory: root holds repository-wide rules (coding standards, commit conventions, layout); per-subdirectory/per-package files hold area-specific stack conventions. Commit all so teammates inherit; have each directory owner maintain its file.", "Start Claude from a package/subdirectory when work is scoped there (loads only that file + ancestors, excludes sibling packages automatically). Start from repo root only when the task spans multiple packages.", "Treat CLAUDE.md edits like documentation changes reviewed in PRs; revisit after major model releases to delete instructions that worked around now-fixed limitations (e.g. a forced single-file-refactor rule).", "Use `claudeMdExcludes` for packages you never touch (other teams', legacy, vendored); to focus on a different package day-to-day, re-launch from that package's directory instead of editing exclusions.", "Add `Read` deny rules for checked-in generated/vendored code that `.gitignore` doesn't cover; put org-wide ones in managed settings so user/project can't override.", "Install a code intelligence (LSP) plugin so Claude jumps to definitions/references instead of scanning and grepping the tree; combine with `claudeMdExcludes` + Read deny rules to keep context small.", "Use `worktree.sparsePaths` to check out only needed directories (faster, less disk), include `.claude` in the list to keep root settings/rules/skills, and pair with `symlinkDirectories: [\"node_modules\"]` to avoid duplicating heavy dirs.", "For cross-package changes, give Claude the whole change (shared edit + all call sites) in one session to keep decisions consistent, and have Claude write the plan to a markdown file in the repo so it survives context compaction.", "Keep skill descriptions short and lead with words a request would contain (e.g. 'writing or modifying tests in packages/api/'), because descriptions get truncated when many skills are discovered.", "Place skills shared across many directories in the repo root's `.claude/skills/` (load from any start dir); package skills needing independent versioning or cross-repo use as plugins.", "When per-directory CLAUDE.md governance stops scaling, move conventions/reference content out of always-loaded CLAUDE.md into on-demand skills, versioned plugins (owned by a platform team), or an MCP server exposing an existing code-search/RAG index.", "Add a Stop hook that reviews the session transcript and proposes CLAUDE.md updates while the exposed gap is fresh; add a SessionStart hook to recommend the right plugin per launch directory.", "Pick your model and effort level at the top of a session and avoid changing them mid-task; each change recomputes the entire request and costs a slow/expensive turn.", "Run /compact at a natural break between tasks rather than waiting for mid-task auto-compaction, so you control when the cache-rebuild overhead lands.", "To abandon a wrong path, prefer /rewind over /compact — rewinding truncates back to an already-cached prefix instead of building a new one.", "Enable fast mode (and the 1-hour TTL) at the start of a session rather than deep into a long one, since the uncached cost is paid once over a much smaller history early on.", "Keep CLAUDE.md, memory, output style, model, and effort stable for the whole session — mid-session edits to CLAUDE.md/output style silently don't apply until /clear, /compact, or restart anyway.", "Monitor cache health with a statusline script reading current_usage: a high cache_read_input_tokens-to-cache_creation_input_tokens ratio is good; persistently high creation means something in your prefix keeps changing.", "For org-wide governance, put caching env vars (disable flags, ENABLE_PROMPT_CACHING_1H / FORCE_PROMPT_CACHING_5M) in the env block of managed settings.", "Use the OpenTelemetry exporter to monitor per-user/per-session cache read and creation tokens across a team.", "Prefer deferred MCP tools (tool search, the default on supported models) so MCP server connect/disconnect/tool-list changes don't invalidate the cache; be aware that on Haiku, Vertex AI, custom gateways, or alwaysLoad servers, tools load into the prefix and MCP churn invalidates it.", "Use scoped deny rules (e.g. Bash(rm *)) rather than bare tool-name denies (e.g. Bash) to avoid mid-session cache invalidation; allow/ask rules never invalidate.", "Set DISABLE_AUTOUPDATER=1 (or just restart deliberately) to control when an upgrade's cache rebuild happens.", "Avoid resuming very long sessions immediately after a Claude Code upgrade — the first turn reprocesses the whole history with no cache hits and can be your most expensive request.", "On API key / Bedrock / Vertex with long idle gaps between turns, set ENABLE_PROMPT_CACHING_1H=1 to keep the cache warm (accepting higher cache-write rates); subscriptions already get 1-hour TTL free.", "For Agent SDK fleets, suppress per-machine system-prompt sections so multiple machines/users share one cache.", "Name sessions (`claude -n <name>` or `/rename <name>`) when running several tasks in parallel so they are findable and resumable by name.", "Use `/branch` (or `--fork-session`) to try a different approach without losing the current path; re-approve session permissions since they do not carry to the branch.", "Use `/context` to inspect what is consuming the context window, then `/compact` or `/clear` to manage it within a session rather than restarting.", "Resume headless (`claude -p`) or Agent SDK sessions by passing their session ID to `claude --resume <session-id>` from the directory they were started in.", "For team/multi-user privacy or shared machines, set `CLAUDE_CODE_SKIP_PROMPT_HISTORY` (or `--no-session-persistence` in non-interactive runs) to avoid writing transcripts.", "Relocate session storage off the default home with `CLAUDE_CONFIG_DIR`, and tune retention with the `cleanupPeriodDays` setting.", "Use ultraplan when you want a richer review surface than the terminal: comment on individual plan sections, keep the terminal free for other work during drafting, and pick cloud-vs-local execution at the end.", "Watch for the `◇ ultraplan needs your input` status and open the session link promptly to answer clarifying questions, or drafting stalls.", "For a clean execution context, choose 'Start new session' so only the approved plan seeds the conversation; rely on the printed `claude --resume` command to recover the prior session if needed.", "If you don't want to execute immediately, choose 'Cancel' to persist the plan to the printed file path and return to it later.", "Use `/code-review` for fast local feedback while iterating, `/review <pr>` to vet a teammate's PR before approving, and `/code-review ultra` before merging substantial changes for a deeper verified pass.", "For large repos that can't be bundled, push your branch and open a draft PR, then run `/code-review ultra <PR-number>` (PR mode clones from host).", "In CI, use `claude ultrareview` with `--json` to capture the raw `bugs.json` payload and rely on exit codes (0 success, 1 failure) for gating; keep stdout parseable since progress/URL go to stderr.", "For repository-integrated automatic PR reviews that post inline comments without a CLI step, use the Code Review GitHub integration instead of the CLI.", "Use a workflow (not subagents/skills/agent-teams) when a task needs more agents than one conversation can coordinate or when you want the orchestration codified as a rerunnable script: codebase-wide bug sweeps, 500-file migrations, cross-checked research, multi-angle planning.", "To gauge cost before a large run, run the workflow on a small slice first (one directory, or a narrow question); watch per-agent token usage in /workflows and stop anytime without losing completed work.", "Before a long run, add the shell commands, web fetches, and MCP tools the agents will need to your tool allowlist so they don't prompt mid-run.", "Check /model before a large workflow run if you usually use a smaller model for routine work, since every agent uses the session model unless the script routes a stage elsewhere; ask Claude to use a smaller model for stages that don't need the strongest.", "For sign-off between stages, run each stage as its own separate workflow — there is no mid-run user input within a single workflow.", "Save reusable orchestrations to .claude/workflows/ in the repo to share a repeatable process (e.g. a per-branch review) with the whole team; use ~/.claude/workflows/ for personal cross-project workflows.", "Pass per-run input via 'args' instead of editing the script each time (e.g. 'Run /triage-issues on issues 1024, 1025, 1030').", "If you have an existing orchestrator (folder of subagent prompts or a fan-out skill), point Claude at it and ask for a workflow that does the same thing.", "Use /effort high to drop out of ultracode for routine work, since ultracode turns single requests into multiple workflows and multiplies token use and latency.", "Read or diff the generated script (path under ~/.claude/projects/, or Ctrl+G at the approval prompt) before approving, then save it once a run does what you want."], "gotchas": ["Bloated/over-long CLAUDE.md causes Claude to ignore instructions — important rules get lost in noise. Ruthlessly prune.", "LLM performance degrades as the context window fills; Claude may 'forget' earlier instructions or make more mistakes when it gets full.", "Stop hooks are overridden after 8 consecutive blocks — Claude Code ends the turn anyway, so a Stop-hook gate is not absolutely unbreakable.", "Checkpoints only track changes made by Claude, not external processes — not a replacement for git.", "A reviewer subagent prompted to find gaps will usually report some even when work is sound; chasing every finding leads to over-engineering (extra abstraction, defensive code, impossible-case tests).", "Auto mode aborts non-interactive (-p) runs if the classifier repeatedly blocks actions, because there is no user to fall back to.", "CLAUDE.local.md must be added to .gitignore manually or it will be shared with the team.", "Common failure pattern 'kitchen sink session': mixing unrelated tasks fills context with irrelevant info — /clear between them.", "The trust-then-verify gap: plausible-looking implementations may miss edge cases; if you can't verify it, don't ship it.", "Files changed by bash commands (rm, mv, cp, build scripts) are NOT tracked and cannot be undone by rewind — a major silent gap if you assume checkpoints cover all file changes.", "Manual edits made outside Claude Code and edits from concurrent sessions are not captured unless they touch the same files the current session edited — risky in multi-agent / team setups sharing a working tree.", "Double-Esc only opens the rewind menu when the input is empty; if there is text it just clears the input, which can surprise users expecting the menu.", "Checkpoints (and their parent sessions) are auto-deleted after 30 days, so they are not a durable recovery mechanism.", "'Restore code and conversation' reverts code on disk — if you only meant to rewind the chat, choose 'Restore conversation' instead, or you'll lose file work.", "`/loop` scheduled tasks stop when you start a new conversation; only `--resume`/`--continue` restore unexpired ones.", "Image paste uses ctrl+v even on Mac — cmd+v does NOT work for pasting images into the CLI.", "Directory @ references show only a file listing, not file contents.", "`claude --continue` with no prior session in the current directory prints 'No conversation found to continue' and exits (it does not start a fresh session interactively).", "Claude reads files fresh per tool call, so edits made in another app are only picked up on the next read of that file.", "Path-scoped rules (paths: frontmatter) and nested subdirectory CLAUDE.md files do NOT survive compaction and are lost until a matching file is read again — surprising if you rely on them persisting.", "Skill descriptions are the one piece of startup content NOT re-injected after /compact; only skills you actually invoked are preserved.", "Invoked skill bodies are truncated to 5,000 tokens/skill and 25,000 tokens total after compaction, with oldest dropped first — large skills lose their tail.", "Hook plain stdout on exit 0 is invisible to Claude (debug log only); only hookSpecificOutput.additionalContext JSON reaches context. A common mistake is expecting stdout to inform Claude.", "For PostToolUse hooks, exit code 2 surfaces stderr as an error but CANNOT block the tool because it already ran.", "Subagents do NOT inherit the main session's conversation history or auto memory, so they start 'cold' aside from CLAUDE.md/MCP/skills.", "Subagents by default cannot spawn further subagents (Agent/Task tool withheld to prevent recursion).", "Built-in Explore and Plan agents skip CLAUDE.md, so project conventions in CLAUDE.md won't apply to them.", "Tool/command outputs that show as terse one-liners in the terminal still consume their full token count in Claude's context.", "A great deal loads before you type your first prompt (CLAUDE.md, memory, skills, MCP names), so the context is already substantially filled at session start.", "Token counts in the docs visualization are illustrative; actual usage varies with CLAUDE.md size, MCP servers, and file lengths.", "The /usage dollar figure is a LOCAL estimate from token counts and may differ from the actual bill — use Claude Console Usage page for authoritative billing.", "/usage only reflects local session history on the current machine; usage from other devices or claude.ai is excluded.", "For Max/Pro subscribers the Session block dollar cost in /usage is not relevant for billing (usage is included in the subscription).", "On Bedrock/Vertex/Foundry, Claude Code sends NO cost metrics — you get zero cost visibility unless you add an external gateway like LiteLLM (which is unaffiliated with Anthropic and unaudited for security).", "Claude Code traffic in the auto-created workspace counts against your org's overall API rate limits and can starve other production workloads unless you set a workspace rate limit.", "Agent teams cost ~7x a standard session in plan mode and each teammate keeps consuming tokens until it exits or the session ends.", "Extended thinking is ON by default and bills as output tokens (tens of thousands per request possible) — easy to overspend on simple tasks.", "MAX_THINKING_TOKENS is ignored by adaptive-reasoning models; thinking cannot be disabled at all on Fable 5.", "A bloated CLAUDE.md loads its full token cost into every session even for unrelated work — move specialized instructions to skills.", "Claude Code consumes a small amount of tokens in the background even when idle (summarization for --resume, /usage status checks).", "Fast mode tokens are billed at the fast-mode rate from the FIRST token and draw from usage credits even when you still have plan-included usage remaining — they do not count against the subscription.", "Disabling fast mode with /fast leaves you on Opus; it does NOT revert to your previous (possibly cheaper) model. Use /model to switch back.", "Disabled by default for Team and Enterprise orgs — it won't work until an admin enables it; /fast shows an org-disabled message otherwise.", "Not available on Bedrock, Vertex AI, Azure Foundry, or Claude Platform on AWS — only Anthropic Console API / subscription.", "Not available in the VS Code extension.", "An availableModels allowlist that excludes the fast-mode Opus model silently blocks /fast with an 'allowed models' refusal even if fast mode is otherwise enabled.", "Opus 4.6 fast mode is deprecated and will silently fall back to standard speed/pricing ~30 days after Opus 4.8 launch.", "Default fast-mode model differs by CLI version (4.8 on v2.1.154+, 4.7 on v2.1.142–2.1.153), so cost-per-token can differ across team members on different versions ($10/$50 vs $30/$150).", "Precedence differs per feature: skills are managed>user>project but subagents are managed>CLI flag>project>user>plugin and MCP is local>project>user. CLAUDE.md is additive (no override) and hooks merge (all fire). Don't assume one uniform precedence rule.", "CLAUDE.md conflicts are resolved by Claude's judgment, not a hard rule — 'more specific typically takes precedence' is a tendency, not a guarantee.", "By default every model-invocable skill's description loads into context every request; many overlapping/vague descriptions cause Claude to load the wrong skill or miss a relevant one, and add noise that degrades effectiveness.", "Built-in Explore and Plan subagents OMIT CLAUDE.md and git status at startup — your conventions won't be in their context.", "Subagents do NOT inherit your conversation history or already-invoked skills; only skills in their 'skills:' field are preloaded, so context must be passed explicitly in the prompt.", "Adding too many extensions doesn't just fill the context window — the added noise can make skills mis-trigger and cause Claude to lose track of conventions.", "Agent teams are experimental, disabled by default, and cost more tokens (each teammate is a separate Claude instance).", "Plugin skills must be invoked with the namespaced form /plugin-name:skill, not a bare /skill.", "Sessions do NOT inherit prior conversation history — only CLAUDE.md and auto memory persist; don't assume yesterday's context is present.", "Detailed instructions from early in a conversation can silently disappear after compaction; relying on them instead of CLAUDE.md is a failure mode.", "Auto memory only loads the first 200 lines or 25KB of MEMORY.md — content beyond that is not loaded at session start.", "Checkpoints only revert file changes; remote side effects (DB writes, API calls, deployments) cannot be undone, which is why Claude prompts before such commands.", "A single oversized file/tool output can trigger a thrashing error that halts auto-compaction (it stops looping after a few attempts rather than recovering automatically).", "Code intelligence features (type errors, find references) are NOT built-in — they require code intelligence plugins.", "Auto mode is a research preview, not a stable/guaranteed mode.", "Even in Plan mode, normal permission prompts still apply as in default mode (Plan mode only prevents source edits, not all actions).", "`.claude/settings.json` does NOT inherit from parent directories (unlike CLAUDE.md) — it loads only from the starting directory. Each subdirectory's settings file must be self-contained, and worktree sessions load settings from the worktree root, so deny rules/hooks needed in worktrees must also live in the repo root's `.claude/settings.json` (a second copy).", "Managed policy CLAUDE.md files cannot be excluded by `claudeMdExcludes`.", "Read deny rules do NOT filter denied paths out of recursive search OUTPUT, and do NOT block arbitrary subprocesses that open files — only built-in tools and recognized Bash file commands with the path as an argument.", "`additionalDirectories` setting grants file read/write but never loads that directory's CLAUDE.md, rules, OR skills; `--add-dir` loads skills but loads CLAUDE.md/rules only with `CLAUDE_CODE_ADDITIONAL_DIRECTORIES_CLAUDE_MD=1`. Easy to assume conventions follow the granted directory — they don't.", "`sparsePaths` lists directories only; listing individual files won't work. Root-level directories (including `.claude`) are not auto-included — omitting `.claude` silently drops root settings/rules/skills inside the worktree.", "Starting Claude from the repo root can accumulate skills from every subdirectory it touches into the hundreds, and many-skill description truncation can strip the keywords Claude needs to pick the right one.", "claudeMdExcludes glob patterns match against ABSOLUTE paths, so a relative-looking pattern without a leading `**/` won't match files deeper in the tree.", "Long cross-package sessions compact context mid-task; conversation history (including an in-memory plan) may not survive — save the plan to a file.", "Editing project-root or user-level CLAUDE.md mid-session silently has NO effect — Claude keeps the session-start version until /clear, /compact, or restart. Same for output style changes.", "opusplan makes entering/leaving plan mode a model switch (Opus↔Sonnet), so each plan toggle invalidates the cache even though permission-mode changes are normally cache-safe.", "MCP servers can invalidate the cache with no action on your part when tools load into the prefix: a stdio process exiting, an HTTP session expiring, automatic reconnection after a transient failure, or a server pushing a dynamic tool update.", "A bare tool-name deny rule (Bash, WebFetch, Bash(*), or \"*\") invalidates the cache; scoped denies and allow/ask rules don't — the distinction is whether the rule removes a tool from context vs. is checked at call time.", "Resuming a session after a Claude Code upgrade reprocesses the entire history uncached — cost scales with how long the resumed conversation is.", "Switching models can feel free but causes a slower, more expensive turn afterward because the new model's cache starts cold.", "Subagents always use the 5-minute TTL even on a subscription (the automatic 1-hour TTL applies only to the main conversation).", "Worktrees of the same repo have different working directories, so they build different prefixes and miss each other's cache; sequential sessions in one dir only share cache if the startup git-status snapshot (branch + recent commits) matches.", "On Bedrock, prompt caching support, minimum cacheable prefix length, and 1-hour TTL availability vary by model — zero cache token counts means the model/region doesn't support it.", "Fast mode toggles and rate-limit fallbacks invalidate the cache on Claude Code versions earlier than v2.1.86.", "As of v2.1.163, /reload-plugins refuses to apply a reload that would force a full cache re-read unless you pass --force.", "Resuming the same session in two terminals WITHOUT forking interleaves messages from both into one transcript.", "Permissions approved with 'allow for this session' do NOT carry over when you branch/fork the session.", "Headless (`claude -p`) and Agent SDK sessions are invisible in the session picker — you must know the session ID to resume them.", "Session ID lookup only works from the originating project directory/worktrees; elsewhere it reports 'No conversation found with session ID'.", "`/resume <name>` errors on an ambiguous name (whereas `claude --resume <name>` opens the picker pre-filled instead).", "Transcripts are deleted after 30 days by default (`cleanupPeriodDays`), so long-term reference requires `/export` or backup.", "Desktop app, web, and VS Code extension keep separate session histories from the CLI — a session in one is not in the others.", "Selecting a session from an unrelated project does not resume it in place; it only copies a cd+resume command to the clipboard.", "Hard requirement: Claude Code v2.1.91+ and a Claude Code on the web account plus a GitHub repo; behavior may change since it is a research preview.", "Unavailable on Bedrock, Vertex AI, and Microsoft Foundry deployments — relevant for teams pinned to those backends.", "The keyword path is implicit: the word `ultraplan` anywhere in a normal prompt triggers it (though command/keyword paths do show a confirmation dialog).", "Remote Control and ultraplan are mutually exclusive — starting ultraplan disconnects an active Remote Control session.", "Stopping ultraplan via `/tasks` archives the cloud session and saves nothing to the terminal — drafting work is lost.", "'Teleport back to terminal' only appears if launched from the CLI and the terminal is still polling; otherwise you must execute on the web.", "Team and Enterprise plans get ZERO free ultrareview runs — every run bills as usage credits, which must be explicitly turned on or the launch is blocked.", "A free run is consumed even if the review is stopped early or fails to complete, because it counts once the cloud session starts.", "Stopping a review via `/tasks` archives the cloud session and returns NO partial findings.", "Ultrareview is entirely unavailable on Bedrock, Vertex AI, Microsoft Foundry, and for Zero-Data-Retention organizations — and requires Claude.ai auth, not API-key-only.", "Interrupting `claude ultrareview` (Ctrl-C, exit 130) does not stop the remote review — it keeps running and billing; you must follow the session URL to manage it.", "If the PR diff is too large, the review is refused before any work runs; if the local repo is too large to bundle, you're forced into PR mode.", "Subagents in a workflow always run in acceptEdits mode and auto-approve file edits regardless of your session permission mode — your session mode only gates the launch prompt, not the agents' edits.", "Resume only works within the same Claude Code session; if you exit Claude Code while a workflow is running, the next session starts it fresh (no cross-session resume).", "Under ultracode a single request can silently spawn several workflows in a row (understand → change → verify), so each request costs more tokens and takes longer.", "In Auto permission mode the approval prompt is skipped entirely when ultracode is on, and any 'Yes' in Auto records consent in user settings so later launches don't prompt.", "The trigger keyword changed: before v2.1.160 it was 'workflow'; now it's 'ultracode' (natural-language requests work in both).", "Even with an approved launch, non-allowlisted shell/web/MCP tool calls can still interrupt a long run with mid-run prompts.", "In claude -p and the Agent SDK there is no interactive confirmation at all — tool calls just follow configured permission rules, so a misconfigured allowlist runs unattended.", "Workflow runs count toward plan usage and rate limits like any session, and a single run can use meaningfully more tokens than doing the task in conversation; the 16-concurrent / 1,000-total agent caps are the main guardrail against runaway cost.", "Monorepo precedence is subtle: project workflows beat same-named personal ones, and among multiple .claude/workflows/ dirs the one closest to the working directory wins (v2.1.178+)."], "claims": ["CLAUDE.md is read at the start of every conversation. Locations: ~/.claude/CLAUDE.md (all sessions), ./CLAUDE.md (project root, check into git to share), ./CLAUDE.local.md (personal, add to .gitignore), parent directories (monorepos, pulled in automatically), child directories (pulled in on demand when Claude reads a file there).", "CLAUDE.md supports imports via @path/to/import syntax (e.g. @README.md, @docs/git-instructions.md, @~/.claude/my-project-instructions.md).", "/init generates a starter CLAUDE.md by analyzing the codebase to detect build systems, test frameworks, and code patterns.", "Skills live in .claude/skills/<name>/SKILL.md with YAML frontmatter (name, description). Invoked automatically when relevant, or directly as /skill-name. disable-model-invocation: true makes a skill manual-only (for workflows with side effects). $ARGUMENTS in the skill body receives invocation args (e.g. /fix-issue 1234).", "Subagents are defined in .claude/agents/<name>.md with frontmatter fields: name, description, tools (e.g. Read, Grep, Glob, Bash), model (e.g. opus). They run in their own context window with their own allowed tools and report back summaries.", "Hooks are configured in .claude/settings.json and run scripts deterministically at workflow points. Browse configured hooks with /hooks. A Stop hook can block a turn from ending until a check passes; Claude Code overrides the Stop hook and ends the turn after 8 consecutive blocks.", "MCP servers are added via 'claude mcp add'.", "Plugins bundle skills, hooks, subagents, and MCP servers into one installable unit. Browse the marketplace with /plugin.", "Permission reduction options: auto mode (a separate classifier model reviews commands and blocks risky ones — scope escalation, unknown infrastructure, hostile-content-driven actions), permission allowlists via /permissions, and OS-level sandboxing via /sandbox.", "Non-interactive mode: 'claude -p \"prompt\"'. Output formats via --output-format: text (default), json, stream-json (requires --verbose for streaming). --allowedTools scopes permissions for batch/unattended runs (e.g. --allowedTools \"Edit,Bash(git commit *)\").", "Auto mode for unattended runs: 'claude --permission-mode auto -p \"...\"'. With -p (non-interactive), auto mode aborts if the classifier repeatedly blocks actions since there is no user fallback.", "/clear resets the context window entirely between unrelated tasks. /compact <instructions> compacts with focus (e.g. /compact Focus on the API changes). Claude auto-compacts near context limits.", "Esc stops Claude mid-action with context preserved; Esc+Esc or /rewind opens the rewind menu to restore conversation, code, or both to a checkpoint. Every prompt creates a checkpoint; checkpoints persist across sessions but only track changes made by Claude (not external processes) — not a git replacement.", "Rewind/summarize options: select a message checkpoint then 'Summarize from here' (condense messages forward, keep earlier context) or 'Summarize up to here' (condense earlier, keep recent in full).", "Session resume: 'claude --continue' picks up the most recent session; 'claude --resume' chooses from a list; /rename names a session.", "Plan mode separates exploration from execution; press Ctrl+G to open the plan in your text editor for direct editing before Claude proceeds.", "/btw answers a side question in a dismissible overlay that never enters conversation history (does not grow context).", "/goal sets a check condition; a separate evaluator re-checks it after every turn and Claude keeps working until it holds.", "Bundled /code-review skill reviews the current diff for bugs in a fresh subagent and returns findings to the session.", "Reference files with @ (Claude reads before responding); paste/drag images into the prompt; pipe data via 'cat error.log | claude'; allowlist frequently-used doc domains with /permissions.", "Claude Code automatically captures the state of code before each edit; every user prompt creates a new checkpoint.", "Checkpoints persist across sessions and are accessible in resumed conversations.", "Checkpoints are automatically cleaned up along with sessions after 30 days (described as configurable, but the page does not name the setting key).", "Open the rewind menu with the /rewind command or by pressing Esc twice when the prompt input is empty.", "If the prompt input contains text, double Esc clears it instead of opening the rewind menu; the cleared text is saved to input history and recallable with Up.", "Rewind menu actions: 'Restore code and conversation', 'Restore conversation' (code kept), 'Restore code' (conversation kept), 'Summarize from here', 'Summarize up to here', 'Never mind'.", "'Summarize from here' replaces the selected message and everything after it with a summary, keeping earlier messages intact.", "'Summarize up to here' replaces messages before the selected message with a summary, keeping the selected message and later messages intact; leaves you at the end of the conversation with empty input.", "Summarize compresses context within the same session without changing files on disk; original messages are preserved in the session transcript so Claude can still reference them. You can type optional instructions to guide the summary focus.", "Checkpointing does NOT track files modified by bash commands (e.g. rm, mv, cp); those cannot be undone via rewind. Only edits made through Claude's file-editing tools are tracked.", "Checkpointing does NOT capture manual external edits or edits from other concurrent sessions unless they modify the same files the current session edited.", "To branch off and try a different approach while preserving the original session intact, use fork (claude --continue --fork-session) instead of summarize.", "`claude --continue` resumes the most recent session in the current directory; if none exists it prints 'No conversation found to continue' and exits.", "`claude --resume` shows a list of sessions to choose from; `/resume` does the same from inside a running session.", "When you create a PR with `gh pr create`, the session is automatically linked to that PR; return to it with `claude --from-pr <number>` or paste the PR URL into the `/resume` picker search.", "`claude --worktree <name>` starts an isolated parallel session on a separate git checkout/branch; run with a different name in a second terminal for concurrent non-colliding edits.", "Worktrees support `.worktreeinclude` (controls what gets included) and non-git VCS; cleanup is documented at /en/worktrees.", "Plan mode: start with `claude --permission-mode plan`, or toggle mid-session with `Shift+Tab`. Claude reads files and proposes a plan but makes no edits until approved.", "Delegate research to a subagent by prompting e.g. 'use a subagent to investigate ...'; the subagent reads files in its own context window and returns only a summary, keeping the main context clean.", "Non-interactive/headless mode: `claude -p \"<prompt>\"`; stdin/stdout work like a Unix tool, e.g. `git log --oneline -20 | claude -p \"summarize these recent commits\"`.", "@ references: `@src/utils/auth.js` includes full file content; `@src/components` provides a directory listing (not contents); `@server:resource` (e.g. `@github:repos/owner/repo/issues`) fetches MCP resources.", "@ file references also add the CLAUDE.md in that file's directory and parent directories to context.", "The `.claude/` directory and `CLAUDE.md` coexist with other tools' config directories without conflict; Claude reads files fresh on each tool call, so external edits are seen on the next read.", "Paste an image into the CLI with ctrl+v (NOT cmd+v, even on Mac); or drag-and-drop, or give a file path.", "Scheduling options: Routines (Anthropic-managed infra, configure at claude.ai/code/routines, can trigger on schedule/API/GitHub events); Desktop scheduled tasks (local machine via desktop app); GitHub Actions (CI pipeline); `/loop` (current CLI session, stops on new conversation, restorable via --resume/--continue if unexpired).", "Claude Code has built-in access to its own latest documentation regardless of installed version; `/powerup` runs interactive lessons with animated demos.", "Default context window is 200,000 tokens (MAX = 200000 in the simulation).", "Auto memory (MEMORY.md) is loaded into context as the first 200 lines OR 25KB, whichever comes first.", "Startup auto-loaded content (before first prompt) includes: system prompt (~4.2K tokens), auto memory MEMORY.md, environment info, MCP tool names (deferred), skill descriptions, ~/.claude/CLAUDE.md (global), and project CLAUDE.md.", "By default MCP full tool schemas stay deferred; Claude loads specific ones on demand via tool search. ENABLE_TOOL_SEARCH=auto loads schemas upfront when they fit within 10% of the context window; ENABLE_TOOL_SEARCH=false loads everything (all schemas) upfront.", "Git branch, status, and recent commits load as a separate block at the very end of the system prompt (not with the rest of environment info).", "Skills with disable-model-invocation: true are NOT in the startup skill-description index and cost zero context until invoked with /name; full skill body loads only on invocation.", "Skill descriptions (the one-line startup listing) are NOT re-injected after /compact; only skills actually invoked are preserved.", "Path-scoped rules in .claude/rules/ with a paths: frontmatter pattern load automatically only when Claude reads a file matching that pattern; terminal shows 'Loaded .claude/rules/<file>' but not the content.", "PostToolUse hook output reaches Claude's context ONLY via hookSpecificOutput.additionalContext JSON field. Plain stdout on exit 0 goes to the debug log only, not context. Exit code 2 surfaces stderr as an error to Claude but cannot block a PostToolUse hook (tool already ran). additionalContext enters context without truncation.", "Subagents get their own separate context window: own (shorter) system prompt, own copy of project CLAUDE.md, same MCP servers and skills, but NOT the main session's conversation history or auto memory. Only the subagent's final text response (plus small metadata trailer with token counts/duration) returns to the parent context.", "Built-in Explore and Plan agents skip loading project CLAUDE.md for a smaller context. The general-purpose subagent does load CLAUDE.md.", "Subagents lack several parent tools that don't apply in nested context: plan-mode controls, background-task tools, and by default the Agent/Task tool itself (to prevent recursion).", "A custom agent with memory: in its frontmatter loads its own separate MEMORY.md instead of the main session's auto memory.", "After /compact, invoked skill bodies are re-injected but capped at 5,000 tokens per skill and 25,000 tokens total; oldest invoked skills dropped first when total budget exceeded. Truncation keeps the START of the file.", "What survives compaction: system prompt and output style (unchanged, not in message history); project-root CLAUDE.md and unscoped rules (re-injected from disk); auto memory (re-injected from disk); rules with paths: frontmatter (LOST until a matching file is read again); nested CLAUDE.md in subdirectories (LOST until a file in that subdir is read again); hooks (run as code, not context).", "/compact accepts focus instructions, e.g. '/compact focus on the auth bug fix', to keep chosen content instead of the automatic pass's guess.", "/clear resets conversation for unrelated work; /context shows live context breakdown by category with optimization suggestions; /memory shows which CLAUDE.md and auto memory files loaded at startup.", "Compaction summary keeps: user requests/intent, key technical concepts, files examined/modified with important code snippets, errors and fixes, pending tasks, current work. It discards verbatim full tool outputs and intermediate reasoning.", "Bash mode with ! prefix (e.g. !git status) runs the command in your shell; both the command AND its output enter context as part of your message.", "--append-system-prompt text and output styles both go into the system prompt the same way as auto-loaded startup content.", "Claude Code auto-compacts as you approach the context limit; the automatic pass works the same way as manual /compact, so a full window does not end the session.", "Fable 5, Opus 4.6 and later, and Sonnet 4.6 support a 1 million token context window via a [1m] model variant; availability varies by plan (see /en/model-config#extended-context). Compaction works the same at the larger limit.", "File reads dominate context usage; tool/command outputs (grep, npm test) are summarized in the terminal as one-liners but the full output still enters Claude's context.", "Average enterprise cost is ~$13/developer/active day and $150-250/developer/month; below $30/active day for 90% of users.", "/usage shows the Session block with token usage; the dollar figure is a local estimate from token counts and may differ from the actual bill.", "/usage attributes recent usage to skills, subagents, plugins, and individual MCP servers as percentages; press 'd' or 'w' to toggle last 24 hours vs last 7 days.", "/usage figures are computed from local session history on the current machine only — usage from other devices or claude.ai is not included.", "VS Code extension shows the same usage breakdown in Account & usage dialog (Day/Week toggle); requires Claude Code v2.1.174 or later.", "Authoritative billing is the Usage page in Claude Console (platform.claude.com/usage), not /usage.", "Claude API workspace spend limits cap total Claude Code workspace spend; admins view cost/usage reporting in Console.", "On Pro and Max plans, /usage-credits sets a monthly spend limit on usage credits; changing the limit requires billing access on the account.", "First authentication auto-creates a workspace named 'Claude Code' for centralized cost tracking; you cannot create API keys for it — it is exclusively for Claude Code auth/usage.", "Claude Code traffic in the auto-created workspace counts toward the org's overall API rate limits; set a workspace rate limit on its Limits page to cap Claude Code's share.", "On Bedrock, Vertex, and Foundry, Claude Code does NOT send cost metrics; enterprises use LiteLLM (unaffiliated, unaudited) to track spend by key.", "Per-user rate limit recommendations decrease with team size: 1-5 users 200k-300k TPM / 5-7 RPM; 100-500 users 15k-20k TPM / 0.37-0.47 RPM; 500+ users 10k-15k TPM. Limits apply at org level, not per individual user.", "Agent teams are disabled by default; enable with CLAUDE_CODE_EXPERIMENTAL_AGENT_TEAMS=1 in settings.json or environment.", "Agent teams use ~7x more tokens than standard sessions when teammates run in plan mode; each teammate has its own context window as a separate Claude instance.", "/compact <instructions> (e.g. '/compact Focus on code samples and API usage') tells Claude what to preserve during summarization; compact behavior can also be set via a '# Compact instructions' section in CLAUDE.md.", "MCP tool definitions are deferred by default — only tool names enter context until a specific tool is used. Run /context to see context consumers; /mcp to disable unused servers.", "Extended thinking is enabled by default; thinking tokens bill as output tokens, default budget can be tens of thousands of tokens per request. Lower with /effort, disable in /config, or set MAX_THINKING_TOKENS=8000 on fixed-budget models.", "Adaptive-reasoning models ignore nonzero MAX_THINKING_TOKENS budgets — use effort levels there instead. Disabling thinking is unavailable on Fable 5 (always uses extended thinking).", "For simple subagent tasks specify 'model: haiku' in subagent config; set default model in /config or switch with /model mid-session.", "Background token usage (conversation summarization for --resume, command processing like /usage) typically consumes under $0.04 per session even when idle.", "Prompt caching reduces costs for repeated content (system prompts) and auto-compaction summarizes history near context limits — both automatic.", "claude --version checks current version (cost reporting behavior can change between updates).", "Fast mode is a high-speed API configuration for Claude Opus, up to 2.5x faster at higher cost per token. It is NOT a different model — same quality/capabilities, just a config that prioritizes speed over cost efficiency.", "Fast mode is supported only on Opus 4.8, Opus 4.7, and Opus 4.6. Not available on Sonnet, Haiku, or other models.", "Toggle fast mode by typing /fast and pressing Tab (CLI only), or by setting \"fastMode\": true in the user settings file. Run /fast again to check current on/off state.", "Fast mode is not supported in the VS Code extension — CLI only.", "Requires Claude Code v2.1.36 or later (check with claude --version).", "Opus 4.8 is the fast mode default in Claude Code v2.1.154+. On v2.1.142 through v2.1.153, fast mode defaults to Opus 4.7.", "Fast mode pricing per MTok input/output: Opus 4.8 = $10/$50; Opus 4.7 and Opus 4.6 = $30/$150. Pricing is flat across the full 1M-token context window.", "Available to all Claude Code users on subscription plans (Pro/Max/Team/Enterprise) and Claude Console. For subscription plans, fast mode is available via usage credits ONLY and is NOT included in subscription rate limits.", "Fast mode usage draws directly from usage credits even if plan usage remains; fast mode tokens do not count against plan-included usage and are charged at the fast mode rate from the first token.", "Requirements: Anthropic Console API or Claude subscription only. NOT available on Amazon Bedrock, Google Vertex AI, Microsoft Azure Foundry, or Claude Platform on AWS.", "Requirement: usage credits must be turned on (billing beyond plan's included usage). Individuals enable in Console billing settings; for Team/Enterprise an admin must turn on usage credits for the org.", "Fast mode is DISABLED by default for Team and Enterprise organizations. An admin must explicitly enable it before users can access it.", "Admins enable fast mode in Console (API customers) at Claude Code preferences (platform.claude.com/claude-code/preferences), or in Claude AI (Team/Enterprise) at Admin Settings > Claude Code (claude.ai/admin-settings/claude-code).", "Set env var CLAUDE_CODE_DISABLE_FAST_MODE=1 to disable fast mode entirely.", "Admins on Team/Enterprise can set \"fastModePerSessionOptIn\": true in managed settings or server-managed settings, so each session starts with fast mode OFF, requiring explicit /fast per session. Used to control costs with concurrent sessions. User preference is still saved; removing the setting restores persistent behavior.", "By default fast mode persists across sessions (a user who enables it keeps it on in future sessions) unless fastModePerSessionOptIn is set.", "First enabling fast mode in a conversation charges the full fast-mode UNCACHED input token price for the entire conversation context. Cost applies once per conversation; toggling off then on again does not repeat it.", "Fast mode has separate rate limits from standard Opus. Opus 4.8, 4.7, and 4.6 fast mode share the same rate limit pool.", "On hitting fast mode rate limit or running out of credits: fast mode auto-falls-back to standard speed/pricing, the ↯ icon turns gray (cooldown), and fast mode auto-re-enables when cooldown expires.", "If admin has not enabled fast mode, /fast shows \"Fast mode has been disabled by your organization.\" If the org's availableModels allowlist excludes the fast-mode Opus model, /fast is refused with \"is not in your organization's allowed models\".", "Enabling fast mode while on a non-Opus model auto-switches to Opus. Disabling fast mode with /fast keeps you on Opus (does not revert to previous model); use /model to switch.", "Fast mode is in research preview — feature, pricing, and availability may change.", "Fast mode for Opus 4.6 is deprecated and will be removed ~30 days after Opus 4.8 launch; after removal it falls back to standard speed/pricing on 4.6. Migrate to Opus 4.8 or 4.7 to keep the speedup.", "Feature precedence when same name exists at multiple levels: SKILLS override by name with priority managed > user > project.", "SUBAGENTS override by name with priority managed > CLI flag > project > user > plugin.", "MCP servers override by name with priority local > project > user.", "CLAUDE.md files are ADDITIVE, not overriding: all levels (managed, user, project, nested subdirectory) contribute content simultaneously; Claude reconciles conflicts by judgment, with more specific instructions typically taking precedence.", "HOOKS MERGE: all registered hooks fire for their matching events regardless of source (no override).", "Features can be defined at four levels: user-wide, per-project, via plugins, or through managed policies.", "Plugin skills are namespaced as /plugin-name:skill (e.g. /my-plugin:review) so multiple plugins can coexist without conflict.", "A plugin bundles skills, hooks, subagents, and MCP servers into a single installable unit; distributed via a marketplace.", "Set 'disable-model-invocation: true' in a skill's frontmatter to hide it from Claude entirely until manually invoked, reducing its context cost to zero (descriptions otherwise load every request).", "To hide a skill you didn't write without editing its file, set 'skillOverrides' in settings.", "CLAUDE.md loads full content at session start; recommended limit is under 200 lines.", "Use .claude/rules/ files to split CLAUDE.md; rules with 'paths' frontmatter only load when Claude works with matching files, saving context.", ".claude/rules/ load every session OR when matching files are opened (path-scoped); can be scoped to file paths.", "Both CLAUDE.md and skills support @path imports to include other files.", "MCP: tool names load at session start; full JSON schemas stay deferred until a specific tool is needed. Tool search is ON by default so idle MCP tools consume minimal context.", "Run /mcp to see connection status and token costs per server; Claude Code auto-reconnects to remote MCP servers if they drop.", "Subagent loads: its own system prompt (not full Claude Code system prompt), full content of skills in its 'skills:' field, CLAUDE.md and git status — EXCEPT built-in Explore and Plan agents omit both CLAUDE.md and git status. Subagents do NOT inherit conversation history or invoked skills.", "Skills in a subagent's 'skills' field are FULLY PRELOADED at launch (not on-demand); subagents can still discover/invoke unlisted project, user, and plugin skills via the Skill tool.", "A skill can run in isolated context using 'context: fork' in frontmatter.", "Hooks fire on lifecycle events including PostToolUse, PreToolUse, SessionStart, prompt submission, permission requests, and compaction; a hook can run a shell command, HTTP request, LLM prompt, or subagent.", "Bundled skills that work out of the box include /code-review, /batch, and /debug.", "The LSP (code intelligence) tool is inactive until you install a code intelligence plugin for your language; it surfaces type errors/warnings after edits and symbol definitions/references on lookup.", "Context cost by feature: CLAUDE.md = full content every request; Skills = descriptions every request (full content when used); MCP = tool names at start, schemas on demand; Hooks = zero unless they return output; Subagents = isolated from main session.", "Agent teams are experimental and disabled by default; each teammate is a separate Claude instance (higher token cost) that messages peers directly and shares a task list.", "Managed policies are listed as one of the four levels at which features are defined, and 'managed' is the highest-priority tier in both skill (managed > user > project) and subagent precedence — implying enterprise/admin-managed config overrides user and project.", "Session conversation is written to a plaintext JSONL file per message/tool-use/result under ~/.claude/projects/, enabling rewind, resume, and fork.", "Each new session starts with a fresh context window and does NOT carry conversation history from previous sessions; persistence is via auto memory or CLAUDE.md.", "Auto memory loads the first 200 lines or 25KB of MEMORY.md (whichever comes first) at the start of each session.", "The context window holds: conversation history, file contents, command outputs, CLAUDE.md, auto memory, loaded skills, and system instructions.", "MCP tool definitions are deferred by default and loaded on demand via tool search; only tool names consume context until a specific tool is used.", "Run /context to see what is using context space; run /mcp to check per-server context costs.", "Auto-compaction clears older tool outputs first, then summarizes the conversation; user requests and key code snippets are preserved, but detailed early instructions may be lost.", "Control compaction via a 'Compact Instructions' section in CLAUDE.md, or run /compact with a focus, e.g. '/compact focus on the API changes'.", "If a single file/tool output is so large that context refills after each summary, Claude Code stops auto-compacting after a few attempts and shows a thrashing error instead of looping.", "Skills load on demand: skill descriptions are visible at session start, full content loads only when used. Set 'disable-model-invocation: true' to keep a manually-invoked skill's description out of context until needed.", "Use skillOverrides in settings to hide descriptions of skills you didn't write until needed.", "Subagents get their own fresh, isolated context separate from the main conversation and return only a summary; this prevents main-context bloat.", "Permissions can be scoped from organization-wide policies down to personal preferences; allow specific commands in .claude/settings.json so Claude does not re-ask (e.g. npm test, git status).", "Shift+Tab cycles permission modes: Default (asks before edits/commands), Auto-accept edits (runs filesystem commands like mkdir/mv without asking), Plan mode (explores/proposes without editing source; prompts still apply), Auto mode (background safety checks, research preview).", "Before any file edit, Claude snapshots file contents; press Esc twice to rewind. Checkpoints are local to the session, separate from git, and cover only file changes — not remote side effects (DBs, APIs, deployments).", "Switch models with /model during a session or start with 'claude --model <name>'. Sonnet handles most coding; Opus is for complex architectural reasoning.", "Resume with 'claude --continue' or 'claude --resume' reuses the same session ID and appends messages; fork with '--fork-session' or '/branch' copies history into a new session ID, leaving the original unchanged.", "The /resume picker shows sessions from the current worktree by default, with keyboard shortcuts to widen to other worktrees or projects.", "Sessions are tied to the current directory; run parallel sessions using git worktrees (separate directories per branch).", "Press Esc to stop Claude immediately (cancels the running tool call); type a correction and Enter to steer without stopping the running tool.", "Three execution environments: Local (your machine, default), Cloud (Anthropic-managed VMs, for offloading/repos not local), Remote Control (code runs on your machine, controlled from browser).", "Code intelligence (type errors, jump-to-definition, find references) requires code intelligence plugins.", "Setup commands: /init creates a project CLAUDE.md; /agents configures custom subagents; /doctor diagnoses installation issues.", "Claude Code loads every CLAUDE.md from the working directory and every parent directory at launch, then loads each subdirectory's CLAUDE.md on demand when it reads files there.", "Where you launch `claude` determines file access, which CLAUDE.md files load at startup, and which project settings apply. Starting from repo root: access to every file, root CLAUDE.md loaded (subdir files load on demand). Starting from a subdirectory: access to that subtree only until you grant more, and that directory's CLAUDE.md plus every ancestor's load.", "Project settings in `.claude/settings.json` load only from your starting directory and are NOT inherited from parent directories the way CLAUDE.md files are. A root `.claude/settings.json` applies only when you start from the root.", "`claudeMdExcludes` setting skips specific CLAUDE.md/rules files by path or glob so they never load. Patterns use glob syntax matched against absolute file paths; start relative-style patterns with `**/` to match anywhere. Example: `\"**/packages/admin-dashboard/**\"`.", "`claudeMdExcludes` is a static list, not a per-task switch. It can be set at any settings scope (user, project, local, managed). Arrays merge across scopes.", "Managed policy CLAUDE.md files CANNOT be excluded via `claudeMdExcludes` — organization-wide instructions always apply.", "Claude's content searches respect `.gitignore` by default, so `node_modules/`, `dist/`, `build/` stay out of search results without extra config.", "For checked-in generated/vendored code, add `Read` deny rules under `permissions.deny` in `.claude/settings.json`, e.g. `\"Read(./**/dist/**)\"`, `\"Read(./**/*.generated.*)\"`, `\"Read(./vendor/**)\"`.", "Read deny rules cover Claude's built-in file tools and recognized Bash file commands (cat, head, grep, find) when a denied path is passed as an argument. They do NOT filter denied paths out of a recursive search's output, and do NOT cover arbitrary subprocesses that open files.", "Deny rules set in managed settings cannot be overridden by user or project settings.", "Code intelligence plugins connect Claude to a language server (jump to definition, find references, type errors). Install e.g. `/plugin install typescript-lsp@claude-plugins-official`. Official marketplace has TypeScript, Python, Go, Rust, etc.", "To enable a plugin for everyone in the repo, add it to the `enabledPlugins` project setting rather than each developer installing it.", "Code intelligence plugins require the language's language server binary on each developer's machine. Installing from official marketplace requires network access to GitHub; on restricted networks add the marketplace from an internal Git host or local path.", "`--worktree` flag starts a session in a new git worktree. By default it checks out the entire repository; `worktree.sparsePaths` uses git sparse-checkout to write only listed directories plus root-level files.", "`worktree.sparsePaths` paths are relative to the repository root regardless of starting subdirectory. List directories, not individual files. Root-level files (package.json, tsconfig, lockfiles) are always checked out; root-level directories are NOT — include `.claude` explicitly to get root `.claude/settings.json`, rules, and skills inside the worktree.", "All worktrees in a session (including subagent worktrees) share the same `sparsePaths`. Pair `sparsePaths` with `worktree.symlinkDirectories` (e.g. `[\"node_modules\"]`) to symlink large dirs back to the main repo instead of duplicating.", "`sparsePaths` and `symlinkDirectories` are read from your starting directory BEFORE the worktree is created. After creation the working directory is the worktree root, so settings inside the worktree load from the worktree root's `.claude/settings.json` (the checked-out copy of the repo root file). Put permission rules/hooks needed in worktrees in the repo root's `.claude/settings.json`.", "`permissions.additionalDirectories` in `.claude/settings.json` grants read/write access to directories outside the working directory (e.g. `\"../shared\"`). Relative paths resolve against the directory you start Claude from.", "`--add-dir` flag (or `/add-dir` command) grants directory access at runtime without editing settings, e.g. `claude --add-dir ../shared`.", "Directories added via `additionalDirectories` setting: never load CLAUDE.md/rules, never load skills (file access only). Directories added via `--add-dir`/`/add-dir`: load skills always, and load CLAUDE.md/rules only if env var `CLAUDE_CODE_ADDITIONAL_DIRECTORIES_CLAUDE_MD=1` is set. That env var has no effect on `additionalDirectories` setting entries.", "Per-directory skills live under `.claude/skills/<name>/SKILL.md` inside the directory. They load on demand when Claude determines relevance; commit them alongside the area's code.", "Skill `paths:` frontmatter field takes glob patterns; Claude loads the skill only when working with matching files (e.g. a root skill scoped to `**/migrations/**`).", "Skills in scope depend on starting location: from a subdirectory = that directory + every parent to repo root + user + enterprise levels; from repo root = skills from every subdirectory Claude touches (can reach hundreds); via `--add-dir` = that sibling's skills load too. `additionalDirectories` setting grants file access only, not skills.", "Claude picks a skill by reading every discovered skill's name and description; only the chosen skill's full content loads. Skill descriptions are shortened when there are many, which can strip keywords. Names always load.", "Plugin skills use a `plugin-name:skill-name` namespace so they never collide with per-directory skills.", "To find unused skills, enable the OpenTelemetry logs exporter and set `OTEL_LOG_TOOL_DETAILS=1` so skill names are recorded verbatim. The `skill_activated` event records each invocation in `skill.name`; `invocation_trigger` records whether a command, Claude, or a nested skill invoked it.", "A `Stop` hook receives the path to the session transcript when Claude finishes; a script can review the session and propose CLAUDE.md updates.", "A `SessionStart` hook can print to stdout (added to Claude's context before the first prompt) to recommend the right plugin for the launch directory using a committed path-to-plugin map.", "Reference points to admin/org rollout: `/en/admin-setup` (org-wide baseline config), server-managed vs endpoint-managed settings at `/en/server-managed-settings`, and `/en/costs` for spend limits before a wider rollout.", "Prompt caching is automatic in Claude Code; the API caches by exact-prefix match (start of the request), with no per-file or per-segment caching — any change anywhere in the prefix recomputes everything after it.", "Request layers, ordered most-stable-first: (1) System prompt (core instructions, tool definitions, output style), (2) Project context (CLAUDE.md, auto memory, unscoped rules), (3) Conversation (messages, responses, tool results). A system-prompt change invalidates everything; a conversation change leaves layers 1-2 cached.", "Model and effort level are part of the cache key but are NOT in the prompt text. Each model has its own cache; each effort level has its own cache per model. Switching either mid-session recomputes the entire request.", "cache_read_input_tokens are billed at roughly 10% of the standard input rate; cache_creation_input_tokens are billed at the cache write rate. Check these via a statusline script reading the current_usage object.", "Actions that INVALIDATE the cache (one slow/expensive turn): switching models (/model), changing effort level (/effort), turning on fast mode, connecting/disconnecting an MCP server (when tools loaded into prefix), enabling/disabling a plugin that provides MCP servers (when non-deferred), denying an entire tool, compacting (/compact), upgrading Claude Code.", "opusplan model setting resolves to Opus in plan mode and Sonnet during execution, so each plan-mode toggle is a model switch that starts a fresh cache.", "Automatic model fallback on Fable 5 (safety classifier flags a request) is a model switch; the request re-runs on default Opus and continues there.", "Deferred MCP tools (default on supported models via tool search) only append content, so connecting/disconnecting/changing the tool list does NOT disturb the cache. Tools loaded into the prefix (Haiku models, Vertex AI, custom ANTHROPIC_BASE_URL gateway, alwaysLoad servers/tools, or threshold-based loading) DO invalidate on change.", "Editing MCP config does not itself change the cache; the new config takes effect only after restart (when the server connects/disconnects).", "Plugins: skills, commands, agents, hooks, LSP servers, monitors, and themes NEVER invalidate the cache (appended after conversation). Only a plugin that provides MCP servers can, following MCP-server rules. Plugin changes apply on /reload-plugins or new session, not at /plugin install|enable|disable.", "As of v2.1.163, if /reload-plugins would trigger a full cache re-read it shows a warning and does NOT apply; pass --force to apply anyway.", "A deny rule with a bare tool name (e.g. Bash, WebFetch), the Bash(*) form, or a tool-name glob like \"*\" removes the tool from context and invalidates the cache mid-session. Scoped deny rules like Bash(rm *) and all allow/ask rules leave the prefix intact. A glob matching only MCP tools (mcp__*) keeps the cache intact when matched tools are deferred.", "Compaction (/compact) replaces history with a summary, invalidating the conversation layer; system prompt is reused and project context reloaded from disk (cache-hits only if CLAUDE.md/memory unchanged since session start). The summarization request shares the prefix so it reads the existing cache; the post-compaction turn is short and not the slow part.", "Auto-update downloads new versions in background but applies on next launch, never mid-session. Set DISABLE_AUTOUPDATER=1 to control when upgrades apply.", "Resuming a session after an upgrade reprocesses the entire history with no cache hits (history now sits behind a different system prompt); cost scales with conversation length.", "Editing project-root and user-level CLAUDE.md mid-session does NOT invalidate cache but the edit ALSO does not apply — Claude keeps the version loaded at session start; new content loads on next /clear, /compact, or restart. Nested CLAUDE.md and paths:-frontmatter rules load lazily on first matching file read.", "Changing output style (via /config or outputStyle setting) mid-session does not invalidate cache and also does not apply until next /clear or restart (output style is part of the system prompt).", "Cache-safe actions (append or no-op): editing repo files, editing CLAUDE.md (no-op), changing output style (no-op), changing permission mode (except opusplan plan toggle), invoking skills/commands, /recap, /rewind, spawning a subagent.", "/rewind truncates back to an earlier already-cached prefix (cheaper than /compact which builds a new prefix). /recap appends a summary as command output and keeps the prefix intact (unlike /compact).", "Cache TTL: API offers 5-minute and 1-hour TTLs. Each cache hit resets the timer. The 1-hour TTL bills cache writes at a higher rate.", "On a Claude subscription, Claude Code requests the 1-hour TTL automatically at no extra cost; if over plan limit and drawing on usage credits, it drops to 5-minute TTL.", "On API key, Bedrock, Vertex, Foundry, or Claude Platform on AWS, default TTL is 5 minutes. Set ENABLE_PROMPT_CACHING_1H=1 to opt into the 1-hour TTL. Set FORCE_PROMPT_CACHING_5M=1 to force 5-minute regardless of auth (overrides ENABLE_PROMPT_CACHING_1H in managed settings).", "Cache is effectively scoped to one machine + directory: the system prompt embeds working directory, platform, shell, OS version, auto-memory paths, branch, and recent commits. Different directories (including worktrees of the same repo) miss each other's cache. Parallel sessions in the same directory share cache; sequential sessions share only if the git-status snapshot at startup matches.", "Subagents start their own conversation/system prompt/tool set and own cache (no hits on first call); they use the 5-minute TTL even on a subscription. The parent's cache is unaffected. A fork inherits the parent's prefix exactly and reads the parent's cache on its first request.", "Disable caching via env vars set to 1: DISABLE_PROMPT_CACHING (all), DISABLE_PROMPT_CACHING_HAIKU, DISABLE_PROMPT_CACHING_SONNET, DISABLE_PROMPT_CACHING_OPUS, DISABLE_PROMPT_CACHING_FABLE.", "To set caching policy org-wide, put the disable/TTL env vars in the env block of managed settings.", "Fast mode keep-header-across-toggles behavior (so off/on toggles and rate-limit fallbacks keep the cache) requires Claude Code v2.1.86+; earlier versions invalidate cache on every fast-mode toggle and rate-limit fallback. Fast mode's uncached cost applies once per conversation; /clear and /compact reset it.", "Toggling the advisor tool (/advisor) is an exception to MCP/tool rules: its definition sits after the cache breakpoint, so enabling/disabling it keeps the cached prefix intact.", "Editing a file Claude previously read does not retroactively change history; Claude Code appends a <system-reminder> noting the change and re-reads if needed.", "For visibility across an organization, the OpenTelemetry exporter reports cache read and creation tokens per user and session (see Monitor usage).", "For Agent SDK fleets, per-machine system-prompt sections can be suppressed to share cache across users/machines (see agent-sdk/modifying-system-prompts).", "`claude --continue` resumes the most recent session in the current directory.", "`claude --resume` (no arg) opens the interactive session picker; `claude --resume <name>` or `<session-id>` resumes directly.", "`claude --from-pr <number>` resumes the session linked to that pull request.", "`/resume` switches to a different conversation from inside an active session; `/resume <name>` resumes an exact match directly but errors on ambiguous names (use `/resume` with no arg for the picker).", "Sessions created with `claude -p` (headless) or the Agent SDK do NOT appear in the session picker, but can be resumed by passing the session ID to `claude --resume <session-id>`.", "Session ID lookup is scoped to the current project directory and its git worktrees; running from another directory reports `No conversation found with session ID: <session-id>`.", "Sessions are stored per project directory. Picker shows interactive sessions from the current worktree plus sessions that added the current dir via `/add-dir`.", "In the picker: `Ctrl+W` widens to all worktrees of the repository; `Ctrl+A` widens to every project on the machine; `Ctrl+B` filters to the current git branch; `Ctrl+R` renames; `Space`/`Ctrl+V` previews.", "Name a session: at startup `claude -n auth-refactor`; during a session `/rename auth-refactor`; from picker `Ctrl+R`. Accepting a plan in plan mode auto-names the session from plan content unless already named.", "Branch a session with `/branch [name]` (in-session) or `claude --continue --fork-session` / `claude --resume --fork-session` from CLI; original session is left intact.", "`/branch` prints two session IDs (new branch and original); permissions approved with 'allow for this session' do NOT carry over to the new branch.", "In-session context commands: `/clear` (empty context, previous conversation saved/resumable), `/compact [instructions]` (replace history with optionally-focused summary), `/context` (show what is consuming context).", "`/export` copies the current conversation to clipboard or, with a filename argument, writes it to a plain-text file with messages and tool outputs rendered as readable text.", "Transcripts are stored as JSONL at `~/.claude/projects/<project>/<session-id>.jsonl`, where `<project>` is derived from the working directory path; each line is a JSON object for a message, tool use, or metadata.", "Set `CLAUDE_CONFIG_DIR` to store sessions somewhere other than `~/.claude`.", "Local session files are removed after 30 days by default; change via the `cleanupPeriodDays` setting.", "Suppress transcript writes entirely with env var `CLAUDE_CODE_SKIP_PROMPT_HISTORY`, or in non-interactive mode use the `--no-session-persistence` flag.", "From v2.1.169, moving a session with `/cd` relocates it to the new directory's project storage so it appears in that directory's picker.", "Forked sessions (from `/branch`, `/rewind`, or `--fork-session`) are grouped under their root session in the picker; press `→` to expand.", "The desktop app, Claude Code on the web, and the VS Code extension each maintain their own separate session history from the CLI.", "In the picker search, pasting a GitHub, GitHub Enterprise, GitLab, or Bitbucket pull/merge request URL finds the session that created it.", "Ultraplan is in research preview and requires Claude Code v2.1.91 or later.", "Ultraplan hands a planning task from the local CLI to a Claude Code on the web session running in plan mode; Claude drafts the plan in the cloud while the terminal stays free.", "Ultraplan requires a Claude Code on the web account and a GitHub repository.", "Ultraplan is NOT available when using Amazon Bedrock, Google Cloud Vertex AI, or Microsoft Foundry, because it runs on Anthropic's cloud infrastructure.", "The cloud session runs in the account's default cloud environment; if none exists, ultraplan creates one automatically on first launch.", "Three launch methods: run `/ultraplan <prompt>`; include the keyword `ultraplan` anywhere in a normal prompt; or from a finished local plan choose 'No, refine with Ultraplan on Claude Code on the web' at the approval dialog.", "The command and keyword launch paths open a confirmation dialog first; the local-plan path skips the dialog because the menu selection serves as confirmation.", "If Remote Control is active, it disconnects when ultraplan starts, because both occupy the claude.ai/code interface and only one can be connected at a time.", "CLI status indicators: `◇ ultraplan` (researching/drafting), `◇ ultraplan needs your input` (clarifying question, open session link to respond), `◆ ultraplan ready` (plan ready to review in browser).", "`/tasks` then selecting the ultraplan entry opens a detail view with the session link, agent activity, and a 'Stop ultraplan' action; stopping archives the cloud session and clears the indicator with nothing saved to the terminal.", "Browser review view supports inline comments on highlighted passages, emoji reactions on sections, and an outline sidebar for navigation; iteration is unlimited before execution.", "Execution choice 'Approve Claude's plan and start coding' runs the implementation in the same web session; review the diff and create a PR from the web interface afterward.", "Execution choice 'Approve plan and teleport back to terminal' implements locally; it only appears when the session was launched from the CLI and the terminal is still polling, and it archives the web session to prevent parallel work.", "The 'Ultraplan approved' terminal dialog offers three options: 'Implement here' (inject plan into current conversation), 'Start new session' (clear conversation, keep only the plan as context), and 'Cancel' (save plan to a file and print the path without executing).", "Choosing 'Start new session' prints a `claude --resume` command at the top so the previous conversation can be returned to later.", "Ultrareview is invoked as `/code-review ultra`; `/ultrareview` remains as a deprecated alias.", "Ultrareview is a research preview feature available in Claude Code v2.1.86 and later.", "`/code-review ultra` with no args reviews the diff between the current branch and the default branch, including uncommitted and staged working-tree changes; Claude bundles repo state and uploads it to a remote sandbox.", "`/code-review ultra <PR-number>` (e.g. `/code-review ultra 1234`) reviews a GitHub PR; in PR mode the remote sandbox clones the PR from the host instead of bundling the local working tree.", "PR mode works with github.com and with GitHub Enterprise Server instances that an admin has connected to Claude Code.", "Ultrareview requires authentication with a Claude.ai account (runs on Claude Code on the web infra). If signed in with API key only, run `/login` and authenticate with Claude.ai first.", "Ultrareview is NOT available when using Amazon Bedrock, Google Cloud Vertex AI, or Microsoft Foundry, and NOT available to organizations with Zero Data Retention enabled.", "Free runs: Pro and Max each get 3 free ultrareview runs (one-time per account, do not refresh); Team and Enterprise get none.", "After free runs, each review bills as usage credits (NOT plan-included usage), typically $5-$20 depending on change size.", "A run counts (consumes a free run) once the cloud session starts; a review stopped early or that fails still uses a free run. For paid reviews, credits bill only for the portion that ran.", "Usage credits must be turned on at the account/org level before launching a paid review; if off, Claude Code blocks the launch. Check/change with `/usage-credits`.", "A review typically takes 5-10 minutes and runs as a background task; you can keep working, run other commands, or close the terminal.", "Use `/tasks` to see running/completed reviews, open detail view, or stop an in-progress review. Stopping archives the cloud session and returns no partial findings.", "Each verified finding includes file location and an explanation; you can ask Claude to fix it directly.", "Non-interactive CLI subcommand `claude ultrareview` runs the same review for CI/scripts; blocks until finished, prints findings to stdout, exits 0 on success / 1 on failure.", "`claude ultrareview` forms: no args (current branch vs default), `claude ultrareview 1234` (PR number), `claude ultrareview origin/main` (diff against a base branch).", "`claude ultrareview` flags: `--json` prints raw `bugs.json` payload instead of formatted findings; `--timeout <minutes>` max wait (default 30).", "`claude ultrareview` exit codes: 0 = completed (with or without findings), 1 = failed to launch/cloud session error/timeout elapsed, 130 = interrupted with Ctrl-C. Progress and live session URL go to stderr so stdout stays parseable.", "Interrupting the `claude ultrareview` subcommand does NOT stop the remote review; it keeps running and can be watched via the session URL printed to stderr.", "Invoking the `claude ultrareview` subcommand counts as consent for the billing and terms prompt that the interactive command shows.", "Ultrareview independently reproduces and verifies every reported finding, focusing results on real bugs rather than style suggestions; a larger parallel fleet of reviewer agents gives broader coverage than a medium-effort local review.", "Claude does NOT start an ultrareview on its own; it runs only when explicitly invoked with `/code-review ultra`. A pre-launch confirmation dialog shows review scope (file and line count for branch reviews), remaining free runs, and estimated cost.", "Dynamic workflows require Claude Code v2.1.154 or later.", "Dynamic workflows are available on all paid plans (Pro, Max, Team, Enterprise), with Anthropic API access, and on Amazon Bedrock, Google Cloud Vertex AI, and Microsoft Foundry. On Pro, they must be turned on via the 'Dynamic workflows' row in /config.", "A dynamic workflow is a JavaScript script that orchestrates subagents; Claude writes the script and a runtime executes it in the background while the session stays responsive.", "/deep-research <question> is a built-in/bundled workflow that fans out web searches, fetches and cross-checks sources, votes on each claim, and returns a cited report with claims that failed cross-checking filtered out. It requires the WebSearch tool to be available.", "Include the keyword 'ultracode' in a prompt to run a single task as a workflow without changing session effort. Natural language ('use a workflow', 'run a workflow') also opts in. Before v2.1.160 the literal trigger keyword was 'workflow'.", "Dismiss an unintended workflow keyword highlight with Option+W (macOS) or Alt+W (Windows/Linux), or backspace with cursor right after the highlighted keyword. Disable entirely via 'Ultracode keyword trigger' toggle in /config.", "/effort ultracode combines xhigh reasoning effort with automatic workflow orchestration; Claude plans a workflow for every substantive task. It lasts only the current session and resets on a new session. Drop back with /effort high. Only available on models supporting xhigh effort.", "Subagents spawned by a workflow always run in acceptEdits mode and inherit your tool allowlist, regardless of your session's permission mode. File edits are auto-approved.", "Permission mode controls only the launch prompt. Default/accept-edits modes prompt every run unless you select 'Yes, and don't ask again' for that workflow in that project. Auto mode prompts on first launch only (consent recorded in user settings), and is skipped entirely when ultracode is on. Bypass permissions, claude -p, and Agent SDK never prompt.", "Shell commands, web fetches, and MCP tools not in your allowlist can still prompt you mid-run; add needed commands to the allowlist before starting a long run to avoid interruptions.", "Save a workflow run's script as a command via /workflows then press 's'. Two save locations: .claude/workflows/ in the project (shared via repo) or ~/.claude/workflows/ in home (personal, all projects). Saved workflows run as /<name>.", "Precedence: if a project workflow and a personal workflow share a name, the project one runs. In a monorepo with multiple .claude/ dirs (as of v2.1.178), saving writes to the closest existing .claude/workflows/ between cwd and repo root (or repo root if none); workflows load from every .claude/workflows/ along that path, and when names collide the one closest to the working directory runs.", "Saved workflows accept input via the 'args' parameter, exposed in the script as a global named 'args' (structured data, callable as array/object directly). If omitted, args is undefined.", "Runtime limits: up to 16 concurrent agents (fewer on limited-CPU machines); 1,000 agents total per run; no mid-run user input (only agent permission prompts pause a run); the workflow script itself has no direct filesystem or shell access (agents do that, script coordinates).", "Every run writes its script to a file under the session directory in ~/.claude/projects/; the path is given to Claude at run start so you can read, diff, or edit and relaunch it.", "Resume works only within the same Claude Code session; completed agents return cached results. Exiting Claude Code while a workflow runs makes the next session start it fresh.", "Every workflow agent uses your session's model unless the script routes a stage to a different one. Check /model before a large run; ask Claude to use a smaller model for stages that don't need the strongest.", "Disable workflows for yourself: toggle 'Dynamic workflows' off in /config; or set \"disableWorkflows\": true in ~/.claude/settings.json; or set env var CLAUDE_CODE_DISABLE_WORKFLOWS=1 (read at startup).", "Disable workflows org-wide: set \"disableWorkflows\": true in managed settings (server-managed-settings), or use the toggle on the Claude Code admin settings page (claude.ai/admin-settings/claude-code).", "/workflows lists running and completed runs; progress view shows each phase with agent count, token total, and elapsed time. Footer keys: arrows select, Enter/right drill in, Esc back out, j/k scroll, f filter by status (v2.1.186+), p pause/resume, x stop agent or whole run, r restart agent, s save.", "At the per-run approval prompt: Ctrl+G opens the script in your editor; Tab lets you adjust the prompt before the run starts.", "Workflows are available in the CLI, Desktop app, IDE extensions, non-interactive mode (claude -p), and the Agent SDK; the same disable settings apply on every surface."]}, "Permissions, security & governance": {"pages": ["auto-mode-config", "data-usage", "legal-and-compliance", "network-config", "permission-modes", "permissions", "sandbox-environments", "sandboxing", "security", "security-guidance", "server-managed-settings", "zero-data-retention"], "bestPractices": ["For most orgs, autoMode.environment is the only field you need to set; populate it with your source-control orgs, trusted cloud buckets, internal domains, and key internal services as prose.", "Roll out incrementally: start from $defaults, add your source-control org and key internal services first (resolves most false positives like pushing to your own repos), then trusted domains and buckets, then fill the rest as blocks come up.", "Always include \"$defaults\" in any autoMode array unless you deliberately intend to own the whole list; this keeps force-push/curl|bash/prod-deploy soft blocks and exfiltration hard blocks intact and inherits future updates.", "Distribute organization-wide trusted infrastructure via Managed settings; developers can extend but not remove managed entries.", "For absolute, non-overridable boundaries use permissions.deny in managed settings rather than autoMode.hard_deny, since the classifier is only a second gate and allow rules are additive.", "Put behavioral rules like 'never force push' in project CLAUDE.md to steer both Claude and the classifier with one edit.", "After saving settings, run 'claude auto-mode config' to confirm the effective rules; run 'claude auto-mode critique' on custom rules to catch ambiguity/redundancy/false positives.", "To rewrite or remove a built-in rule (not just add), save 'claude auto-mode defaults' to a file, edit the lists, and paste the result in place of \"$defaults\".", "When repeated denials hit the same destination, add that destination to autoMode.environment, then re-run 'claude auto-mode config' to verify.", "For team/org deployments, standardize on Team/Enterprise/API (commercial) accounts so prompts and code are not used for model training by default; never let devs use personal Free/Pro/Max accounts for company code.", "Set telemetry/feedback opt-out env vars in a managed settings.json so they apply org-wide: DISABLE_TELEMETRY, DISABLE_ERROR_REPORTING, DISABLE_FEEDBACK_COMMAND=1, CLAUDE_CODE_DISABLE_FEEDBACK_SURVEY=1 — or use the single CLAUDE_CODE_DISABLE_NONESSENTIAL_TRAFFIC switch.", "If using Bedrock/Vertex/Foundry, telemetry/errors/feedback are already off by default; you still must explicitly set CLAUDE_CODE_DISABLE_FEEDBACK_SURVEY=1 to stop session surveys.", "For maximum confidentiality on Enterprise, request Zero Data Retention via your account team (it is opt-in, per-org, and not part of the standard Enterprise plan).", "Govern the local plaintext transcript cache: tune cleanupPeriodDays and treat ~/.claude/projects/ as sensitive on shared/developer machines.", "If your network blocks api.anthropic.com, either allowlist it or set skipWebFetchPreflight: true; when disabling the preflight, pair it with WebFetch permission rules to restrict reachable domains.", "To keep survey signal without sending anything to Anthropic, set CLAUDE_CODE_ENABLE_FEEDBACK_SURVEY_FOR_OTEL=1 and capture ratings via your own OpenTelemetry collector.", "For teams handling PHI/healthcare data, enable Zero Data Retention (ZDR) per organization AND execute a BAA — both are required for BAA coverage of Claude Code.", "If your team runs Claude Code via Amazon Bedrock or Google Vertex, your existing commercial agreement already covers it — no separate Claude Code agreement needed unless mutually agreed.", "Provision developers/agents building automated services (Agent SDK) with API keys via Claude Console or a cloud provider, not subscription OAuth logins, to stay within Anthropic's authentication policy.", "Keep automated/programmatic Claude Code usage on Team/Enterprise/API plans rather than Pro/Max, since Pro/Max limits assume ordinary individual usage.", "Prefer HTTPS_PROXY over HTTP_PROXY for corporate proxy routing; set NO_PROXY for internal hosts (e.g. localhost and internal domains).", "For TLS-inspection proxies (Zscaler, CrowdStrike Falcon), install the root cert in the OS trust store rather than configuring Claude Code — the default bundled,system cert store picks it up automatically.", "For a custom enterprise CA, point NODE_EXTRA_CA_CERTS at the CA .pem instead of disabling TLS verification.", "Configure network env vars centrally via the `env` block in ~/.claude/settings.json so team members get consistent proxy/CA/mTLS setup; remember CLAUDE_CODE_CERT_STORE has no schema key and must go in `env` or the process environment.", "When building the firewall/proxy allowlist, include api.anthropic.com, claude.ai, platform.claude.com, downloads.claude.ai, storage.googleapis.com, bridge.claudeusercontent.com, *.claudeusercontent.com, and raw.githubusercontent.com (drop the two download domains if you self-distribute the binary via npm).", "Disable operational telemetry via env vars first if you want a minimal allowlist, then finalize firewall rules.", "On Bedrock/Vertex/Foundry, still allow api.anthropic.com OR set skipWebFetchPreflight: true so the WebFetch domain safety check doesn't break.", "For GitHub Enterprise Cloud IP restrictions, enable IP allow list inheritance for installed GitHub Apps so the Claude GitHub App's registered IP ranges are honored automatically; for self-hosted GHES behind a firewall, allowlist Anthropic API IP ranges.", "Avoid hardcoding proxy passwords in scripts; use env vars or secure credential storage; for NTLM/Kerberos proxies route through an LLM Gateway.", "For team governance, control auto/bypass at the org level via managed settings: set permissions.disableAutoMode and/or permissions.disableBypassPermissionsMode to \"disable\" to lock them off across all developers.", "Put `defaultMode: \"auto\"` in ~/.claude/settings.json (user) or managed settings, never in repo .claude/settings.json — repo-level auto is ignored by v2.1.142+ by design.", "Use `plan` as a project default (defaultMode: \"plan\" in .claude/settings.json) for codebases where you want exploration before any edits.", "Use `dontAsk` mode for CI pipelines: pre-define exactly what Claude may do via permissions.allow; everything else is denied non-interactively.", "Restrict bypassPermissions to isolated containers/VMs/dev containers without internet; prefer auto mode for fewer prompts with safety checks on a real host.", "For a hard, persistent guarantee in auto mode (e.g. 'never push'), add a deny rule rather than stating a boundary in conversation — conversational boundaries are re-read from the transcript each check and can be lost to context compaction.", "To reduce auto-mode false-positive blocks for your team, have an admin configure trusted repos/buckets/services via the autoMode.environment managed setting instead of letting developers loosen rules.", "Do not rely on Edit(.claude/**) allow rules to let Claude edit its own config — protected-path checks run first; instead approve via the in-session 'allow Claude to edit its own settings' prompt option.", "Distribute team permissions by checking .claude/settings.json into version control (shared project settings); keep developer-specific overrides in .claude/settings.local.json (gitignored).", "For org-wide governance, deploy managed settings (MDM/OS policy/server-managed) — they sit at the top of precedence and cannot be overridden, even by CLI args. Put hard constraints (disableBypassPermissionsMode, deny rules) here.", "To enforce that ONLY central policy applies, set allowManagedPermissionRulesOnly:true (rules), allowManagedMcpServersOnly:true (MCP), allowManagedHooksOnly:true (hooks), strictPluginOnlyCustomization:true (skills/agents/hooks/MCP) in managed settings.", "For reliable URL/network filtering, deny Bash network tools (curl, wget) and grant WebFetch(domain:...) allow rules — do NOT try to constrain curl arguments with Bash patterns (fragile to flags, protocol, redirects, variables, spaces).", "To run most Bash without prompts but block a few commands: add 'Bash' to allow and register a PreToolUse hook (exit code 2) that rejects the specific dangerous commands — more robust than allow/deny pattern lists.", "Use the sandbox alongside permission rules for defense-in-depth: deny rules stop Claude from attempting access, sandbox stops Bash child processes even if a prompt injection bypasses the model's decision.", "Write Bash allow rules with a trailing space before * (Bash(ls *)) to enforce word boundaries and avoid accidentally matching prefixes like 'lsof'.", "When approving work inside environment runners (devbox run, npx, docker exec, mise exec — NOT stripped as wrappers), write specific rules including both runner and inner command (e.g. Bash(devbox run npm test)), one per inner command — never Bash(devbox run *).", "Use //path for true absolute paths in Read/Edit rules; remember /path is project-root-relative, a common footgun.", "Use Agent(AgentName) deny rules or --disallowedTools to control which subagents are available to the team.", "Use /permissions to inspect which settings file each rule comes from when debugging precedence issues.", "Use canonical tool names (from the tools reference) in rules and hook matchers, not the transcript labels (e.g. TaskStop not 'Stop Task').", "Always run --dangerously-skip-permissions inside a full-process isolation boundary (container, VM, or sandbox runtime) so file tools, MCP servers, and hooks are also constrained — the Bash sandbox alone is insufficient for unattended runs.", "To isolate MCP servers and hooks (not just Bash) without Docker, use the sandbox runtime: configure ~/.srt-settings.json to allow writes to the project dir plus ~/.claude and ~/.claude.json and the needed network domains (api.anthropic.com or provider), then run `npx @anthropic-ai/sandbox-runtime claude`.", "For a team, commit the example dev container (.devcontainer/ with default-deny iptables firewall) into repos to standardize a sandboxed environment, and pin the Claude Code version and firewall allowlist.", "To require isolation org-wide, only the built-in Bash sandbox is enforceable by Claude Code itself — deploy `sandbox` settings keys via managed settings / server-managed settings; for containers/VMs enforce installation via MDM/software allowlisting.", "Use a dedicated VM (or Claude Code on the web) when working on untrusted repositories; use the sandbox runtime when you want MCP/hook isolation without Docker; use the Bash sandbox only to reduce permission prompts in everyday trusted work.", "Layer the built-in Bash sandbox inside a container for OS-level command restrictions on top of the outer boundary (enable the nested-sandbox setting in unprivileged containers).", "For managed/org deployments that require the sandbox as a security gate, set sandbox.failIfUnavailable=true so a missing bubblewrap/socat blocks startup instead of silently falling back to unsandboxed execution.", "Add credential directories (~/.aws, ~/.ssh) to sandbox.filesystem.denyRead — the default read policy allows reading them, which combined with network access enables exfiltration.", "Prefer granting narrow write paths via sandbox.filesystem.allowWrite (e.g. ~/.kube, /tmp/build) over excluding whole tools with excludedCommands, since allowWrite is OS-enforced for all child processes.", "Keep allowedDomains narrow and avoid broad entries like github.com — the proxy doesn't inspect TLS, so broad domains permit data exfiltration / domain fronting. Use a custom TLS-terminating proxy (httpProxyPort/socksProxyPort) if the threat model demands it.", "To lock down an org: combine sandbox.enabled=true, failIfUnavailable=true, allowUnsandboxedCommands=false, allowManagedReadPathsOnly=true, allowManagedDomainsOnly=true, and a narrow excludedCommands list (knowing excludedCommands can still be widened by developers).", "Set CLAUDE_CODE_SUBPROCESS_ENV_SCRUB to strip Anthropic and cloud credentials from sandboxed subprocess environments, since subprocesses inherit the parent env by default.", "For tools incompatible with the sandbox, add them to excludedCommands: docker (`docker *`), and on macOS Go-based CLIs (gh, gcloud, terraform) that fail TLS under Seatbelt. Run jest with --no-watchman (watchman is sandbox-incompatible).", "On WSL2, add Windows binaries (cmd.exe, powershell.exe, anything under /mnt/c/) to excludedCommands since the sandbox blocks the Unix-socket handoff to the Windows host.", "Use enableWeakerNestedSandbox=true only when running inside an unprivileged container that already provides isolation (bubblewrap can't mount fresh /proc there); it weakens security by exposing process info.", "Put denyRead/allowRead configs with relative `.` paths in project .claude/settings.json (where `.` resolves to project root) — in ~/.claude/settings.json `.` resolves to ~/.claude instead and won't cover project files.", "Use managed settings (/en/settings) to enforce organizational standards that individual users cannot override.", "Share approved permission configurations through version control so the whole team inherits the same allowlist/denylist.", "Configure ConfigChange hooks to audit or block settings changes made during sessions.", "Monitor team Claude Code usage via OpenTelemetry metrics (/en/monitoring-usage) for audit.", "For sensitive repos, use project-specific permission settings and regularly audit with /permissions.", "To hard-block web-fetching commands across a team, add curl/wget to permissions.deny rather than relying on the default prompt.", "Run scripts and tool calls that touch external web services inside VMs or dev containers (/en/devcontainer) for isolation.", "Avoid piping untrusted content directly to Claude; review suggested commands and changes to critical files before approval.", "Start Claude Code from a project subdirectory rather than the home directory so directory trust persists and the trust prompt is not re-shown every launch.", "Use /sandbox to define filesystem/network boundaries where Claude can work autonomously, cutting prompt fatigue without losing isolation.", "On Windows, do not enable WebDAV or grant access to \\\\* paths, since this can bypass the permission system.", "For team-wide enforcement, check the plugin into the repo via .claude/settings.json enabledPlugins rather than relying on each member's user-scoped install — user scope does not propagate to teammates or to Claude Code on the web.", "Use admin managed settings enabledPlugins to enforce the plugin org-wide and prevent individual opt-out (only an admin can then disable).", "Distribute org-wide custom rules by pushing ~/.claude/claude-security-guidance.md and ~/.claude/security-patterns.yaml to user scope via device management (MDM).", "Prefer .claude/security-patterns.json over .yaml for portability — JSON parses on any Python install while YAML silently no-ops without PyYAML.", "Encode repo-specific threat-model rules (e.g. required auth guards on routes, fields that must not be logged, constant-time comparisons) in .claude/claude-security-guidance.md so the model reviewer enforces them.", "Treat the plugin as one layer of defense in depth — it never blocks writes/commits and the review model can miss issues; pair it with /security-review, PR Code Review, and CI scanners.", "For HARD enforcement of a protected-file or vulnerability policy, use a PreToolUse hook that blocks the edit or a CI gate — the plugin's guidance rules are advisory and cannot block.", "Be aware commits made from your own shell or the `!` shell escape bypass the commit review entirely; route security-sensitive commits through Claude's Bash tool if you want them reviewed.", "Reduce cost by disabling specific layers via env vars (e.g. ENABLE_COMMIT_REVIEW=0) rather than the whole plugin; the per-edit pattern layer is free.", "Keep model-review guidance under the 8 KB combined cap and custom patterns under 50 rules / 1 KB reminders, or content past the limits is dropped.", "Use server-managed settings when the org lacks MDM; prefer endpoint-managed settings on MDM-enrolled devices for OS-level protection of the policy file.", "Enforce permission policy centrally via permissions.deny + permissions.disableBypassPermissionsMode: \"disable\" + allowManagedPermissionRulesOnly: true to prevent users bypassing or adding their own rules.", "Set forceRemoteSettingsRefresh: true to eliminate the brief unenforced startup window, but first confirm network connectivity to api.anthropic.com or users will be unable to start the CLI.", "Validate any managed-settings payload change with `claude doctor` on a test machine before rolling out to the whole org.", "Restrict managed-settings admin access to trusted Primary Owner/Owner personnel since changes hit every user.", "Use ConfigChange hooks to detect/block runtime configuration tampering, especially on unmanaged devices where users have sudo/admin.", "Distribute MCP allow/deny policy via the managed-mcp.json file (allowedMcpServers/deniedMcpServers), not server-managed settings.", "Have users run /permissions and /status to confirm managed rules and the active managed source after deployment; debug delivery with `claude --debug-file <path>` searching for 'Remote settings'.", "If your team requires ZDR, plan procurement on Claude for Enterprise and engage the Anthropic account team early — it cannot be toggled in admin settings and requires eligibility review.", "When creating a new organization under an existing ZDR account, explicitly request ZDR enablement for that org — do not assume it inherits.", "Do not rely on ZDR to cover MCP servers or third-party integrations; vet each external tool's own data handling separately, since ZDR explicitly excludes them.", "For ZDR teams, avoid workflows that depend on Claude Code on the Web, Desktop cloud sessions, Artifacts, or /feedback — they are backend-disabled and will error.", "If a deterministic model is needed for a ZDR team, account for the 'best' alias resolving to Opus (not Fable 5) and pin models explicitly via /model where reproducibility matters."], "gotchas": ["Checked-in .claude/settings.json (shared project settings) is ignored by the classifier for autoMode rules — a repo cannot inject allow rules; only ~/.claude/settings.json, .claude/settings.local.json, managed settings, and --settings/SDK inline JSON are read.", "Omitting \"$defaults\" silently replaces the entire default list for that section: a soft_deny without it drops built-in force-push/curl|bash/prod-deploy blocks; a hard_deny without it drops built-in data-exfiltration and auto-mode-bypass blocks.", "autoMode.soft_deny is not a hard policy boundary: a developer-added allow entry can override an org-set soft_deny because rules are additive — use permissions.deny for true enforcement.", "hard_deny/allow/soft_deny entries are natural-language prose, not regex or tool-match patterns; tool-pattern-based hard blocks belong in permissions.deny instead.", "On Bedrock/Vertex/Foundry auto mode is unavailable until CLAUDE_CODE_ENABLE_AUTO_MODE is set; it is not on by default there.", "Only specific, direct user intent clears a soft_deny — broad instructions ('clean up the repo') do not authorize the destructive subaction.", "The WebFetch domain safety check is NOT disabled by CLAUDE_CODE_DISABLE_NONESSENTIAL_TRAFFIC and runs on every provider including Bedrock/Vertex; blocking api.anthropic.com silently breaks all WebFetch until allowlisted or skipWebFetchPreflight is set.", "Session quality surveys and the WebFetch check run even on Bedrock/Vertex/Foundry/Claude Platform on AWS where telemetry/errors/feedback are off by default — so 'using Bedrock' does not silence everything.", "The transcript-share follow-up uploads source code and file contents AS-IS (only API key/token patterns are redacted) — a real data-exfiltration surface if a dev clicks 'Yes'; suppressed only by ZDR, org policy, or CLAUDE_CODE_DISABLE_NONESSENTIAL_TRAFFIC.", "Local session transcripts sit in PLAINTEXT under ~/.claude/projects/ for 30 days by default regardless of account type or ZDR.", "/feedback can include other sessions from the same project over the last 24h or 7d (not just the current session) and can create a GitHub issue in a PUBLIC repo.", "Development Partner Program (training opt-in) is first-party Anthropic API only — not available to Bedrock or Vertex users.", "ZDR is NOT included in the standard Enterprise plan; assuming Enterprise = no retention is wrong — it must be separately enabled per-org by the account team.", "Disabling skipWebFetchPreflight means WebFetch will attempt ANY URL without consulting the blocklist — combine with permission rules or you lose that safety layer.", "v2.1.126 behavior change: with CLAUDE_CODE_PROVIDER_MANAGED_BY_HOST set, metrics default ON for Vertex/Bedrock/Foundry (opt out via DISABLE_TELEMETRY) — a reversal of the usual provider default-off.", "A BAA does NOT automatically cover Claude Code on its own — ZDR must also be activated per organization, or healthcare data handling is not covered.", "ZDR must be enabled separately for each organization; enabling it for one org does not cover others under the same customer.", "Routing Claude Code requests through Free/Pro/Max OAuth credentials on behalf of other users (or offering Claude.ai login in a third-party product) is prohibited and can be enforced without prior notice.", "Pro/Max advertised usage limits assume ordinary individual use; heavy team/automated usage on these plans may run afoul of policy.", "SOCKS proxies are unsupported — only HTTP/HTTPS proxies work.", "CLAUDE_CODE_CERT_STORE has no settings.json schema key; putting it under a normal settings key won't work — it must be in the `env` block or the process environment.", "WebFetch still hits api.anthropic.com for a domain safety preflight even on Bedrock/Vertex/Foundry; a restrictive allowlist will break WebFetch unless you allow that domain or set skipWebFetchPreflight: true.", "Proxy basic auth puts credentials in the URL (HTTPS_PROXY=http://user:pass@host:port), which risks leaking secrets in scripts/logs.", "Telemetry is sent by default, so a naive allowlist build can either leak telemetry or silently fail telemetry endpoints unless you explicitly disable it.", "storage.googleapis.com requirement is version-dependent (only versions before 2.1.116), so allowlists may differ across client versions.", "*.claudeusercontent.com / bridge.claudeusercontent.com are needed by the browser (Chrome extension / artifact viewer), not the CLI — easy to misattribute when debugging CLI network failures.", "`permissions.allow` rules do NOT override protected-path protection, because the protected-path check runs before allow-rule evaluation — a subtle precedence trap.", "`defaultMode: \"auto\"` set in .claude/settings.json or .claude/settings.local.json is silently ignored (v2.1.142+); the session starts in default with no error, making it look broken.", "On Bedrock/Vertex/Foundry, even with defaultMode: auto, auto mode is ignored unless CLAUDE_CODE_ENABLE_AUTO_MODE=1 is also set.", "Claude Code on the web silently ignores defaultMode bypassPermissions/dontAsk from checked-in settings — your repo config won't take effect in cloud sessions.", "Subagent frontmatter `permissionMode` is ignored under auto mode — you cannot loosen permissions per-subagent.", "Entering auto mode silently drops broad allow rules (Bash(*), Bash(python*), Agent rules), so a workflow relying on them may suddenly hit the classifier; rules are restored only on leaving auto.", "Auto-mode conversational boundaries (e.g. 'don't deploy') are not stored as rules and can be lost if context compaction removes the message that stated them.", "Auto mode unavailability after meeting v/model/plan requirements is permanent (a config issue), but a 'cannot determine the safety' message is a transient classifier outage — different failure classes.", "Auto mode classifier calls add latency (extra round-trip before shell/network actions) and count toward token usage, on a model independent of your /model choice.", "bypassPermissions cannot be toggled on mid-session; you must restart with an enabling flag — and it refuses to run as root/sudo on Linux/macOS outside a sandbox.", "Deny rules cannot carry allowlist exceptions: a broad deny always wins over a narrower allow regardless of specificity.", "additionalDirectories in a settings file grants file access ONLY — it does NOT load skills, agents, hooks, or CLAUDE.md from that directory. Only --add-dir/ /add-dir load (some) config.", "Bash(command:rm *) and similar param-syntax rules on canonicalized fields are silently ignored (with startup warning) because they'd be bypassable — use Bash(rm *).", "Process wrappers timeout/time/nice/nohup/stdbuf/xargs are stripped, but devbox run / npx / docker exec / mise exec / direnv exec are NOT — Bash(devbox run *) effectively allows arbitrary commands after 'run'.", "Read/Edit deny rules do NOT block Python/Node scripts (or any subprocess) that open files themselves — only built-in file tools and recognized Bash file commands (cat/head/tail/sed). Use the sandbox for OS-level enforcement.", "/path in Read/Edit rules is relative to project root, not the filesystem root — /Users/alice/file does not mean the absolute path; use //Users/alice/file.", "bypassPermissions still writes to sensitive dirs (.git, .claude, .ssh-adjacent config dirs) without prompting — only use in isolated containers/VMs.", "WebFetch(domain:*.example.com) does not match example.com itself (only subdomains).", "WebFetch permission does not prevent network access while Bash is allowed — Claude can curl/wget any URL.", "Bash 'don't ask again' for files persists per-project-and-command permanently, but file-modification 'don't ask again' only lasts until session end — different durability.", "Unanchored allow tool-name globs ('*', 'B*', 'mcp__*') are silently skipped with a warning and auto-approve nothing; only mcp__<server>__ prefixed globs work in allow rules.", "A hook returning 'allow' does not override a matching deny or ask rule; deny-first precedence still applies, so hooks cannot loosen managed deny rules.", "Compound-command approval saves up to 5 separate per-subcommand rules — approving one compound can silently allowlist multiple commands for the future.", "cd combined with git in a single compound command always prompts, even for read-only git and an in-cwd target.", "Tool rules using transcript labels (e.g. 'Stop Task') silently fail to match — must use canonical name (TaskStop).", "The Bash sandbox is a common false sense of security: it constrains ONLY Bash commands — MCP servers and hooks run unconstrained on the host, so it is not sufficient for fully unattended runs in either permission mode.", "Sandbox isolation does not change what is sent to the model: prompts and files Claude reads are still transmitted to the API/provider regardless of sandbox.", "Any sandbox allowing network egress can still leak data the agent can read; any sandbox mounting the project writable can still modify code — isolation reduces impact, not risk.", "The sandbox runtime is a beta research preview and its configuration format may change.", "The sandbox runtime denies all writes and network by default — forgetting to allowlist ~/.claude, ~/.claude.json, or the API endpoint will break the session.", "Dev containers / custom containers / VMs are conventions, not enforcement — developers can still run Claude Code outside them unless blocked by org device management.", "The Bash sandbox does not support native Windows (WSL2 or container/VM required).", "DEFAULT FAILURE-OPEN: if the sandbox can't start (missing deps or unsupported platform), Claude Code warns and runs commands UNSANDBOXED unless failIfUnavailable=true.", "Default read policy allows reading ~/.aws/credentials and ~/.ssh/ — sandboxing does NOT protect credentials unless you add denyRead entries.", "A bare `Bash` / `Bash(*)` ask rule is silently SKIPPED for sandboxed commands in auto-allow mode (still applies to fallback commands).", "In auto-allow mode, Bash commands modifying files run without prompting even when NOT in accept-edits mode, bypassing the approval that file-edit tools would normally require.", "excludedCommands cannot be locked down by managed settings — developers can always append entries to widen the unsandboxed surface.", "Sandbox filesystem path syntax (`/`=absolute, no-prefix=project-relative) differs from Read/Edit permission-rule syntax (`//`=absolute, `/`=project-relative) — easy to misconfigure.", "`.` relative paths resolve to project root only in project settings; in ~/.claude/settings.json they resolve to ~/.claude, so a denyRead ~/ + allowRead . placed in user settings leaves project files blocked.", "Sandboxed vs unsandboxed commands resolve $TMPDIR to DIFFERENT directories, so temp files don't transfer between them — write to the working directory instead.", "allowAppleEvents=true (macOS) removes code-execution isolation (sandboxed commands can launch apps unsandboxed and send AppleScript); it is ignored from project settings — only user/managed/CLI.", "allowUnixSockets exposing /var/run/docker.sock effectively grants host access; allowWrite to $PATH dirs or shell rc files enables privilege escalation.", "docker and watchman (jest) are sandbox-incompatible; macOS Go CLIs (gh/gcloud/terraform) may fail TLS under Seatbelt.", "On WSL2, sandboxed commands cannot launch Windows binaries (cmd.exe/powershell.exe//mnt/c/) because the Unix-socket handoff is blocked.", "enableWeakerNestedSandbox considerably weakens security (exposes /proc) and should only be used when an outer container already enforces isolation.", "Subagents share the parent's sandbox config (no independent boundary).", "Trust verification is bypassed entirely under -p (non-interactive) mode — automation/CI loses the trust prompt safeguard.", "Running in the home directory never persists trust acceptance (session-only, no setting to change it); the prompt reappears every launch — start from a subdirectory instead.", "Claude Code can READ files outside the working directory even though it cannot write there — the security boundary is write-only, not read confinement.", "Accept Edits mode silently auto-approves destructive filesystem commands (rm, mv, cp) within the working directory — out-of-scope paths still prompt, but in-scope deletions do not.", "MCP servers are NOT security-audited or managed by Anthropic even if listed in the Anthropic Directory — trust is the user's responsibility.", "Windows WebDAV / \\\\* paths can let Claude Code trigger remote network requests that bypass the permission system entirely.", "Protections reduce but do not eliminate prompt-injection risk; no system is fully immune — human review of commands/changes is still required.", "Remote Control is materially different from cloud execution: it runs locally with no VM/sandbox isolation, so local file access and execution are unrestricted by cloud controls.", "User-scoped plugin installs do NOT propagate to Claude Code on the web or to teammates cloning the repo — only checked-in .claude/settings.json or managed settings does.", "YAML pattern files are silently ignored if PyYAML is not importable (plugin never installs PyYAML); no error in conversation — check ~/.claude/security/log.txt.", "Commits/pushes you run from your own shell or via the `!` shell escape are NOT reviewed — only commits Claude makes through its Bash tool.", "Model-backed reviews skip silently if the directory is not a git repo or the session has no Anthropic authentication; only the free per-edit pattern check runs.", "None of the layers block writes or commits — findings are advisory instructions to Claude and the review model can miss issues; not a complete security solution.", "Guidance that tells the reviewer to ignore a vulnerability class does not suppress those findings — extension files are additive only.", "On Windows the venv bootstrap is skipped, so the agentic commit review only runs if claude-agent-sdk is already importable, otherwise it silently falls back to single-shot.", "Limits truncate silently: guidance file combined cap 8 KB, max 50 custom rules, reminder text capped at 1 KB, 30 changed files per end-of-turn review, end-of-turn fires at most 3x in a row, commit review capped at 20/rolling hour.", "Globs in security-patterns paths match the full file path — project-relative patterns must be prefixed with **/ or they will not match.", "Sources do not merge: if server-managed delivers ANY keys, endpoint-managed (plist/registry) is ignored entirely — clearing server config to fall back is delayed by cached settings until the next successful fetch.", "Non-interactive mode with -p SKIPS security approval dialogs and applies shell/env/hook settings without user approval.", "Server-managed settings are a client-side control: on unmanaged devices, users with admin/sudo can modify the binary, filesystem, or network to evade them.", "Using any third-party model provider (Bedrock/Vertex/Foundry/Mantle or non-default ANTHROPIC_BASE_URL) BYPASSES server-managed settings entirely.", "First launch without cached settings has a brief window where restrictions are not yet enforced (fetch is async); deleting the cache file reproduces this window.", "Per-group/per-user configuration is not supported — one config applies to all org users.", "policyHelper and wslInheritsWindowsSettings are silently not honored in server-managed settings (must go through MDM/system managed-settings.json).", "OpenTelemetry and other advanced settings require a full restart to take effect, unlike most settings that apply live.", "Tampered cached settings file still applies at startup until the next server fetch restores correct settings.", "ZDR does not auto-apply to newly created organizations under the same account — a silent coverage gap unless each org is enabled separately.", "ZDR cannot be enabled from admin/self-serve settings; it is Anthropic-side only and requires sales/account-team involvement.", "ZDR does NOT cover Claude Code Analytics metadata, seat/user management data, or third-party/MCP integrations — those still retain data under standard policies.", "Policy-violation-flagged sessions can be retained up to 2 years even under ZDR.", "Fable 5 is silently unavailable under ZDR; the 'best' alias quietly resolves to Opus instead, which can change model behavior without an obvious notice.", "ZDR applies only to Anthropic's direct platform — Bedrock/Vertex/Foundry deployments are governed by those clouds' retention policies, not Anthropic ZDR."], "claims": ["Auto mode runs Claude Code without routine permission prompts by routing tool calls through a classifier that blocks anything irreversible, destructive, or aimed outside your environment.", "Deny and explicit ask rules from the permissions system are evaluated BEFORE the classifier and still block or prompt.", "By default the classifier trusts only the working directory and the current repo's configured remotes; pushing to a company source-control org or writing to a team cloud bucket is blocked until added to autoMode.environment.", "Auto mode is available to all users on the Anthropic API. On Amazon Bedrock, Google Cloud Vertex AI, and Microsoft Foundry you must first set env var CLAUDE_CODE_ENABLE_AUTO_MODE.", "Admin enablement of auto mode applies on Team and Enterprise plans (see permission-modes requirements).", "The classifier reads the same CLAUDE.md content Claude loads, so an instruction like 'never force push' in project CLAUDE.md steers both Claude and the classifier.", "The classifier reads the autoMode block from these scopes: ~/.claude/settings.json (one developer), .claude/settings.local.json (one project/one developer), Managed settings (organization-wide), and inline JSON via --settings flag or Agent SDK (per-invocation).", "The classifier does NOT read autoMode from shared project settings in .claude/settings.json, so a checked-in repo cannot inject its own allow rules.", "autoMode entries from each scope are combined (additive). A developer can extend environment, allow, soft_deny, and hard_deny with personal entries but cannot remove entries that managed settings provide.", "Because allow rules act as exceptions to soft block rules inside the classifier, a developer-added allow entry can override an organization soft_deny entry; the combination is additive, not a hard policy boundary.", "For actions that must never run regardless of user intent or classifier config, use permissions.deny in managed settings, which blocks before the classifier and cannot be overridden.", "autoMode.environment tells the classifier which repos, buckets, and domains are trusted; entries are prose (natural-language), not regex or tool patterns.", "Include the literal string \"$defaults\" in any autoMode array (environment, allow, soft_deny, hard_deny) to splice in the built-in entries; custom entries can go before or after it.", "Classifier precedence has four tiers: hard_deny blocks unconditionally (no user intent or allow override); soft_deny blocks next (user intent and allow can override); allow rules override matching soft_deny; explicit specific user intent overrides remaining soft blocks.", "Explicit intent must directly and specifically describe the exact action. 'clean up the repo' does NOT authorize force-pushing; 'force-push this branch' does.", "Setting environment, allow, soft_deny, or hard_deny WITHOUT \"$defaults\" replaces the entire default list for that section. A soft_deny without $defaults discards built-in soft blocks including force push, curl|bash, and production deploys; a hard_deny without $defaults discards built-in data exfiltration and auto-mode bypass rules.", "Each autoMode section is evaluated independently, so setting environment alone leaves default allow, soft_deny, and hard_deny lists intact.", "CLI: 'claude auto-mode defaults' prints built-in environment/allow/soft_deny/hard_deny rules as JSON.", "CLI: 'claude auto-mode config' prints the effective config the classifier actually uses (settings applied where set, defaults otherwise, with $defaults expanded in place).", "CLI: 'claude auto-mode critique' gets AI feedback on custom allow/soft_deny/hard_deny rules, flagging ambiguous, redundant, or false-positive-prone entries.", "Auto-mode denials are recorded in /permissions under the 'Recently denied' tab; pressing 'r' on a denied action marks it for retry, and on exit Claude Code tells the model it may retry that tool call and resumes.", "To react to denials programmatically, use the PermissionDenied hook.", "Commercial users (Team, Enterprise, API, 3rd-party platforms, Claude Gov) — Anthropic does NOT train generative models on code/prompts sent to Claude Code under commercial terms, unless the customer opts in (e.g. Development Partner Program).", "Consumer users (Free, Pro, Max) — data IS used to train new models when the data-training setting is on, including Claude Code usage from those accounts. Setting changeable at claude.ai/settings/data-privacy-controls.", "Development Partner Program is an explicit org-admin opt-in for model training; available only for Anthropic first-party API, NOT for Bedrock or Vertex users.", "Data retention — Commercial (Team/Enterprise/API): 30-day standard retention.", "Data retention — Consumer who allow training: 5-year retention; who don't allow: 30-day retention.", "Zero Data Retention (ZDR) is available to qualified accounts for Claude Code on Claude for Enterprise; NOT included in standard Enterprise plan; enabled per-organization by your account team after eligibility confirmation.", "Transcripts shared via /feedback are retained for 5 years.", "Transcripts shared via the optional session-survey transcript-share follow-up are retained for up to 6 months.", "Local session transcripts are stored in plaintext under ~/.claude/projects/ for 30 days by default; adjust with cleanupPeriodDays setting.", "DISABLE_TELEMETRY environment variable opts out of operational metrics (latency/reliability/usage). Telemetry does not include any code or file paths.", "DISABLE_ERROR_REPORTING env var opts out of Sentry error logging.", "DISABLE_FEEDBACK_COMMAND=1 env var disables the /feedback command.", "CLAUDE_CODE_DISABLE_FEEDBACK_SURVEY=1 disables session quality surveys. Surveys also auto-disabled when DISABLE_TELEMETRY, DO_NOT_TRACK, or CLAUDE_CODE_DISABLE_NONESSENTIAL_TRAFFIC is set.", "CLAUDE_CODE_DISABLE_NONESSENTIAL_TRAFFIC opts out of all non-essential traffic (telemetry, errors, feedback, surveys) at once, but does NOT affect the WebFetch domain safety check (which has its own opt-out).", "feedbackSurveyRate setting (probability 0 to 1) in settings file controls survey frequency instead of fully disabling.", "CLAUDE_CODE_ENABLE_FEEDBACK_SURVEY_FOR_OTEL=1 lets orgs that block nonessential traffic re-enable surveys logging only to their own OpenTelemetry collector; transcript-share follow-up stays disabled.", "By default error reporting, telemetry, and /feedback are DISABLED when using Bedrock, Vertex, Foundry, or Claude Platform on AWS. Session quality surveys and the WebFetch domain safety check are exceptions and run regardless of provider.", "Provider opt-in env vars: CLAUDE_CODE_USE_VERTEX=1, CLAUDE_CODE_USE_BEDROCK=1, CLAUDE_CODE_USE_FOUNDRY=1, CLAUDE_CODE_USE_ANTHROPIC_AWS=1.", "As of v2.1.126, when host sets CLAUDE_CODE_PROVIDER_MANAGED_BY_HOST, metrics default ON for Vertex/Bedrock/Foundry and follow standard DISABLE_TELEMETRY opt-out; Sentry and /feedback remain off by default on those providers.", "WebFetch sends only the requested hostname (not full URL/path/contents) to api.anthropic.com to check a safety blocklist; results cached per hostname for 5 minutes. Runs regardless of provider and is NOT affected by CLAUDE_CODE_DISABLE_NONESSENTIAL_TRAFFIC.", "skipWebFetchPreflight: true in settings disables the WebFetch domain safety check; if api.anthropic.com is blocked, WebFetch fails until allowlisted or this is set.", "Session quality survey rating prompt records only the rating — no transcripts/inputs/outputs collected. The transcript-share follow-up ('Yes') uploads conversation transcript, subagent transcripts, and raw session log; only known API key/token patterns are redacted (source code/file contents uploaded as-is).", "The transcript-share follow-up never appears for orgs with zero data retention, where product feedback is disabled by org policy, or where CLAUDE_CODE_DISABLE_NONESSENTIAL_TRAFFIC is set.", "Survey responses and shared transcripts do NOT affect data-training preferences and cannot be used to train models.", "With third-party provider (Bedrock/Vertex) or no Anthropic credentials, /feedback writes a local archive to ~/.claude/feedback-bundles/ instead of sending to Anthropic; API key/token patterns redacted; nothing leaves the machine until manually sent.", "/feedback lets you choose history scope: current session only (default), or also other sessions from same project over last 24 hours or 7 days. Optionally creates a GitHub issue in a public repo.", "Data in transit encrypted via TLS 1.2+. Encryption at rest: Anthropic API AES-256 disk encryption; Bedrock AES-256 AWS-managed keys (CMK via KMS); Vertex Google-managed keys (CMEK available); Foundry routes to Anthropic infra with AES-256.", "Claude Code on the web runs in Anthropic-managed isolated VMs; GitHub auth via secure proxy (credentials never enter sandbox); all outbound traffic through a security proxy for audit/abuse prevention. Remote Control sessions follow LOCAL data flow (execution on your machine).", "For remote Claude Code, Claude accesses only the repository where you initiated the session, not other connected repositories without a started session.", "Environment variables can be checked into settings.json (settings reference).", "Team, Enterprise, and Claude API users are governed by Anthropic's Commercial Terms; Free, Pro, and Max users by the Consumer Terms of Service.", "Using the Claude API directly (1P) or via Amazon Bedrock or Google Vertex (3P), your existing commercial agreement applies to Claude Code usage unless mutually agreed otherwise.", "If a customer has a Business Associate Agreement (BAA) with Anthropic, it automatically extends to cover Claude Code only if the customer has executed a BAA AND has Zero Data Retention (ZDR) activated.", "ZDR is enabled on a per-organization basis; each organization must enable ZDR separately to be covered under the BAA. The BAA applies to that customer's API traffic flowing through Claude Code.", "OAuth authentication is exclusively for purchasers of Claude Free, Pro, Max, Team, and Enterprise subscription plans and is for ordinary use of Claude Code and other native Anthropic apps.", "Developers building products/services (including via the Agent SDK) must use API key authentication through Claude Console or a supported cloud provider, NOT OAuth/Claude.ai login.", "Anthropic does not permit third-party developers to offer Claude.ai login or to route requests through Free, Pro, or Max plan credentials on behalf of their users; Anthropic may enforce this without prior notice.", "Advertised usage limits for Pro and Max plans assume ordinary, individual usage of Claude Code and the Agent SDK.", "Claude Code usage is subject to the Anthropic Usage Policy (AUP).", "Security vulnerabilities are reported via Anthropic's HackerOne program; compliance/security details are at the Anthropic Trust Center (trust.anthropic.com) and Transparency Hub.", "All network env vars on this page can also be set in settings.json (via the `env` block in ~/.claude/settings.json).", "Claude Code respects standard proxy env vars: HTTPS_PROXY (recommended), HTTP_PROXY (fallback), and NO_PROXY.", "NO_PROXY accepts space-separated OR comma-separated lists (e.g. \"localhost,192.168.1.1,example.com,.example.com\"); NO_PROXY=\"*\" bypasses proxy for all requests.", "Claude Code does NOT support SOCKS proxies.", "Proxy basic auth: embed credentials in URL, e.g. export HTTPS_PROXY=http://username:password@proxy.example.com:8080. For NTLM/Kerberos, use an LLM Gateway service instead.", "CLAUDE_CODE_CERT_STORE accepts a comma-separated list of `bundled` (Mozilla CA set shipped with Claude Code) and/or `system` (OS trust store). Default is `bundled,system`.", "By default Claude Code trusts BOTH its bundled Mozilla CA certs AND the OS certificate store, so TLS-inspection proxies like CrowdStrike Falcon and Zscaler work with no extra config when their root cert is in the OS trust store.", "CLAUDE_CODE_CERT_STORE has NO dedicated settings.json schema key; set it via the `env` block in ~/.claude/settings.json or the process environment.", "NODE_EXTRA_CA_CERTS=/path/to/ca-cert.pem makes Claude Code trust a custom CA certificate directly.", "mTLS client cert auth uses CLAUDE_CODE_CLIENT_CERT (cert .pem), CLAUDE_CODE_CLIENT_KEY (private key .pem), and optional CLAUDE_CODE_CLIENT_KEY_PASSPHRASE for an encrypted key.", "Required allowlist URLs: api.anthropic.com (API requests), claude.ai (claude.ai auth), platform.claude.com (Console auth), downloads.claude.ai (plugin downloads + native installer/auto-updater), storage.googleapis.com (native installer/updater on versions prior to 2.1.116).", "Additional allowlist URLs: bridge.claudeusercontent.com (Claude in Chrome WebSocket bridge), *.claudeusercontent.com (artifact viewing in browser, not the CLI), raw.githubusercontent.com (changelog feed for /release-notes, release notes, plugin marketplace install counts).", "If you install Claude Code via npm or manage your own binary distribution, end users may not need access to downloads.claude.ai or storage.googleapis.com.", "WebFetch tool still calls api.anthropic.com for its domain safety check even when using Bedrock/Vertex/Foundry, unless you set skipWebFetchPreflight: true in settings.", "When using Amazon Bedrock, Google Vertex AI, or Microsoft Foundry, model traffic and auth go to your provider instead of api.anthropic.com / claude.ai / platform.claude.com.", "Claude Code sends optional operational telemetry by default; it can be disabled with environment variables (see Telemetry services / data-usage) before finalizing an allowlist.", "Claude Code on the web and Code Review connect to repos from Anthropic-managed infrastructure; for GitHub Enterprise Cloud orgs that restrict by IP, enable IP allow list inheritance for installed GitHub Apps (the Claude GitHub App registers its IP ranges).", "For self-hosted GitHub Enterprise Server behind a firewall, allowlist the Anthropic API IP addresses so Anthropic infra can reach the GHES host to clone repos and post review comments.", "storage.googleapis.com is only needed for the native installer/auto-updater on versions prior to 2.1.116 (max-version 2.1.115 note).", "Permission modes: `default` (reads only), `acceptEdits` (reads + file edits + common filesystem Bash), `plan` (reads only, no edits), `auto` (everything with classifier safety checks), `dontAsk` (only pre-approved tools), `bypassPermissions` (everything, no checks).", "Set default mode via `permissions.defaultMode` in settings.json (e.g. {\"permissions\":{\"defaultMode\":\"acceptEdits\"}}).", "Start in a mode at launch with `claude --permission-mode <mode>` (e.g. plan, dontAsk, bypassPermissions, acceptEdits). Same flag works with `-p` for headless.", "Shift+Tab cycles default → acceptEdits → plan in the CLI. Optional modes slot after plan: bypassPermissions first, auto last. dontAsk never appears in the cycle.", "In every mode except `bypassPermissions`, writes to protected paths are never auto-approved. Deny rules and explicit ask rules apply in every mode including bypassPermissions; allow rules have no effect in bypassPermissions.", "`permissions.allow` rules do NOT pre-approve protected-path writes: the safety check runs before allow rules are evaluated, so e.g. `Edit(.claude/**)` does not bypass protection.", "Protected directories include: .git, .config/git, .vscode, .idea, .husky, .cargo, .devcontainer, .yarn, .mvn, .claude (except .claude/worktrees). Protected files include .gitconfig, shell rc files (.bashrc/.zshrc/.envrc etc.), package config (.npmrc/.yarnrc/bunfig.toml etc.), .pre-commit-config.yaml, .mcp.json, .claude.json, pyrightconfig.json.", "Admins can lock OFF auto mode by setting `permissions.disableAutoMode` to \"disable\" in managed settings; this overrides the enable env var.", "Admins can block bypassPermissions by setting `permissions.disableBypassPermissionsMode` to \"disable\" in managed settings.", "On Team and Enterprise plans, an admin must enable auto mode in Claude Code admin settings (claude.ai/admin-settings/claude-code) before users can turn it on.", "Auto mode requires Claude Code v2.1.83+. On Anthropic API needs Opus 4.6+ or Sonnet 4.6; on Bedrock/Vertex/Foundry only Opus 4.7 and 4.8. Sonnet 4.5, Opus 4.5, Haiku, claude-3 are not supported.", "On Bedrock/Vertex AI/Foundry, auto mode is off until `CLAUDE_CODE_ENABLE_AUTO_MODE` is set to \"1\" (works in v2.1.158+); add to `env` block in ~/.claude/settings.json (per-dev) or managed settings (org-wide).", "Claude Code v2.1.142+ ignores `defaultMode: \"auto\"` in .claude/settings.json and .claude/settings.local.json (so a repo cannot grant itself auto mode); it must be in ~/.claude/settings.json (user settings) or managed settings.", "Claude Code on the web ignores `defaultMode: \"bypassPermissions\"` and `defaultMode: \"dontAsk\"` from settings files (silently); a checked-in repo settings file cannot start a cloud session in those modes.", "bypassPermissions cannot be entered mid-session unless started with an enabling flag (--permission-mode bypassPermissions, --dangerously-skip-permissions, or --allow-dangerously-skip-permissions). The --allow- variant adds it to the cycle without activating it.", "On Linux/macOS, Claude Code refuses to start in bypassPermissions when running as root or under sudo (unless inside a recognized sandbox / dev container running as non-root).", "As of v2.1.126, bypassPermissions also skips protected-path prompts (earlier versions still prompted). rm -rf / and rm -rf ~ still prompt as a circuit breaker even in bypassPermissions.", "dontAsk auto-DENIES every tool call that would otherwise prompt; only `permissions.allow` matches and read-only Bash run; explicit `ask` rules are denied (not prompted). Fully non-interactive — for CI.", "acceptEdits auto-approves filesystem Bash: mkdir, touch, rm, rmdir, mv, cp, sed (incl. with safe env prefixes like LANG=C, or wrappers timeout/nice/nohup), but only for paths inside working dir or additionalDirectories. Other Bash and out-of-scope/protected writes still prompt.", "Auto mode classifier blocks by default: curl|bash, sending sensitive data externally, prod deploys/migrations, mass cloud-storage deletion, granting IAM/repo perms, force push or push to main, git reset --hard / git checkout -- . / git restore . / git clean -fd / git stash drop|clear (v2.1.182+), git commit --amend on a HEAD commit not made this session, terraform/pulumi/cdk/terragrunt destroy.", "Auto mode classifier allows by default: local file ops in working dir, installing deps from lockfiles/manifests, reading .env and sending creds to matching API, read-only HTTP, pushing to the start branch or a Claude-created branch. Run `claude auto-mode defaults` to see full rule lists.", "Entering auto mode DROPS broad code-execution allow rules: blanket Bash(*)/PowerShell(*), wildcarded interpreters like Bash(python*), package-manager run commands, and Agent allow rules. Narrow rules like Bash(npm test) carry over. Dropped rules restored on leaving auto mode.", "Auto mode classifier sees user messages, tool calls, and CLAUDE.md content; tool RESULTS are stripped so hostile file/web content can't manipulate it directly. A separate server-side probe scans tool results for suspicious content.", "Auto mode fallback: if classifier blocks 3 times in a row OR 20 times total, auto mode pauses and prompts resume; thresholds not configurable. Any allowed action resets the consecutive counter. In headless -p mode, repeated blocks abort the session.", "Auto mode subagents: classifier evaluates the delegated task description before spawn (v2.1.178+), each subagent action during the run (subagent frontmatter `permissionMode` is IGNORED), and full action history on finish. Classifier runs on a server-configured model independent of /model; its calls count toward token usage.", "VS Code: set default via `claudeCode.initialPermissionMode`, but it does NOT accept `auto` — use `defaultMode` in user settings for auto. bypassPermissions needs the 'Allow dangerously skip permissions' extension toggle.", "Custom permission logic via `PreToolUse` and `PermissionRequest` hooks. Remote Control starting mode: `claude remote-control --permission-mode acceptEdits`.", "Permission rules are enforced by Claude Code, NOT by the model; instructions in CLAUDE.md or prompts shape what Claude tries but cannot grant/revoke access. Use /permissions, rules, permission modes, or PreToolUse hooks.", "Rules evaluate in order: deny, then ask, then allow. First match wins; rule specificity does NOT change order. A broad deny like Bash(aws *) blocks even calls matching a narrower allow Bash(aws s3 ls). A matching ask rule prompts even when a more specific allow also matches.", "Deny rule by bare tool name (e.g. Bash) removes the tool from Claude's context entirely. A scoped deny (e.g. Bash(rm *)) leaves the tool available but blocks matching calls. Bash(*) is equivalent to Bash.", "/permissions UI lists all permission rules and the settings.json file each is sourced from. Allow rules skip approval, Ask rules prompt every time, Deny rules block.", "Default approval tiers: Read-only tools (file reads, Grep) need no approval; Bash commands require approval ('don't ask again' persists permanently per project directory+command); File modifications require approval ('don't ask again' lasts until session end only).", "Permission modes set via defaultMode in settings files: default, acceptEdits (auto-accepts edits + mkdir/touch/mv/cp in cwd or additionalDirectories), plan (read-only exploration), auto (auto-approve with background safety checks, research preview), dontAsk (auto-denies unless pre-approved via allow rules), bypassPermissions (skips prompts except explicit ask rules).", "bypassPermissions skips prompts including writes to .git, .config/git, .claude, .vscode, .idea, .husky, .cargo, .devcontainer, .yarn, .mvn. Explicit ask rules still prompt; rm -rf / and rm -rf ~ still prompt as circuit breaker. Admins block it via permissions.disableBypassPermissionsMode: 'disable' in managed settings.", "Set permissions.disableBypassPermissionsMode or permissions.disableAutoMode to 'disable' in any settings file to prevent those modes; most useful in managed settings where they can't be overridden. disableBypassPermissionsMode works from any scope (a user can self-lock).", "Rule syntax is Tool or Tool(specifier). Examples: Bash(npm run build) exact match; Read(./.env); WebFetch(domain:example.com).", "Deny/ask rules can match a top-level scalar input parameter via Tool(param:value), e.g. Agent(model:opus), Agent(isolation:worktree), Bash(run_in_background:true). Allow rules cannot use this; they use each tool's own specifier. Value supports * wildcard; omitted params never match; one parameter per rule; whitespace around colon ignored.", "Canonicalized fields are NOT matchable via param syntax: command (Bash/PowerShell), file_path (Read/Edit/Write), path (Grep/Glob), notebook_path (NotebookEdit), url (WebFetch). A rule like Bash(command:rm *) is ignored with a startup warning; use Bash(rm *) instead.", "Bash wildcards: * matches any sequence including spaces, at any position. Space before * enforces word boundary: Bash(ls *) matches 'ls -la' not 'lsof'; Bash(ls*) matches both. Trailing :* equals trailing ' *' (Bash(ls:*) == Bash(ls *)); :* only recognized at end of pattern.", "Tool-name globs allowed in deny/ask rules: '*' matches every tool, 'mcp__*' matches all MCP tools across servers. Allow rules accept tool-name globs ONLY after a literal mcp__<server>__ prefix with glob-free server segment (e.g. mcp__puppeteer__*, mcp__github__get_*). Unanchored allow globs like '*', 'B*', 'mcp__*' are skipped with a warning.", "Compound commands: Claude Code is shell-operator aware; Bash(safe-cmd *) does NOT permit 'safe-cmd && other-cmd'. Separators: && || ; | |& & and newlines. Each subcommand must match independently. Approving a compound with 'don't ask again' saves a separate rule per subcommand (up to 5).", "Process wrappers stripped before Bash matching: timeout, time, nice, nohup, stdbuf, and bare xargs (no flags). NOT stripped: direnv exec, devbox run, mise exec, npx, docker exec — so Bash(devbox run *) would match 'devbox run rm -rf .'. Exec wrappers watch, setsid, ionice, flock and find with -exec/-delete always prompt and can't be prefix-approved.", "Built-in read-only Bash commands run without prompt in every mode: ls, cat, echo, pwd, head, tail, grep, find, wc, which, diff, stat, du, cd, and read-only git forms. Not configurable; add ask/deny to force a prompt. cd into cwd or additional dir is read-only, but cd combined with git in one compound always prompts.", "Read/Edit rules follow gitignore spec with 4 anchors: //path = absolute from FS root; ~/path = home dir; /path = relative to PROJECT ROOT (NOT absolute); path or ./path = relative to cwd. /Users/alice/file is NOT absolute (it's project-root-relative); use //Users/alice/file. Edit rules apply to all built-in file-editing tools.", "Read/Edit deny rules also apply to file commands in Bash (cat, head, tail, sed) but NOT to arbitrary subprocesses (Python/Node scripts reading files). For OS-level enforcement across all processes, enable the sandbox.", "Symlink handling: allow rules require BOTH symlink path and target to match (else prompt); deny rules block if EITHER matches.", "WebFetch rules use domain: prefix matching hostname, case-insensitive, * wildcards. WebFetch(domain:*.example.com) matches subdomains at any depth but NOT example.com itself. WebFetch(domain:*) == bare WebFetch. Non-leading wildcards match only text between two dots.", "WebFetch alone does not prevent network access: if Bash is allowed, Claude can curl/wget any URL. For reliable URL filtering, deny curl/wget/etc and use WebFetch(domain:...) allow rules, or use PreToolUse hooks.", "MCP rule forms: mcp__puppeteer (all tools from server), mcp__puppeteer__* (wildcard, all tools), mcp__puppeteer__puppeteer_navigate (specific tool).", "Agent(AgentName) controls subagents: Agent(Explore), Agent(Plan), Agent(my-custom-agent). Disable via deny array or --disallowedTools CLI flag.", "Cd rules control /cd command targets (not model-invocable). Bare Cd deny disables /cd; adding any Cd allow rule switches /cd to allowlist mode. Uses //, ~/, / anchors; * = one segment, ** = across segments.", "PreToolUse hooks run before the permission prompt and can deny/force-prompt/skip. Hook decisions do NOT bypass deny/ask rules (deny-first precedence preserved, including managed deny). A hook exiting code 2 blocks the call before rules are evaluated, overriding allow rules. Pattern: add 'Bash' to allow, register PreToolUse hook to reject specific commands.", "Extend working directories: --add-dir <path> at startup, /add-dir in session, or additionalDirectories in settings (persistent). Additional dirs follow same permission rules as cwd.", "additionalDirectories in a settings file grants FILE ACCESS ONLY, no config loading. Only --add-dir/ /add-dir directories load some config: Skills (.claude/skills/, live reload), Subagents (.claude/agents/), settings only enabledPlugins + extraKnownMarketplaces keys, and CLAUDE.md only when CLAUDE_CODE_ADDITIONAL_DIRECTORIES_CLAUDE_MD=1.", "Settings precedence (highest first): 1) Managed settings (cannot be overridden by anything incl CLI args), 2) Command line arguments, 3) Local project (.claude/settings.local.json), 4) Shared project (.claude/settings.json), 5) User (~/.claude/settings.json). A deny at any level cannot be overridden by any other level.", "Managed-only settings (ignored elsewhere): allowAllClaudeAiMcps, allowedChannelPlugins, allowManagedHooksOnly, allowManagedMcpServersOnly, allowManagedPermissionRulesOnly, blockedMarketplaces, channelsEnabled, forceRemoteSettingsRefresh, pluginTrustMessage, sandbox.filesystem.allowManagedReadPathsOnly, sandbox.network.allowManagedDomainsOnly, strictKnownMarketplaces, strictPluginOnlyCustomization, wslInheritsWindowsSettings.", "allowManagedPermissionRulesOnly:true blocks user/project allow/ask/deny rules so only managed rules apply (does not affect MCP allowlist — use allowManagedMcpServersOnly for that). allowManagedHooksOnly:true loads only managed/SDK/force-enabled-plugin hooks. strictPluginOnlyCustomization:true (or array ['skills','hooks']) blocks skills/agents/hooks/MCP from user/project sources.", "Managed settings delivered via MDM/OS-level policies, managed settings files, or server-managed settings. wslInheritsWindowsSettings:true (in Windows HKLM key or C:\\Program Files\\ClaudeCode\\managed-settings.json) makes WSL read Windows policy chain plus /etc/claude-code.", "Sandboxing is OS-level enforcement for Bash and child processes only; permissions cover all tools. Sandbox filesystem combines sandbox.filesystem settings with Read/Edit deny rules; network combines WebFetch rules with sandbox allowedDomains/deniedDomains.", "With autoAllowBashIfSandboxed:true (default) sandboxed Bash runs without prompting even with a bare Bash ask rule; content-scoped ask rules (Bash(git push *)) still prompt, deny rules still apply, and rm/rmdir targeting / home or critical paths still prompt.", "On Team and Enterprise plans, an admin enables/disables Remote Control and web sessions org-wide in Claude Code admin settings (claude.ai/admin-settings/claude-code). Remote Control also disablable per-device via disableRemoteControl managed setting; web sessions have no per-device key.", "Embedding hosts can supply managed policy via SDK managedSettings option when parentSettingsBehavior is 'merge'; embedder values can tighten but not loosen policy.", "/cd requires Claude Code v2.1.169+; it relocates the session (loads new dir CLAUDE.md, --resume finds session from there), unlike /add-dir which only adds access.", "Tool transcript labels can differ from canonical names (e.g. 'Stop Task' = TaskStop). Permission rules and hook matchers match the canonical name only. Deny/ask rules naming an unknown tool emit a startup warning (names with _ or * exempt).", "Starter settings configurations for deployment scenarios are at github.com/anthropics/claude-code/tree/main/examples/settings.", "The sandboxed Bash tool is enabled with the /sandbox command and uses macOS Seatbelt, and bubblewrap on Linux and WSL2.", "By default the sandboxed Bash tool allows writes to the working directory and prompts the first time a command needs a new network domain.", "The sandboxed Bash tool does NOT isolate MCP servers and hooks (separate processes running unconstrained on the host) nor other built-in tools like Read/Edit/WebFetch; those are gated by permission rules instead.", "The sandboxed Bash tool does not support native Windows; on Windows use WSL2 or a container/VM.", "The sandbox runtime is the @anthropic-ai/sandbox-runtime npm package; launch with `npx @anthropic-ai/sandbox-runtime claude`.", "The sandbox runtime denies ALL write and network access by default; you must configure it before launching.", "Sandbox runtime config lives in ~/.srt-settings.json or a file passed with --settings; you must allow write access to your project directory and to ~/.claude and ~/.claude.json, plus the network domains needed including api.anthropic.com or your provider endpoint.", "--dangerously-skip-permissions removes per-action review except explicit ask rules; the docs say always run it inside a container, VM, or the sandbox runtime so file tools/MCP/hooks are also inside the boundary.", "Auto mode replaces the prompt with a classifier that blocks actions escalating beyond the request, targeting unrecognized infrastructure, or driven by hostile content; it is a per-action control, not an isolation boundary.", "The published example dev container uses a default-deny iptables firewall, which supports running with --dangerously-skip-permissions for unattended work.", "The built-in Bash sandbox is the only sandboxing approach Claude Code enforces itself; deliver its `sandbox` settings keys via managed settings (MDM-managed file) or server-managed settings on Claude.ai.", "Dev containers, custom containers, and VMs are conventions not enforcement boundaries because Claude Code does not require a container; enforce via org device management or software allowlisting.", "Unprivileged containers running the nested Bash sandbox need a nested-sandbox setting (see Sandboxing troubleshooting).", "Claude Code on the web requires a Claude subscription and a connected GitHub account; sessions clone the repo from GitHub.", "Sandbox settings keys are documented at /en/settings#sandbox-settings, including managed-settings delivery.", "The Bash sandbox runs on macOS (Seatbelt), Linux and WSL2 (bubblewrap). Native Windows is unsupported; run inside WSL2. WSL1 is unsupported because bubblewrap needs WSL2 kernel features.", "Open the sandbox panel with the `/sandbox` slash command; it has three tabs: Mode, Overrides, Config (and a Dependencies tab that appears alone when a required package is missing).", "On Linux/WSL2 the sandbox requires two packages: `bubblewrap` (filesystem isolation) and `socat` (network relay). Install via `sudo apt-get install bubblewrap socat` (Ubuntu/Debian) or `sudo dnf install bubblewrap socat` (Fedora).", "An optional seccomp filter adds Unix domain socket blocking; install it with `npm install -g @anthropic-ai/sandbox-runtime`. ripgrep is bundled with the native binary.", "The dependency check runs at startup; restart Claude Code after installing packages for `/sandbox` to detect them.", "Selecting a mode in `/sandbox` writes to project-local `.claude/settings.local.json` (not checked into git, current project only).", "To enable the sandbox across all your projects, set `sandbox.enabled` to `true` in user settings `~/.claude/settings.json`.", "Two sandbox modes: auto-allow (sandboxed commands run without prompting) and regular permissions (all Bash commands go through the regular permission flow even when sandboxed). Both enforce identical filesystem/network restrictions.", "In auto-allow mode, these still prompt/apply: explicit deny rules; `rm`/`rmdir` targeting `/`, home, or critical system paths; content-scoped ask rules like `Bash(git push *)`. A bare `Bash` (or `Bash(*)`) ask rule is SKIPPED for sandboxed commands but still applies to commands that fall back to the regular flow.", "Default filesystem: write access only to current working directory + subdirectories and the session temp dir ($TMPDIR); read access to the entire computer EXCEPT certain denied dirs. The default read policy still allows reading ~/.aws/credentials and ~/.ssh/ — add them to denyRead to block.", "Claude Code sets `$TMPDIR` to the session temp dir for sandboxed commands; unsandboxed commands keep the shell's $TMPDIR, so the two resolve $TMPDIR to different directories. Pass temp files between them via the working directory.", "Grant subprocess write access to extra paths with `sandbox.filesystem.allowWrite` (e.g. [\"~/.kube\",\"/tmp/build\"]). Also available: `denyWrite`, `denyRead`, and `allowRead` (re-allow within a denyRead region).", "Sandbox filesystem path prefixes: `/` = absolute from root; `~/` = relative to home; `./` or no prefix = relative to project root (project settings) or to `~/.claude` (user settings). This DIFFERS from Read/Edit permission rules which use `//path` for absolute and `/path` for project-relative.", "When the same sandbox filesystem array is defined in multiple settings scopes, the arrays are MERGED (paths from every scope combined), not replaced. Paths from sandbox.filesystem settings and permission rules are also merged into the final config.", "Network: no domains are pre-allowed; first use of a new domain prompts for approval. Pre-allow with `allowedDomains`; block with `deniedDomains` (overrides a broader allowedDomains wildcard).", "The built-in network proxy enforces the allowlist by requested hostname and does NOT terminate or inspect TLS — so broad allows (e.g. github.com) can enable data exfiltration / domain fronting.", "Sandbox escape hatch: when a command fails due to sandbox restrictions, Claude may retry with the `dangerouslyDisableSandbox` parameter, which runs outside the sandbox via the regular permission flow (requires approval).", "Set `sandbox.allowUnsandboxedCommands` to `false` (shown as 'Strict sandbox mode' in Overrides) to fully ignore `dangerouslyDisableSandbox`; then all commands must run sandboxed or be listed in `excludedCommands`.", "By default, if the sandbox can't start (missing deps / unsupported platform) Claude Code warns and runs UNSANDBOXED. Set `sandbox.failIfUnavailable` to `true` to make it a hard failure (block startup) — intended for managed deployments requiring sandboxing as a security gate.", "Enforce sandboxing org-wide via managed settings (MDM-managed file or Claude.ai server-managed settings). Recommended managed config: {\"sandbox\":{\"enabled\":true,\"failIfUnavailable\":true,\"allowUnsandboxedCommands\":false}}.", "Managed-settings precedence: for boolean keys (enabled, failIfUnavailable) the managed value wins and local values are ignored. For array keys (excludedCommands, allowRead) entries from every scope are MERGED, so developers can append/widen.", "Set `allowManagedReadPathsOnly` to `true` in managed settings so only managed `allowRead` entries are honored (user/project/local ignored). Set `allowManagedDomainsOnly` to `true` to honor only managed `allowedDomains` and auto-block non-allowed domains instead of prompting.", "`excludedCommands` has NO managed-only lockdown equivalent — developers can always append entries to run commands outside the sandbox. Keep the managed list narrow.", "The sandbox auto-denies writes to Claude Code's settings.json files at every scope and to the managed settings directory, so a sandboxed command cannot modify its own policy.", "Git worktrees: when CWD is a linked worktree, the sandbox allows writes to the main repo's shared `.git` dir (so git commit works) but denies writes to `hooks/` and `config` inside it.", "Subagents run in the same process and use the same sandbox config as the parent; their Bash commands are sandboxed when the parent has sandboxing enabled.", "Sandboxed Bash inherits the parent process environment (including credentials) by default. Set `CLAUDE_CODE_SUBPROCESS_ENV_SCRUB` to strip Anthropic and cloud provider credentials from subprocesses.", "Built-in Read/Edit/Write file tools use the permission system directly, NOT the sandbox. The sandbox only isolates Bash subprocesses.", "`/sandbox` is NOT a permission mode. Auto-allow (sandbox) is separate from Auto mode (permission-mode classifier); they work independently and can be combined.", "In auto-allow sandbox mode, Bash commands that modify files within sandbox boundaries execute without prompting even if you are not in accept-edits mode and even though file edit tools would normally require approval.", "Custom proxy: set `sandbox.network.httpProxyPort` and `sandbox.network.socksProxyPort` to route traffic through a corporate/MITM proxy that can terminate TLS, filter, and log.", "`--dangerously-skip-permissions` is blocked when running as root or via sudo on Linux/macOS, except inside a recognized sandbox. Use the dev container (runs as non-root) for autonomous container runs.", "On Ubuntu 24.04+ (and inside WSL2), AppArmor may block bubblewrap user namespaces. Check `sysctl kernel.apparmor_restrict_unprivileged_userns`; if it returns 1, add an AppArmor profile for /usr/bin/bwrap and `sudo systemctl reload apparmor`.", "Starter sandbox settings examples live in the claude-code repo: github.com/anthropics/claude-code/tree/main/examples/settings.", "Claude Code defaults to strict read-only permissions; a built-in set of read-only commands (ls, cat, git status) runs without a prompt, while commands that can modify the system require explicit approval.", "Write access is confined to the folder where Claude Code was started and its subfolders; it cannot write to parent directories without explicit permission, but it CAN read files outside the working directory.", "Accept Edits mode auto-approves file edits and a fixed set of filesystem Bash commands (mkdir, touch, rm, mv, cp, sed) for paths in the working directory; other Bash commands and out-of-scope paths still prompt.", "Network-fetching commands like curl and wget are NOT auto-approved by default; they prompt like any non-read-only Bash command. Approve once, add an allow rule like Bash(curl *), or block entirely via permissions.deny.", "Tools that make network requests require user approval by default.", "Web fetch uses a separate (isolated) context window to avoid injecting potentially malicious prompts into the main context.", "First-time codebase runs and new MCP servers require trust verification.", "Trust verification is DISABLED when running non-interactively with the -p flag.", "When Claude Code is started directly in the home directory, trust acceptance is held for the session only and not written to disk, so the prompt reappears each launch; there is no setting to persist it. Fix: start from a project subdirectory where trust is saved per directory.", "Command injection detection: suspicious bash commands require manual approval even if previously allowlisted.", "Fail-closed matching: unmatched commands default to requiring manual approval.", "Credentials: API keys/tokens stored in macOS Keychain when available; protected by file permissions on Windows and Linux.", "The /sandbox command enables filesystem and network isolation for bash commands, reducing permission prompts while maintaining security.", "The list of allowed MCP servers is configured in source code as part of Claude Code settings checked into source control.", "Anthropic reviews connectors against listing criteria before adding them to the Anthropic Directory but does NOT security-audit or manage any MCP server.", "ConfigChange hooks (documented at /en/hooks#configchange) can audit or block settings changes during sessions.", "Team enforcement of organizational standards is done via managed settings (see /en/settings settings-files).", "Audit your permission settings with /permissions; report suspicious behavior with /feedback.", "Windows WebDAV risk: Anthropic recommends against enabling WebDAV or allowing access to paths like \\\\* on Windows, because WebDAV may let Claude Code trigger remote network requests that bypass the permission system.", "Cloud execution (Claude Code on the web): isolated Anthropic-managed VM per session; network access limited by default and configurable to disabled or specific-domain allowlist; git push restricted to current working branch; all operations audit-logged; environments auto-terminated after session.", "Cloud credential protection uses a secure proxy with a scoped credential inside the sandbox translated to the actual GitHub token.", "Remote Control sessions run the Claude Code process locally (no cloud VM/sandbox); all code execution and file access stay local; the connection uses multiple short-lived, narrowly scoped credentials that expire independently.", "Report security vulnerabilities via Anthropic's HackerOne program; do not disclose publicly and allow time to address before disclosure.", "Commercial Terms of Service apply to Team, Enterprise, and API users; Consumer Terms apply to Free, Pro, and Max users. Consumer users can change data-training/privacy settings; the page implies different data handling by plan tier.", "Install the security-guidance plugin with `/plugin install security-guidance@claude-plugins-official`; if marketplace not found, run `/plugin marketplace add anthropics/claude-plugins-official` first, then `/reload-plugins` to apply without restart.", "Prerequisites: Claude Code CLI version 2.1.144 or later; Python 3.8+ on PATH (tries python3, python, py -3 in order); a git repo (end-of-turn and commit reviews diff git state and skip silently outside a repo; per-edit pattern check works anywhere).", "On first run the plugin creates a venv under ~/.claude/security/ and installs the Claude Agent SDK into it (needs pip + network). If install fails, commit review falls back to single-shot review. On Windows the venv step is skipped; agentic commit review runs only if claude-agent-sdk is already importable, else falls back.", "The plugin reviews at three points: (1) on each file edit — deterministic string/pattern match, no model call, no cost; (2) at end of each turn — background model diff review; (3) on each commit/push Claude makes — deeper agentic review reading surrounding code.", "Per-edit check flags categories: dynamic code execution (eval(, new Function, os.system, child_process.exec), unsafe deserialization (pickle), DOM injection (dangerouslySetInnerHTML, .innerHTML =, document.write), and edits under .github/workflows/. Each warning fires once per pattern per file per session.", "End-of-turn review computes a git diff of everything changed during the turn (edit tools, Bash, subagents), runs in background, covers up to 30 changed files per turn, and fires at most three times in a row before yielding.", "Commit/push review fires only on `git commit`/`git push` Claude runs through its Bash tool — NOT on commits from your own shell or the `!` shell escape. Capped at 20 reviews per rolling hour. Duplicate findings vs end-of-turn review do not re-prompt Claude.", "Enable in cloud sessions / for everyone cloning a repo via checked-in `.claude/settings.json` with `\"enabledPlugins\": {\"security-guidance@claude-plugins-official\": true}`. User-scoped plugins do NOT carry into Claude Code on the web (runs on Anthropic infra).", "Administrators can enable the plugin org-wide by setting `enabledPlugins` in managed settings (admin-setup). If enabled through managed settings, only an administrator can disable it.", "Add model-review guidance in `.claude/claude-security-guidance.md` (plain-language threat model/checklist). Lookup locations: ~/.claude/claude-security-guidance.md (user, all projects), .claude/claude-security-guidance.md (project, checked in), .claude/claude-security-guidance.local.md (gitignored personal override). All existing locations are concatenated, combined cap 8 KB.", "Add per-edit deterministic rules in `.claude/security-patterns.yaml` (also .yml and .json with same schema). Fields: rule_name, reminder (capped 1 KB), regex (Python regex), substrings (list), paths (globs, prefix project-relative with **/), exclude_paths. Loads up to 50 custom rules; skips regexes prone to catastrophic backtracking.", "YAML pattern files require PyYAML importable (plugin does NOT install it); if PyYAML missing the YAML file is silently ignored — use security-patterns.json (works on any Python) instead.", "Both model-backed reviews use Claude Opus 4.7 by default. Override with SECURITY_REVIEW_MODEL (end-of-turn) and SG_AGENTIC_MODEL (commit review).", "Disable layers via env vars: ENABLE_PATTERN_RULES=0, ENABLE_STOP_REVIEW=0, ENABLE_COMMIT_REVIEW=0, ENABLE_CODE_SECURITY_REVIEW=0 (all model reviews), SECURITY_GUIDANCE_DISABLE=1 (entire plugin without uninstalling). Pause: `/plugin disable ...`; remove: `/plugin uninstall ...`.", "If plugin was enabled via project .claude/settings.json, disabling via /plugin writes an override to your .claude/settings.local.json (does not edit the checked-in file) — off for you, unaffected for teammates.", "Built-in checks cannot be removed individually; extension files (guidance md, patterns yaml) are additive only — a rule saying to ignore a vulnerability class does NOT suppress those findings. Each layer can be disabled independently via env vars.", "Plugin is built entirely on hooks: SessionStart (bootstrap Python env), UserPromptSubmit (capture working-tree baseline), PostToolUse on Edit/Write/NotebookEdit (per-edit match), Stop (end-of-turn review, background), PostToolUse on Bash filtered to git commit/git push (commit review, background).", "Runtime diagnostics log at ~/.claude/security/log.txt. Common silent skips: not a git repo; no Anthropic authentication (model reviews skip, only per-edit runs); security-patterns.yaml present but PyYAML not importable (file ignored).", "Defense-in-depth stack: in-session security-guidance plugin → on-demand /security-review (one-time pass on current branch) → PR-time Code Review (multi-agent, Team and Enterprise plans) → CI static analysis/dependency scanners. Plugin available on all plans.", "Server-managed settings require Claude for Teams or Claude for Enterprise plan; managed via Claude.ai Admin Settings > Claude Code > Managed settings.", "Minimum versions: Claude Code v2.1.38+ for Teams, v2.1.30+ for Enterprise. Requires network access to api.anthropic.com.", "Two centralized-config approaches: server-managed (delivered from Anthropic servers at auth time, for orgs without MDM) and endpoint-managed (deployed via MDM/macOS managed preferences/Windows registry/managed-settings.json file). Endpoint-managed gives stronger guarantees because the file can be OS-protected from user modification.", "All settings.json keys are supported in managed settings except OS-policy-only ones; this includes hooks, env vars, and managed-only keys like allowManagedPermissionRulesOnly. Hooks use the same format as settings.json.", "Permissions example keys: permissions.deny (e.g. \"Bash(curl *)\", \"Read(./.env)\", \"Read(./secrets/**)\"), permissions.disableBypassPermissionsMode: \"disable\", and top-level allowManagedPermissionRulesOnly: true (restricts permission rules to managed ones only).", "autoMode.environment is an array of natural-language strings telling the auto-mode classifier which repos, buckets, and trusted domains the org trusts (see /en/auto-mode-config); also supports allow, soft_deny, hard_deny fields.", "Settings precedence: server-managed and endpoint-managed both occupy the HIGHEST tier; no other level (including command-line args) can override them. Within the managed tier, server-managed is checked first, then endpoint-managed. Sources do NOT merge — if server-managed delivers any keys at all, endpoint-managed is ignored entirely. If server-managed delivers nothing, endpoint-managed applies.", "Most settings keys work in any scope. Managed-only keys are only read from managed settings and have no effect in user/project files (full list at /en/permissions#managed-only-settings). Any non-managed-only key placed in managed settings takes highest precedence.", "Clients fetch settings at startup and poll hourly during active sessions. Updates apply automatically without restart, EXCEPT advanced settings like OpenTelemetry config which need a full restart.", "Cache file is ~/.claude/remote-settings.json; it stores the salvaged payload (invalid entries stripped); the raw invalid payload is never persisted.", "Invalid-entry tolerance: a payload entry failing schema validation is stripped, a validation error surfaced, and remaining valid settings applied (requires v2.1.169+). If no field can be salvaged, last-accepted cached settings are kept and a fatal error recorded.", "forceRemoteSettingsRefresh: true makes the CLI block at startup until remote settings are freshly fetched; if fetch fails the CLI exits rather than proceeding unenforced. Setting self-perpetuates via local cache. As of v2.1.139, claude auth subcommands (e.g. claude auth login) are exempt from this check.", "Security approval dialog is shown to users before applying: shell-command settings, custom env vars not in the safe allowlist, and any hook configuration. Rejecting causes Claude Code to exit. In non-interactive mode with -p, security dialogs are SKIPPED and settings applied without approval. The dialog evaluates the salvaged payload, so stripped invalid entries are never approved or executed.", "Only Primary Owner and Owner roles can manage server-managed settings; changes apply to all org users.", "Server-managed settings are bypassed when using third-party model providers: Amazon Bedrock, Google Vertex AI, Microsoft Foundry, or custom ANTHROPIC_BASE_URL/LLM gateways. Specifically bypassed by env vars CLAUDE_CODE_USE_BEDROCK, CLAUDE_CODE_USE_MANTLE, CLAUDE_CODE_USE_VERTEX, CLAUDE_CODE_USE_FOUNDRY, or non-default ANTHROPIC_BASE_URL.", "managed-mcp.json CANNOT be distributed via server-managed settings; deliver allowedMcpServers and deniedMcpServers policy keys via the managed-mcp.json file instead (see /en/managed-mcp).", "Settings restricted to OS-level policy sources (policyHelper, wslInheritsWindowsSettings) are not honored in server-managed settings; deploy via MDM or a system managed-settings.json.", "Per-group / per-user configs are NOT supported — server-managed settings apply uniformly to all org users.", "Verification/debug commands: /permissions (view effective managed permission rules), /status (see which managed source is active), claude --debug-file <path> then search log for 'Remote settings', claude doctor to validate a payload on a test machine before org rollout.", "ConfigChange hooks (/en/hooks#configchange) can log or block runtime config modifications before they take effect.", "Audit log events for settings changes (action type, account, device, previous/new values) are available via the compliance API or audit log export; contact Anthropic account team for access.", "ZDR for Claude Code is available only to qualified accounts on Claude for Enterprise; it is NOT included in the standard Claude for Enterprise plan and cannot be enabled from admin settings.", "ZDR requires separate enablement by Anthropic (via sales/account team); admins cannot self-enable it.", "ZDR is enabled per-organization. It does NOT auto-apply to new organizations created under the same account; each new org must be enabled separately by the Anthropic account team.", "Under ZDR, prompts and model responses from Claude Code sessions are processed in real time and not stored after the response returns, except where needed to comply with law or combat misuse.", "ZDR on Claude for Enterprise also grants administrative capabilities: per-user cost controls, Analytics dashboard, Server-managed settings (/en/server-managed-settings), and audit logs.", "ZDR covers only Claude Code inference on Anthropic's direct platform. Bedrock, Vertex AI, and Microsoft Foundry deployments follow those platforms' own data retention policies, not Anthropic ZDR.", "ZDR does NOT cover: Chat on claude.ai, Cowork sessions, Claude Code Analytics metadata (account emails, usage stats), user/seat management data, or third-party tools/MCP servers/external integrations — these follow standard data retention.", "For ZDR orgs, the Analytics dashboard shows usage metrics only; contribution metrics are not available.", "Features automatically disabled at the backend under ZDR: Claude Code on the Web, Cloud sessions from the Desktop app, Artifacts, and feedback submission (/feedback command).", "Disabled features are blocked in the backend regardless of client display; using one returns an error that the org's policies do not allow the action.", "Claude Fable 5 is NOT available under ZDR (it requires data retention); it is absent or shown disabled in the /model picker and the server rejects requests for it regardless of client config.", "Fable 5 is not the default model. The 'best' alias resolves to Fable 5 where available but resolves to Opus for ZDR organizations.", "Even with ZDR, if a session is flagged for a Usage Policy violation, Anthropic may retain associated inputs and outputs for up to 2 years.", "All ZDR enablement actions are audit-logged.", "Existing ZDR-via-pay-as-you-go-API-key users can transition to Claude for Enterprise to gain admin features while keeping ZDR for Claude Code (coordinate via account team)."]}, "Setup & onboarding": {"pages": ["admin-setup", "advisor", "authentication", "champion-kit", "communications-kit", "devcontainer", "goal", "overview", "platforms", "quickstart", "setup", "third-party-integrations"], "bestPractices": ["For mixed-provider orgs, configure server-managed settings for Claude.ai users PLUS a file-based or plist/registry fallback so non-Claude.ai users still receive managed policy.", "Use admin-only enforcement channels (macOS plist, Windows HKLM, file-based managed paths) for real policy enforcement; do not rely on Windows HKCU which is writable without elevation.", "Pair permission rules with sandboxing: denying WebFetch alone leaves a hole because allowed Bash can run curl/wget — add `sandbox.network.allowedDomains` to enforce network limits at the OS level.", "Use `requiredMinimumVersion`/`requiredMaximumVersion` (not just `minimumVersion`) when you need to refuse start outside an approved version range, not merely block downgrades.", "Lock down customization sources with `strictPluginOnlyCustomization` so skills/agents/hooks/MCP servers come only from vetted plugins or managed settings, not arbitrary user/project files.", "Deploy an org-wide managed-policy CLAUDE.md to inject mandatory instructions into every session (cannot be excluded by developers).", "After configuring managed settings, validate the rollout by having a developer run `/status` and confirm the `Setting sources` line reports `Enterprise managed settings` with the expected source.", "Place an LLM gateway between developers and the provider when you need request-level audit logging or to route traffic by data sensitivity.", "Use the advisor for long, multi-step tasks where most turns are routine but plan quality determines the outcome (large refactors, recurring-error debugging, independent completion checks).", "Pair a faster/cheaper main model with a stronger advisor (e.g. Sonnet main + Opus advisor) to escalate planning and completion checks at decision points — typically cheaper than running the stronger model throughout.", "For lowest cost, use Haiku main + Opus advisor (higher than Haiku alone but lower than switching main to Sonnet/Opus).", "For high-stakes work, use Opus main + Opus advisor so a second Opus independently reviews the first.", "To get more or fewer consultations, instruct Claude in your prompt (e.g. 'consult the advisor before you continue') — there is no frequency setting.", "Don't use the advisor on short tasks with little to plan, or work where every turn needs the strongest model; switch the main model instead.", "Prefer the advisor when you want Claude to decide when a second opinion is needed; use opusplan for stronger planning in plan mode, subagents for an entire delegated subtask, or /model to switch all subsequent turns.", "For CI/scripts/headless without browser login, generate a token with 'claude setup-token' and set CLAUDE_CODE_OAUTH_TOKEN; do not rely on interactive /login.", "For rotating/short-lived credentials (e.g., vault tokens), use apiKeyHelper rather than a static ANTHROPIC_API_KEY, and tune CLAUDE_CODE_API_KEY_HELPER_TTL_MS to match token lifetime.", "When routing through an LLM gateway/proxy that uses bearer tokens, use ANTHROPIC_AUTH_TOKEN (Authorization: Bearer); use ANTHROPIC_API_KEY only for direct Anthropic API access (X-Api-Key).", "If subscription auth fails while an org-issued ANTHROPIC_API_KEY is set, run 'unset ANTHROPIC_API_KEY' to fall back to subscription, then check '/status' to confirm the active method.", "For org-wide auth distribution with cloud providers, distribute the required env vars + credential-generation instructions to users (see /en/settings) rather than per-user manual login.", "Larger orgs needing SSO, role-based permissions, compliance API, and managed policy should adopt Claude for Enterprise rather than self-service Teams.", "Assign the 'Claude Code' Console role (not 'Developer') to users who should only be able to create Claude Code API keys, to limit key scope.", "In WSL2/SSH/container sessions where the browser can't reach the local callback server, expect a login code and paste it at the 'Paste code here if prompted' terminal prompt.", "Run /init once per repo to generate a CLAUDE.md, then add team conventions, test commands, and directories that should NOT be modified (this is the canonical fix for 'doesn't understand our conventions' and for hallucination caused by missing context).", "Provide context with @file and @directory/ references (e.g. @src/components/) or paste error/log/stack-trace output directly; supplying relevant context beats elaborate prompting.", "Use plan mode for changes to shared/production code: press Shift+Tab until you see 'plan' — Claude lays out exactly which files it will touch and changes nothing until approved.", "To recover from a wrong result, paste the failing test or stack trace back to Claude and ask it to fix that specific failure, rather than rephrasing the original request.", "Keep edits surgical by stating scope explicitly ('only change X' or 'give me a diff') — Claude respects scope when scope is stated.", "Save reusable team workflows as .claude/skills/<name>/SKILL.md to create a /name slash skill the whole team can use; because skills are plain Markdown, colleagues can adopt them by copying the file.", "Configure a Stop hook to get a desktop notification when a long-running task completes, so you can step away during long runs.", "Run /team-onboarding in a project you've used heavily: Claude scans your recent sessions, commands, and MCP servers and produces a setup guide a new teammate can paste as their first message to replay your setup.", "For onboarding juniors, have them run 'Explain @file and where it is called from' before asking Claude to change anything.", "Distribute durable patterns (custom skills, CLAUDE.md examples) on the team wiki; post ephemeral discoveries as a screenshot + one or two sentences in the engineering channel.", "Run /init early in each repo; keep CLAUDE.md under two screens — treat it as a cheat sheet (build commands, architecture, conventions), not full documentation.", "Start in plan mode (Shift+Tab until you see 'plan') for any change touching multiple files — get a full proposal before any file moves; this is the fastest way to calibrate trust.", "Review diffs before committing — Claude can be confidently wrong; verify changes that touch critical paths.", "Match the model to the task: Sonnet as default, Opus for high-stakes/large refactors, Haiku for mechanical edits, Fable 5 (opt-in) for hardest long-running work — switch mid-session with /model.", "Use @file/@directory references instead of pasting file contents into the prompt.", "Turn any multi-step prompt you've typed more than once into a skill (.claude/skills/<name>/SKILL.md); ask Claude to create it for you.", "Use a Stop hook to send a desktop notification so you can walk away during long tasks.", "Browse /plugin before building a custom skill — it may already exist.", "For team rollout: create a #claude-code channel, test the install command on one machine first, assign a named channel owner for the first 48 hours, have a C-suite sponsor send/co-sign the announcement, and pick one concrete real first task rather than a generic example.", "Exec-sent launch announcements consistently see higher first-week adoption than admin-sent ones.", "After launch, recruit the 2-3 most active #claude-code posters as champions.", "Drip the tips-and-tricks messages one or two per week to drive feature activation post-launch.", "Pin the Claude Code CLI version in the Dockerfile (npm install -g @anthropic-ai/claude-code@X.Y.Z) plus DISABLE_AUTOUPDATER=1 when you need reproducible team builds; otherwise the feature installs latest and auto-updates.", "Mount a named volume at the remoteUser's ~/.claude so engineers don't re-authenticate on every container rebuild; use ${devcontainerId} in the volume source name to isolate Claude state per repository.", "Deliver unbypassable org policy via server-managed settings (Claude.ai admin console) or MDM rather than baking managed-settings.json into the repo Dockerfile, since anyone with repo write access can edit/remove the Dockerfile COPY step.", "Check MCP servers into the repo at project scope via a root .mcp.json so the whole team gets the same servers; install stdio-server binaries in the Dockerfile and add remote server domains to the firewall allowlist.", "Only run --dangerously-skip-permissions with trusted repositories, ensure remoteUser is non-root, and pair it with network egress restrictions; prefer auto mode (classifier-reviewed actions) when you want fewer prompts without disabling safety.", "Set CLAUDE_CODE_DISABLE_NONESSENTIAL_TRAFFIC=1 and DISABLE_AUTOUPDATER=1 in containerEnv to standardize telemetry opt-out and update behavior across the team.", "For cloud-provider auth, inject credentials as env vars (containerEnv / Codespaces secrets / workload identity); avoid mounting host secrets like ~/.ssh or cloud credential files into the container — prefer repository-scoped or short-lived tokens.", "Use /goal for substantial work with a verifiable end state (API migration until all call sites compile + tests pass, implementing a design doc until acceptance criteria hold, splitting a large file until each module is under a size budget, clearing an issue backlog).", "Write conditions Claude's own output can demonstrate, since the evaluator does not run commands or read files — e.g. 'all tests in test/auth pass' works because Claude runs the tests and the result lands in the transcript.", "Give a condition one measurable end state (test result, build exit code, file count, empty queue), a stated check for how Claude proves it (e.g. 'npm test exits 0', 'git status is clean'), and constraints that must not change (e.g. 'no other test file is modified').", "Bound run length by adding a turn/time clause to the condition itself, e.g. 'or stop after 20 turns'; Claude reports progress against it each turn.", "Combine /goal with auto mode for unattended runs: auto mode removes per-tool prompts, /goal removes per-turn prompts, and the fresh evaluator decides completion rather than the model doing the work.", "For a team needing custom or deterministic completion logic across all sessions, prefer a Stop hook in the settings file (script-based for deterministic checks, prompt-based for model-evaluated) rather than the session-only /goal.", "Put team coding standards, architecture decisions, preferred libraries, and review checklists in a project-root CLAUDE.md so every session and every surface picks them up automatically.", "Distribute repeatable team workflows as Skills (slash commands like /review-pr, /deploy-staging) rather than re-explaining procedures per session.", "Use Hooks to enforce deterministic policy (auto-format after edits, lint before commit) instead of relying on the model to remember.", "Use `claude -p` in CI/pipelines for code review, issue triage, and bulk file operations (e.g. pipe `git diff main --name-only` into it for changed-file security review).", "Standardize MCP server config and settings centrally since they propagate across all surfaces from the same engine.", "For teams on Homebrew/WinGet, schedule periodic manual upgrades (`brew upgrade claude-code` / `winget upgrade Anthropic.ClaudeCode`) since those channels do not auto-update — security fixes will lag.", "Use the llms.txt index to systematically discover authoritative docs pages rather than guessing URLs.", "For a team, standardize on the CLI for any scripting, Agent SDK/headless automation, or CI work, since those capabilities are CLI-only.", "Rely on shared config, project memory (CLAUDE.md), and MCP servers being shared across local surfaces so team members can mix CLI/Desktop/IDE on the same project without re-configuring.", "Use GitHub Actions / GitLab CI/CD + Code Review for automated, governed PR review so bugs are caught before human review.", "Choose the web/cloud surface for long-running tasks that should continue when the developer disconnects; choose CLI/IDE for steerable interactive work.", "For enterprise provider routing, pick the surface by provider: Vertex AI and gateways work on Desktop, but Bedrock or Foundry require CLI or VS Code.", "Be specific in requests: include the symptom and context (e.g. 'fix the login bug where users see a blank screen after entering wrong credentials') rather than 'fix the bug'.", "Break complex tasks into explicit numbered steps in a single prompt so Claude executes them in sequence.", "Let Claude explore/analyze the codebase first (e.g. 'analyze the database schema') before asking it to make changes.", "Use /clear to reset conversation history between unrelated tasks to keep context clean.", "Use Shift+Tab to cycle permission modes; enable 'Accept all' mode only for a session when you want to skip per-edit approval.", "Use claude -c to continue the most recent conversation in the current directory, and claude -r (or /resume) to resume a specific earlier conversation.", "For team consistency, pin the release channel and a minimum version via managed settings (autoUpdatesChannel=\"stable\" + minimumVersion) so user/project settings cannot drift the fleet.", "To hard-gate an allowed version window for an org, use managed requiredMinimumVersion and requiredMaximumVersion (these block startup), not just minimumVersion (which only constrains updates).", "When self-distributing Claude Code, set DISABLE_UPDATES (not just DISABLE_AUTOUPDATER) so users stay on the version you provide.", "Prefer the \"stable\" channel for fleets that need predictability; it lags ~1 week and skips regression releases.", "In enterprise/governed deployments, verify the signed manifest.json (GPG fingerprint 31DD DE24 DDFA B679 F42D 7BD2 BAA9 29FF 1A7E CACE) before distributing binaries internally.", "On WSL/native Windows teams, standardize on WSL 2 if you need sandboxed command execution (sandboxing is unsupported on native Windows and WSL 1).", "Install Git for Windows on native Windows fleets to get the Bash tool; otherwise commands run via the more limited PowerShell tool.", "Use `claude doctor` as the first diagnostic for failed updates, non-writable npm global dirs, and install/config health.", "For package-manager installs (Homebrew/WinGet/apt/dnf/apk), set CLAUDE_CODE_PACKAGE_MANAGER_AUTO_UPDATE=1 or fold `claude update` into your normal system upgrade workflow, since these do not auto-update.", "For most orgs, prefer Claude for Teams/Enterprise over cloud-provider deployments: single subscription, centralized billing, includes Claude on web, no infrastructure setup.", "Check a team .mcp.json into the codebase (configured by one central team) so all users inherit the same MCP servers — e.g. ticket systems, error logs.", "Deploy CLAUDE.md at both org level (system dir) and repo level; check repo CLAUDE.md into source control so every user benefits.", "Pin model versions via ANTHROPIC_DEFAULT_*_MODEL on Bedrock/Vertex/Foundry/Claude Platform on AWS so you control when users move to a new model and avoid lag/unavailable-model issues.", "Use managed (security-team) permission policies that local config cannot override to enforce what Claude Code may do.", "Build a 'one-click' install for custom dev environments to drive org-wide adoption.", "Onboard new users with guided usage: codebase Q&A and small bug fixes/features, ask Claude to make a plan, review and give feedback before allowing more agentic runs.", "Combine corporate proxy (HTTPS_PROXY) and LLM gateway when you need both network policy enforcement and centralized usage tracking/rate limiting/budgets/auth.", "Run /status after configuring proxy/gateway to confirm the configuration took effect."], "gotchas": ["Developers can EXTEND but not remove managed `permissions.allow`/`permissions.deny` entries — array settings merge across all sources, so a managed deny cannot be overridden locally.", "WSL ignores Windows policy by default (reads only `/etc/claude-code`); you must set `wslInheritsWindowsSettings: true` in a Windows source to inherit Windows-side managed settings.", "Windows HKCU registry policy is writable without admin elevation, so it is not a real enforcement boundary despite being a 'policy' location.", "Server-managed settings only work on Claude for Teams/Enterprise plans — Bedrock/Vertex/Foundry/Console-only deployments get no server-managed delivery and must use file/OS mechanisms.", "Denying the WebFetch tool does not block network access if Bash is allowed (curl/wget bypass it); permission rules and sandboxing operate on different layers.", "Cloud-provider deployments (Bedrock/Vertex/Foundry) lose access to Claude.ai-only features (web, Routines, Code Review, Remote Control, Chrome extension) and to the Anthropic-only Analytics dashboard and cost tracking — plan for supplementary Teams/Enterprise seats if needed.", "Advisor is Anthropic-API-only — silently unavailable on Bedrock/Vertex/Foundry, and via an LLM gateway it works only if the gateway forwards requests intact to the Anthropic API.", "An equal-or-weaker advisor is silently NOT attached to main-model requests (you only see it in /advisor output or a notification), so a misconfigured pairing fails open rather than erroring — except the --advisor flag, which errors if the main model is unsupported.", "Opus version gating is strict: an Opus 4.7 main with an Opus 4.6 advisor is rejected (advisor must be at or above the main model's version).", "Fable 5 main rejects Opus or Sonnet advisors — only Fable is accepted because it is a higher tier.", "Each advisor call reprocesses the entire transcript (no cross-call cache for the advisor's read), so advisor cost scales with conversation length and call count.", "The advisor is experimental; behavior, pricing, and availability may change.", "An active subscription PLUS ANTHROPIC_API_KEY set in the environment: the API key takes precedence once approved, so a disabled/expired-org key causes auth failures. Fix with 'unset ANTHROPIC_API_KEY'.", "In non-interactive mode (-p), ANTHROPIC_API_KEY is always used when present (no approval prompt), unlike interactive mode which asks once.", "Bare mode (--bare) silently does NOT read CLAUDE_CODE_OAUTH_TOKEN — scripts passing --bare must use ANTHROPIC_API_KEY or apiKeyHelper.", "Claude Desktop and cloud sessions ignore apiKeyHelper, ANTHROPIC_API_KEY, and ANTHROPIC_AUTH_TOKEN (OAuth only) — these only affect terminal CLI sessions.", "Claude Code on the Web ignores ANTHROPIC_API_KEY / ANTHROPIC_AUTH_TOKEN even in the sandbox; it always uses subscription credentials.", "CLAUDE_CODE_OAUTH_TOKEN is inference-only and cannot establish Remote Control sessions.", "Setting CLAUDE_CONFIG_DIR relocates .credentials.json (Linux/Windows) — back up / account for this when migrating or sharing config.", "A slow apiKeyHelper (>10s) degrades startup and shows a warning; an unoptimized credential script silently slows every session.", "Hallucination is usually a context problem, not a model problem — the fix is @-mentioning the relevant files, running /init, and supplying the actual error output, not rephrasing the prompt.", "Champions should NOT improvise security/data-handling answers; that policy is administrator-configured and must be referred to the admin.", "Page content is version-perishable: docs explicitly warn Claude Code updates frequently, so verify details against /en/overview before redistributing.", "This page is an adoption/advocacy playbook — it contains no managed-policy, permissions-precedence, or governance configuration details; those live on the linked Permissions, Security, and Memory pages.", "Page header warns all copy is DRAFT — rewrite in your org's voice and replace [bracketed placeholders] before sending; generic examples don't drive adoption.", "Claude can be confidently wrong — always review diffs and verify critical-path changes; treat it 'like a sharp junior, not an oracle'.", "On macOS, use Ctrl+V (not Cmd+V) to paste images from clipboard.", "Model mismatch wastes resources/quality: using Opus for a typo burns compute; using Haiku for a 12-file refactor invites a redo.", "Fable 5 is NOT the default and must be explicitly selected with /model fable; its cybersecurity/biology fallback to Opus is silent/automatic.", "'Can it see my whole repo?' — it only reads what you grant access to; reads outside the working directory trigger permission prompts.", "Claude Code ships frequently — verify version-specific details against the docs overview page before distributing internally.", "--dangerously-skip-permissions inside a dev container does NOT prevent a malicious project from exfiltrating anything in the container, including ~/.claude credentials. Use dev containers only with trusted repos and monitor activity.", "The feature version tag (:1.0) pins the install script, not the CLI — teams expecting a pinned Claude Code version from the tag will still get latest + auto-update unless they explicitly pin in the Dockerfile and disable the autoupdater.", "managed-settings.json delivered via Dockerfile is bypassable: anyone with repo write access can edit or delete the COPY step, so it is not a real policy enforcement boundary.", "Container home (including ~/.claude auth) is discarded on rebuild by default — without a volume mount engineers must sign in every rebuild. In Codespaces this also happens on rebuild even though state survives stop/start.", "--dangerously-skip-permissions is silently rejected when Claude Code runs as root; a root remoteUser will block unattended operation.", "Editors without dev container support (e.g. plain Vim) are not part of this workflow.", "Browser OAuth callback can fail to reach the container due to editor port forwarding; fall back to pasting the code manually.", "The /goal evaluator cannot call tools or independently read files/run commands — a condition phrased around state Claude never surfaces in the conversation can never be confirmed met, looping indefinitely until you /goal clear or Ctrl+C.", "On --resume/--continue an active goal is restored but the turn counter, timer, and token-spend baseline all reset, so any embedded 'stop after N turns' clause effectively restarts.", "/goal is silently gated by managed policy: disableAllHooks at any level, or allowManagedHooksOnly in managed settings, makes it unavailable (it does tell you why). Workspaces without an accepted trust dialog can't use it at all.", "The evaluator runs on the session's configured small fast model/provider (defaults to Haiku) — a weak or misconfigured small fast model degrades completion judgment for every goal turn.", "Homebrew and WinGet installs do NOT auto-update; only the native curl/irm install auto-updates — teams mixing install methods will silently run stale, potentially insecure versions.", "Homebrew `claude-code` cask is ~1 week behind stable and deliberately skips regression releases, so it lags `claude-code@latest`.", "On native Windows, missing Git for Windows causes Claude Code to fall back to PowerShell as the shell tool instead of Bash (behavior differs); WSL is unaffected.", "`claude --teleport` requires a claude.ai subscription — not available on all account types.", "This overview page is a navigation hub; actual team governance/permissions/managed-policy detail lives in linked pages (/en/settings, /en/memory, /en/hooks, /en/mcp), not here.", "Provider support is surface-dependent: Bedrock and Foundry are NOT supported on Desktop — you must use CLI or VS Code (or the Cowork 3P preview).", "Scripting and the Agent SDK (headless mode) are CLI-only — IDE extensions and Desktop trade these features for visual review.", "Computer use and Dispatch are gated to Pro and Max plans (and computer use is macOS-only).", "Slack integration runs on Anthropic cloud (not your machine) and requires Claude Code on the web to be enabled.", "Native installs auto-update in the background; Homebrew, WinGet installs do NOT auto-update and must be manually upgraded (brew upgrade claude-code / winget upgrade Anthropic.ClaudeCode).", "Homebrew has two casks with different update cadence: 'claude-code' = stable channel (~a week behind, skips major-regression releases); 'claude-code@latest' = latest channel (ships immediately).", "On native Windows without Git for Windows installed, Claude Code falls back to PowerShell instead of the Bash tool; install Git for Windows to get Bash. WSL does not need Git for Windows.", "Claude Code always asks permission before modifying files unless 'Accept all' mode is enabled for the session.", "claude -c continues conversations scoped to the current directory — directory context matters for resuming.", "minimumVersion only constrains updates — it does NOT prevent Claude Code from starting on an out-of-range version. Use requiredMinimumVersion/requiredMaximumVersion (managed) for startup gating.", "Homebrew/WinGet/apt/dnf/apk installs silently do not auto-update; teams on these methods can drift to old versions unless they opt in or run manual upgrades.", "Claude Code may notify of an update before the new version is actually available in Homebrew/WinGet/Linux repos; failed upgrades should be retried later.", "`npm update -g` may NOT move you to the newest release (it respects the original semver range); use `npm install -g @anthropic-ai/claude-code@latest`.", "DISABLE_AUTOUPDATER does not block `claude update`/`claude install`; only DISABLE_UPDATES blocks all manual update paths.", "On WinGet, in-place upgrades can fail because Windows locks the running executable; Claude Code falls back to showing the manual command.", "Homebrew keeps old versions on disk after upgrades — run `brew cleanup` to reclaim space.", "Removing ~/.claude wipes MCP server configs, allowed-tool permissions, and session history; the VS Code/JetBrains/Desktop integrations recreate ~/.claude if still installed, so a 'clean' uninstall requires removing those first.", "On Alpine/musl, the native installer needs libgcc/libstdc++/ripgrep AND USE_BUILTIN_RIPGREP=0, or search/startup fails.", "The free Claude.ai plan does not include Claude Code — provisioning a team requires Pro/Max/Team/Enterprise/Console or a third-party API provider.", "On cloud providers, unpinned model aliases fall back to Claude Code's built-in default, which can lag the newest release and may not even be enabled in your account — pin explicitly.", "Cloud-provider and Console deployments do NOT include Claude on the web; only Teams/Enterprise does.", "SSO, domain capture, role-based permissions, compliance API, and managed policy settings require the Enterprise plan — Teams does not include them.", "CLAUDE_CODE_SKIP_*_AUTH must only be set when the gateway actually handles provider auth; otherwise auth will be skipped incorrectly.", "Each cloud provider needs its own distinct region var: AWS_REGION (Bedrock), CLOUD_ML_REGION (Vertex), plus ANTHROPIC_VERTEX_PROJECT_ID / ANTHROPIC_FOUNDRY_RESOURCE — they are not interchangeable."], "claims": ["Managed settings take precedence over local developer (user and project) configuration.", "Claude Code checks four managed-settings sources in priority order and applies the first that returns a non-empty config. Priority order (highest to lowest): (1) Server-managed via Claude.ai admin console; (2) plist/registry policy — macOS `com.anthropic.claudecode` plist, Windows `HKLM\\SOFTWARE\\Policies\\ClaudeCode`; (3) File-based managed — macOS `/Library/Application Support/ClaudeCode/managed-settings.json`, Linux/WSL `/etc/claude-code/managed-settings.json`, Windows `C:\\Program Files\\ClaudeCode\\managed-settings.json`; (4) Windows user registry `HKCU\\SOFTWARE\\Policies\\ClaudeCode` (lowest, Windows only).", "Array settings such as `permissions.allow` and `permissions.deny` MERGE entries from all sources — developers can extend managed lists but cannot remove entries from them.", "Server-managed settings reach devices at authentication time and refresh hourly during active sessions, with no endpoint infrastructure. They require a Claude for Teams or Enterprise plan.", "Server-managed settings require a Claude for Teams or Enterprise plan; deployments on other providers (Bedrock/Vertex/Foundry/Console) must use file-based or OS-level (plist/registry) mechanisms instead.", "plist and HKLM registry locations work with any provider and resist tampering because they require admin privileges to write. The Windows user registry HKCU is writable without elevation — a convenience default, not an enforcement channel.", "By default WSL reads only the Linux file path `/etc/claude-code`. Set `wslInheritsWindowsSettings: true` in a Windows registry or `C:\\Program Files\\ClaudeCode` source to extend Windows policy to WSL on the same machine.", "Permission rule settings: `permissions.allow`, `permissions.deny` (allow, ask, or deny specific tools and commands).", "Permission lockdown settings: `allowManagedPermissionRulesOnly` (only managed permission rules apply) and `permissions.disableBypassPermissionsMode` (disables `--dangerously-skip-permissions`).", "Sandboxing settings: `sandbox.enabled` and `sandbox.network.allowedDomains` provide OS-level filesystem and network isolation with domain allowlists.", "MCP server control settings: `allowedMcpServers`, `deniedMcpServers`, `allowManagedMcpServersOnly`, or a deployed `managed-mcp.json` file — restrict which MCP servers users can add/connect to, or deploy a fixed set.", "Plugin marketplace control settings: `strictKnownMarketplaces` and `blockedMarketplaces` restrict which marketplace sources users can add and install from.", "`strictPluginOnlyCustomization` blocks skills, agents, hooks, and MCP servers from user and project sources, so they can only come from plugins or managed settings.", "Hook restriction settings: `allowManagedHooksOnly` (only managed hooks load) and `allowedHttpHookUrls` (restrict HTTP hook URLs).", "`disableAgentView` turns off `claude agents`, `--bg`, `/background`, and the on-demand supervisor.", "`minimumVersion` prevents auto-update from installing below an org-wide minimum (blocks downgrades only). `requiredMinimumVersion` and `requiredMaximumVersion` refuse to start when the running version is outside an org-approved range (stronger than `minimumVersion`).", "Org-wide CLAUDE.md (managed policy memory) is loaded in every session and cannot be excluded; deployed via a file at the managed policy path. See /en/memory#deploy-organization-wide-claude-md.", "Denying the WebFetch tool blocks Claude's fetch tool, but if Bash is allowed, `curl`/`wget` can still reach any URL — sandboxing with a network domain allowlist closes that gap at the OS level.", "Verify active managed settings: run `/status` inside Claude Code; the Status tab `Setting sources` line shows `Enterprise managed settings` followed by source in parentheses: `(remote)`, `(plist)`, `(HKLM)`, `(HKCU)`, or `(file)`.", "Usage monitoring via OpenTelemetry export (sessions, tools, tokens) is available on all providers. Analytics dashboard (per-user metrics, contribution tracking, leaderboard) and cost tracking (spend limits, rate limits, usage attribution) are Anthropic-only.", "Claude for Teams/Enterprise usage dashboard is at claude.ai/analytics/claude-code. Cloud-provider spend is via AWS Cost Explorer, GCP Billing, or Azure Cost Management.", "Some features require a Claude.ai account and are NOT available through Console API keys or cloud-provider credentials alone: Claude Code on the web, Routines, Code Review, Remote Control, and the Chrome extension.", "SSO, SCIM provisioning, and seat assignment are configured at the Claude account level (admin console), not via Claude Code settings.", "On Team, Enterprise, Claude API, and cloud-provider plans, Anthropic does not train models on your code or prompts. Zero Data Retention (ZDR) is available to qualified accounts on Claude for Enterprise.", "Login troubleshooting: `/logout` then `/login` to switch accounts; `claude update` if the enterprise auth option is missing; restart terminal after updating. 'You haven't been added to your organization yet' means the seat lacks Claude Code access.", "The advisor tool lets Claude consult a second, typically stronger model at key decision points; the advisor receives the full conversation (every tool call and result) and returns guidance Claude applies before continuing.", "The advisor is experimental and requires Claude Code v2.1.98 or later.", "Advisor works ONLY with the Anthropic API. It is NOT available on Amazon Bedrock, Google Vertex AI, or Microsoft Foundry. Available to both subscription and API-billed accounts.", "Through an LLM gateway configured with ANTHROPIC_BASE_URL, advisor availability depends on whether the gateway forwards the request intact to the Anthropic API.", "Three ways to enable: /advisor command (saves as default), advisorModel setting in settings file (persistent default), and --advisor flag (single session at launch).", "settings.json key: \"advisorModel\": \"opus\" (also accepts \"sonnet\", \"fable\", or a full model ID like claude-opus-4-8). Aliases resolve to the latest version of each model.", "Launch flag: claude --advisor opus. The flag takes precedence over the advisorModel setting for that session.", "--advisor flag exits with an error if the session's main model does not support the advisor; /advisor command instead saves an inactive selection that activates when you switch to a compatible main model via /model.", "The advisor must be at least as capable as the main model. Accepted advisors: Haiku 4.5 main -> Fable/Opus/Sonnet (Haiku cannot act as advisor); Sonnet 4.6 main -> Fable/Opus/Sonnet; Opus 4.6+ main -> Fable or Opus at-or-above the main's version (Opus 4.7 main with Opus 4.6 advisor is rejected); Fable 5 main -> Fable only (Opus/Sonnet advisor rejected).", "Fable 5 (as main OR advisor) requires Claude Code v2.1.170 or later plus Fable 5 access for the organization.", "Supported main models: Opus 4.6 or later, Sonnet 4.6, or Haiku 4.5 (Fable 5 also qualifies on v2.1.170+).", "Subagents inherit the configured advisor and apply the same pairing check against their own model. A subagent whose own model satisfies the pairing may still use the advisor even if the parent's main model does not.", "Pairing is validated before each request: if advisor is less capable than main, advisor is not attached (shown in /advisor output and a notification); if main or advisor is an unrecognized model, advisor is not attached.", "Claude decides when to call the advisor (model-driven, not rule-based); tends to consult before committing to an approach, when an error keeps recurring, and before declaring a task done.", "You can request a consultation in your prompt like any tool, e.g. 'consult the advisor before you continue'. There is no setting to cap or force advisor call frequency.", "During a call the transcript shows an 'Advising' line with the advisor model name; press Ctrl+O to expand and read the advisor's full guidance.", "Claude generally follows advisor guidance but surfaces conflicts rather than following unconditionally when a recommended step fails or file contents contradict the advice.", "Cost: each advisor call sends the full conversation to the advisor and consumes tokens at the advisor model's rates IN ADDITION to main model usage. API billing charges advisor input/output rates; subscription plans count advisor usage toward plan limits. Advisor usage counts toward /usage session totals.", "Enabling/disabling the advisor mid-session does NOT invalidate the main model's prompt cache (unlike changing model or effort level). The advisor's returned guidance is cached as part of the transcript on later turns.", "The advisor model's own read of the conversation is NOT cached; each advisor call reprocesses the full transcript anew with no reuse between calls.", "Turn off: /advisor off or choose 'No advisor' in the picker (clears saved advisorModel). Disable entirely (including /advisor command and --advisor flag): set env var CLAUDE_CODE_DISABLE_ADVISOR_TOOL=1.", "Run /advisor with no arguments to open a picker of available advisor models; pass directly e.g. /advisor opus.", "On Linux, credentials are stored in ~/.claude/.credentials.json with file mode 0600. On Windows: %USERPROFILE%\\.claude\\.credentials.json (inherits user-profile ACLs). On macOS: encrypted macOS Keychain.", "If CLAUDE_CONFIG_DIR is set (Linux/Windows), .credentials.json lives under that directory instead of ~/.claude.", "Claude Code manages .credentials.json only through /login and /logout. To route through a custom API endpoint, set ANTHROPIC_BASE_URL instead.", "Authentication precedence (highest to lowest): 1) Cloud provider creds when CLAUDE_CODE_USE_BEDROCK / CLAUDE_CODE_USE_VERTEX / CLAUDE_CODE_USE_FOUNDRY is set; 2) ANTHROPIC_AUTH_TOKEN (sent as Authorization: Bearer header, for LLM gateway/proxy); 3) ANTHROPIC_API_KEY (sent as X-Api-Key header, direct Anthropic API); 4) apiKeyHelper script output; 5) CLAUDE_CODE_OAUTH_TOKEN; 6) Subscription OAuth credentials from /login (default for Pro/Max/Team/Enterprise).", "apiKeyHelper setting runs a shell script that returns an API key. By default it is called after 5 minutes or on HTTP 401. Set CLAUDE_CODE_API_KEY_HELPER_TTL_MS env var for custom refresh interval.", "If apiKeyHelper takes longer than 10 seconds to return a key, Claude Code shows a warning notice in the prompt bar with elapsed time.", "apiKeyHelper, ANTHROPIC_API_KEY, and ANTHROPIC_AUTH_TOKEN apply to terminal CLI sessions only. Claude Desktop and cloud sessions use OAuth exclusively and ignore apiKeyHelper and API-key env vars.", "claude setup-token generates a one-year OAuth token for CI/scripts; walks through OAuth and prints the token (does not save it). Set it as CLAUDE_CODE_OAUTH_TOKEN. Requires Pro/Max/Team/Enterprise plan; scoped to inference only and cannot establish Remote Control sessions.", "Bare mode (--bare) does not read CLAUDE_CODE_OAUTH_TOKEN; use ANTHROPIC_API_KEY or apiKeyHelper instead when passing --bare.", "In interactive mode, ANTHROPIC_API_KEY prompts once to approve/decline and remembers the choice (toggle later via 'Use custom API key' in /config). In non-interactive mode (-p), the key is always used when present.", "Claude Code on the Web always uses subscription credentials; ANTHROPIC_API_KEY and ANTHROPIC_AUTH_TOKEN in the sandbox do not override them.", "Console role assignment: 'Claude Code' role lets users create only Claude Code API keys; 'Developer' role lets users create any kind of API key. Set when inviting users (Settings -> Members -> Invite).", "Supported auth types in credential management: Claude.ai credentials, Claude API credentials, Azure Auth, Bedrock Auth, Vertex Auth.", "Claude for Enterprise (vs Teams) adds SSO, domain capture, role-based permissions, compliance API, and managed policy settings for org-wide Claude Code configuration. Teams is self-service/smaller teams; Enterprise for larger orgs with security/compliance needs.", "setup-token / CLAUDE_CODE_OAUTH_TOKEN requires a Pro, Max, Team, or Enterprise plan.", "Cloud provider auth (Bedrock/Vertex/Foundry) needs no browser login — set the required environment variables before running claude.", "/logout logs out and lets you re-authenticate; /login manages login; /status confirms which auth method is active.", "Plan mode is entered by pressing Shift+Tab (cycle until you see 'plan'); it shows exactly which files will be touched before any edit and applies nothing until the user approves.", "/init generates a CLAUDE.md file from the repository.", "A team slash skill is created by saving a SKILL.md file at .claude/skills/<name>/SKILL.md, which becomes a /name command; skills are plain Markdown.", "/team-onboarding scans your recent sessions, commands, and MCP servers and produces a paste-able setup guide for a new teammate.", "@-mentioning a directory (e.g. @src/components/) is supported, not just @file references.", "A Stop hook can be configured to fire a desktop notification when a task completes (see Hooks guide).", "Claude Code runs in the terminal with no IDE extension required; install takes roughly two minutes.", "Security/data-handling answers should be referred to the org administrator — the deployment and data-handling policy is configured by the admin, not the individual user.", "Claude Code is updated frequently; verify version-specific details against the documentation home page before distributing material internally.", "MCP connectors are configured via a `.mcp.json` file at the project root; this wires Claude into GitHub, Jira, Linear, or other trackers.", "A SKILL.md file in `.claude/skills/<name>/` becomes a reusable slash command invoked by typing `/name`.", "`/init` reads the project and writes a CLAUDE.md with build commands, architecture, and conventions; run once per repo, and every future session in that repo loads it automatically.", "Shift+Tab cycles permission modes: `default` (asks before risky actions), `acceptEdits` (lets file edits and common filesystem commands flow but still checks other shell commands), and `plan` (proposes changes for approval before touching any file).", "File reads inside the working directory do not prompt; permission prompts gate edits, shell commands, and access to anything outside the working directory.", "`/rewind` rolls back to an earlier conversation point including the file changes made along the way; checkpointing is automatic with no setup. Open the rewind menu by pressing Esc twice or typing `/rewind`.", "Hooks are shell commands that fire on Claude Code events; e.g. a Stop hook can send a desktop notification when a task finishes.", "`/model` switches models mid-session; Fable 5 is opt-in only via `/model fable`.", "With Fable 5 selected, cybersecurity or biology content automatically falls back to Opus.", "`/plugin` browses and installs plugins in one step; skills are bundled and shared as plugins.", "`@` followed by a file path (or directory) pulls files directly into context; `@` then Tab triggers autocomplete of files in reach.", "Ctrl+V pastes images from clipboard into the terminal, including on macOS (use Ctrl+V, not Cmd+V); drag-and-drop of screenshots is also supported.", "Install command: `curl -fsSL https://claude.ai/install.sh | bash`, then `cd <your-repo>` and `claude`.", "Under an Enterprise agreement, Anthropic does not use your code or prompts to train its models.", "The CLI runs in the terminal and talks directly to Anthropic's API with no third-party servers; optional OS-level sandboxing is available for shell commands.", "Model recommendations: Sonnet is the recommended everyday default; Opus for large refactors/complex debugging/architecture/high-stakes; Haiku for quick questions/formatting/mechanical edits; Fable 5 for hardest, longest-running tasks (opt-in).", "Claude Code installs into a dev container via the Dev Container Feature: add \"ghcr.io/anthropics/devcontainer-features/claude-code:1.0\" to the \"features\" block in .devcontainer/devcontainer.json.", "The feature version tag (e.g. :1.0) pins the feature's install script, NOT the Claude Code release; the feature always installs the latest Claude Code, which auto-updates inside the container by default.", "In VS Code, both the Claude Code extension panel and running `claude` in the integrated terminal run inside the container and share the same ~/.claude configuration.", "By default the container home directory is discarded on rebuild, so engineers must re-authenticate. ~/.claude holds the auth token, user settings, and session history.", "To persist auth/settings across rebuilds, mount a named volume at ~/.claude, e.g. \"mounts\": [\"source=claude-code-config,target=/home/node/.claude,type=volume\"]; replace /home/node with the remoteUser home directory.", "If ~/.claude is mounted at a non-default path, set the CLAUDE_CONFIG_DIR env var to that path so Claude Code reads/writes there.", "Use source=claude-code-config-${devcontainerId} to isolate Claude state per project instead of sharing one volume across all repositories.", "In GitHub Codespaces, ~/.claude persists across stop/start but is cleared on container rebuild, so the volume mount still applies. To carry auth across codespaces, store ANTHROPIC_API_KEY or a CLAUDE_CODE_OAUTH_TOKEN (from `claude setup-token`) as a Codespaces secret; secrets become env vars in the container automatically.", "Claude Code reads /etc/claude-code/managed-settings.json on Linux and applies it at the HIGHEST precedence in the settings hierarchy, overriding ~/.claude and project .claude/ settings.", "managed-settings.json can be copied into the image via Dockerfile (RUN mkdir -p /etc/claude-code; COPY managed-settings.json /etc/claude-code/managed-settings.json), but anyone with repo write access can change/remove that step — for unbypassable policy use server-managed settings or MDM instead.", "Set per-session env vars for all container sessions via containerEnv in devcontainer.json, e.g. CLAUDE_CODE_DISABLE_NONESSENTIAL_TRAFFIC=1 (opt out of telemetry/error reporting) and DISABLE_AUTOUPDATER=1 (prevent auto-update).", "To pin a specific Claude Code version for reproducible builds, install from the Dockerfile with `npm install -g @anthropic-ai/claude-code@X.Y.Z` instead of the feature, and set DISABLE_AUTOUPDATER=1.", "Make MCP servers available in the container by defining them at project scope in a .mcp.json file at the repository root (checked in alongside dev container config). Install local stdio server binary dependencies in the Dockerfile, and add remote server domains to the network allowlist.", "--dangerously-skip-permissions is rejected when Claude Code is launched as root; confirm remoteUser is a non-root account to use it for unattended operation.", "To block --dangerously-skip-permissions entirely, set permissions.disableBypassPermissionsMode to \"disable\" in managed settings.", "The reference container adds NET_ADMIN and NET_RAW capabilities via runArgs to run init-firewall.sh, which blocks all outbound traffic except allowed domains; the firewall and those capabilities are optional for Claude Code itself.", "For cloud providers (Amazon Bedrock, Google Vertex AI, Microsoft Foundry) Claude Code uses cloud provider credentials with no browser prompt; pass credentials via containerEnv, a Codespaces secret, or workload identity rather than mounting host credential files.", "If browser sign-in completes but the localhost callback never reaches the container (port-forwarding issue), copy the code from the browser and paste it at the 'Paste code here if prompted' terminal prompt.", "The reference dev container (CLI + egress firewall + persistent volumes + Zsh shell) lives at anthropics/claude-code/.devcontainer and is a working example, not a maintained base image.", "/goal sets a session-scoped completion condition; after each turn a small fast model (defaults to Haiku) checks whether the condition holds, and if not Claude starts another turn instead of returning control. The goal clears automatically when met.", "/goal requires Claude Code v2.1.139 or later.", "Only one goal can be active per session; setting a new goal replaces the active one.", "Setting a goal starts a turn immediately with the condition as the directive — no separate prompt needed. A '◎ /goal active' indicator shows elapsed time.", "The condition can be up to 4,000 characters.", "/goal with no arguments shows status: condition, run duration, turns evaluated, current token spend, and the evaluator's most recent reason.", "/goal clear removes an active goal early; aliases accepted are stop, off, reset, none, cancel. Running /clear (new conversation) also removes any active goal.", "A goal still active when a session ends is restored on --resume or --continue; the condition carries over but turn count, timer, and token-spend baseline reset. Achieved or cleared goals are not restored.", "/goal works non-interactively (-p), in the desktop app, and through Remote Control. Example: claude -p \"/goal CHANGELOG.md has an entry for every PR merged this week\". Ctrl+C interrupts a non-interactive goal.", "/goal is implemented as a session-scoped prompt-based Stop hook. The evaluator runs on whichever provider the session is configured for and does NOT call tools — it can only judge what Claude already surfaced in the conversation.", "Evaluation tokens are billed on the small fast model configured for the provider and are typically negligible vs main-turn spend.", "/goal runs only in workspaces where the trust dialog has been accepted (the evaluator is part of the hooks system).", "/goal is unavailable when disableAllHooks is set at any settings level, or when allowManagedHooksOnly is set in managed settings; the command states why instead of failing silently.", "To compare session-continuation approaches: /goal starts the next turn when the previous finishes and stops when a model confirms the condition; /loop starts the next turn on a time interval; a Stop hook fires after every turn and stops per your own script/prompt. Auto mode approves tool calls within a turn but does not start a new turn.", "CLAUDE.md is a markdown file in the project root that Claude Code reads at the start of every session; used for coding standards, architecture decisions, preferred libraries, review checklists. Docs: /en/memory", "Auto memory: Claude builds memory as it works (e.g. build commands, debugging insights) saved across sessions without manual writing. Docs: /en/memory#auto-memory", "CLAUDE.md files, settings, and MCP servers work across all surfaces (Terminal, VS Code, JetBrains, Desktop, Web) because each connects to the same underlying engine.", "Skills package repeatable workflows a team can share, invoked as slash commands like /review-pr or /deploy-staging. Docs: /en/skills", "Hooks run shell commands before or after Claude Code actions (e.g. auto-format after every file edit, run lint before a commit). Docs: /en/hooks", "MCP (Model Context Protocol) connects Claude Code to external data sources (Google Drive, Jira, Slack, custom tooling). Docs: /en/mcp; setup: /en/mcp-quickstart", "Sub-agents: spawn multiple Claude Code agents working on different parts of a task simultaneously; a lead agent coordinates, assigns subtasks, merges results. Docs: /en/sub-agents", "Background agents run several full sessions in parallel viewable from one screen. Docs: /en/agent-view", "Headless/scriptable mode: `claude -p \"<prompt>\"` runs non-interactively; composable via Unix pipes (e.g. `tail -200 app.log | claude -p \"...\"`, `git diff main --name-only | claude -p \"review these...\"`). Full flags: /en/cli-reference", "CI automation for code review and issue triage via GitHub Actions (/en/github-actions) or GitLab CI/CD (/en/gitlab-ci-cd); automatic per-PR review via GitHub Code Review (/en/code-review).", "Routines run on Anthropic-managed infrastructure (keep running when computer is off) and can trigger on API calls or GitHub events; created from web, Desktop, or `/schedule` in CLI. Docs: /en/routines", "Desktop scheduled tasks run on your local machine with local file/tool access. `/loop` repeats a prompt within a CLI session for polling. Docs: /en/desktop-scheduled-tasks, /en/scheduled-tasks", "`claude --teleport` pulls a web/iOS-started task into the terminal; teleport requires a claude.ai subscription.", "Native install (curl https://claude.ai/install.sh | bash) auto-updates in the background; Homebrew, WinGet installs do NOT auto-update and must be upgraded manually.", "Homebrew cask `claude-code` tracks stable channel (~1 week behind, skips releases with major regressions); `claude-code@latest` tracks latest channel.", "Agent SDK lets you build custom agents with full control over orchestration, tool access, and permissions, powered by Claude Code's tools. Docs: /en/agent-sdk/overview", "Most surfaces require a Claude subscription or Anthropic Console account; Terminal CLI and VS Code also support third-party providers (/en/third-party-integrations).", "Full documentation index available at https://code.claude.com/docs/llms.txt for discovering all pages.", "Claude Code runs the same underlying engine across all surfaces: CLI, Desktop, VS Code, JetBrains, web, and mobile.", "Configuration, project memory, and MCP servers are shared across the local surfaces (CLI, Desktop, VS Code, JetBrains); you can mix surfaces on the same project.", "The CLI is the most complete surface: scripting and the Agent SDK (headless) are CLI-only.", "Computer use is available on macOS for Pro and Max plans (CLI and Desktop).", "Third-party providers work in CLI and VS Code. Enterprise Desktop deployments support Vertex AI and gateway providers; for Bedrock or Foundry use the CLI or VS Code (or the Cowork 3P research preview).", "Claude Code on the web runs in Anthropic's managed cloud and continues running after you disconnect.", "Mobile (iOS/Android Claude app) is a thin client into cloud sessions or into a local session via Remote Control; can dispatch tasks to Desktop (Pro and Max).", "Slack integration responds to @Claude mentions, runs on Anthropic cloud, and requires the Slack app installed with Claude Code on the web enabled.", "Remote Control is started by running 'claude remote-control' and lets you drive a running CLI or VS Code session from claude.ai/code or the mobile app.", "Channels push external events (Telegram, Discord, CI failures, custom server) into a local CLI session via a channel plugin.", "GitHub Actions and GitLab CI/CD run Claude in CI for automated PR reviews, issue triage, and scheduled maintenance; Code Review reviews every PR automatically.", "Scheduled tasks (recurring prompts) can run on CLI, Desktop, or cloud (routines).", "MCP servers and connectors let you connect external tools like Linear, Notion, Google Drive, or internal APIs.", "The complete documentation index is at https://code.claude.com/docs/llms.txt.", "claude -p \"query\" runs a one-off query then exits (non-interactive/print mode).", "claude -c continues the most recent conversation in the current directory; claude -r resumes a previous conversation.", "Inside a session, /clear clears conversation history, /resume continues a previous conversation, /login switches/re-authenticates accounts, /help lists commands.", "Typing / shows all commands and skills; Tab does command completion; ↑ shows command history; Shift+Tab cycles permission modes.", "Claude subscription tiers that support Claude Code: Pro, Max, Team, Enterprise; also Claude Console (pre-paid API credits) and cloud providers Amazon Bedrock, Google Vertex AI, Microsoft Foundry.", "On first Console login a 'Claude Code' workspace is auto-created in the Console for centralized cost tracking.", "Claude Code is available across interfaces: terminal CLI, web (claude.ai/code), desktop app, VS Code, JetBrains IDEs, Slack, and CI/CD via GitHub Actions and GitLab.", "Credentials are stored on the system after login (see /en/authentication Credential Management); no repeated login needed.", "autoUpdatesChannel setting controls auto-update channel: \"latest\" (default, new features immediately) or \"stable\" (typically ~1 week old, skips releases with major regressions). Set via /config -> Auto-update channel or settings.json.", "minimumVersion setting establishes an update floor: background auto-updates and `claude update` refuse to install any version below it, so switching to \"stable\" won't downgrade you below it. In managed settings it enforces an org-wide minimum that user/project settings cannot override.", "requiredMinimumVersion and requiredMaximumVersion are managed settings that make Claude Code REFUSE TO START outside the version range (minimumVersion only constrains updates, not startup). Updates also respect requiredMaximumVersion as a ceiling.", "Enterprise deployments can enforce a consistent release channel org-wide via managed settings (/en/permissions#managed-settings).", "DISABLE_AUTOUPDATER=\"1\" (in env key of settings.json) stops only the background update check; `claude update` and `claude install` still work. DISABLE_UPDATES blocks all update paths including manual updates.", "Native installations (curl/irm install scripts) auto-update in the background; updates download/install in background and take effect on next start. Homebrew, WinGet, apt, dnf, apk installs do NOT auto-update by default.", "CLAUDE_CODE_PACKAGE_MANAGER_AUTO_UPDATE=1 makes Claude Code run the Homebrew/WinGet upgrade command for you in the background; apt/dnf/apk still require manual upgrade (need elevated privileges).", "Homebrew offers two casks: `claude-code` (stable channel, ~1 week behind) and `claude-code@latest` (latest channel). Channel is chosen by cask name, not the autoUpdatesChannel setting.", "Settings precedence for version pinning: managed settings minimumVersion enforces org-wide minimum that user and project settings cannot override.", "System requirements: macOS 13.0+, Windows 10 1809+/Server 2019+, Ubuntu 20.04+, Debian 10+, Alpine 3.19+; 4 GB+ RAM; x64 or ARM64; internet connection required; available only in Anthropic-supported countries.", "Claude Code requires a Pro, Max, Team, Enterprise, or Console account. The free Claude.ai plan does NOT include Claude Code access. Third-party providers supported: Amazon Bedrock, Google Vertex AI, Microsoft Foundry.", "npm global install requires Node.js 18+; upgrade with `npm install -g @anthropic-ai/claude-code@latest`. Avoid `npm update -g` (respects original semver range, may not move to newest). Do NOT use `sudo npm install -g`.", "Config/state file locations: user settings/state in ~/.claude/ and ~/.claude.json; project settings in .claude/ and .mcp.json (project root).", "On native Windows, Git for Windows enables the Bash tool (Git Bash); without it Claude Code uses the PowerShell tool. Set CLAUDE_CODE_GIT_BASH_PATH in settings.json env if Git Bash path isn't found.", "CLAUDE_CODE_USE_POWERSHELL_TOOL=1 opts in / =0 opts out of the PowerShell tool (rolling out progressively when Git for Windows is installed).", "Sandboxing is supported on WSL 2 but NOT on native Windows or WSL 1.", "Alpine/musl distros: native installer requires libgcc, libstdc++, ripgrep installed via package manager, then set USE_BUILTIN_RIPGREP=0 in settings.json env.", "Release signing key GPG fingerprint: 31DD DE24 DDFA B679 F42D 7BD2 BAA9 29FF 1A7E CACE (security@anthropic.com). Each release has a signed manifest.json with SHA256 checksums; manifest signatures available from release 2.1.89 onward.", "Native installer accepts a version or channel: `curl -fsSL https://claude.ai/install.sh | bash -s stable` or `| bash -s 2.1.89`; channel chosen at install time becomes the default auto-update channel.", "`claude doctor` shows the result of the most recent update attempt and lists fixes (e.g., when npm global dir isn't writable for auto-update).", "Removing ~/.claude, ~/.claude.json, .claude/, .mcp.json deletes all settings, allowed tools, MCP server configs, and session history. VS Code extension, JetBrains plugin, and Desktop app also write to ~/.claude/ and recreate it if still installed.", "Organizations can deploy Claude Code via six paths: Claude for Teams/Enterprise (recommended), Anthropic Console, Amazon Bedrock, Claude Platform on AWS (AWS Marketplace billing), Google Vertex AI, and Microsoft Foundry.", "Claude for Teams is self-service with collaboration, admin, and billing management; Premium is $150/seat with PAYG available. Claude for Enterprise adds SSO + domain capture, role-based permissions, compliance API access, and managed policy settings for org-wide config (contact sales for pricing).", "Prompt caching is enabled by default across all deployment options (Teams/Enterprise, Console, Bedrock, Claude Platform on AWS, Vertex, Foundry).", "Authentication by provider: Teams/Enterprise = Claude.ai SSO or email; Console = API key; Bedrock = API key or AWS credentials; Claude Platform on AWS = API key or AWS credentials; Vertex = GCP credentials; Foundry = API key or Microsoft Entra ID.", "Only Teams/Enterprise includes Claude on web; the cloud-provider/Console paths do not.", "Corporate proxy is configured with HTTPS_PROXY or HTTP_PROXY env vars; routes all outbound traffic through an HTTP/HTTPS proxy. LLM gateway is a separate, combinable config.", "LLM gateway base-URL env vars: ANTHROPIC_BASE_URL (Anthropic API), ANTHROPIC_BEDROCK_BASE_URL, ANTHROPIC_AWS_BASE_URL, ANTHROPIC_VERTEX_BASE_URL, ANTHROPIC_FOUNDRY_BASE_URL.", "Amazon Bedrock setup env: CLAUDE_CODE_USE_BEDROCK=1, AWS_REGION (e.g. us-east-1); gateway adds ANTHROPIC_BEDROCK_BASE_URL and CLAUDE_CODE_SKIP_BEDROCK_AUTH=1 if the gateway handles AWS auth.", "Google Vertex AI setup env: CLAUDE_CODE_USE_VERTEX=1, CLOUD_ML_REGION (e.g. us-east5), ANTHROPIC_VERTEX_PROJECT_ID; gateway adds ANTHROPIC_VERTEX_BASE_URL and CLAUDE_CODE_SKIP_VERTEX_AUTH=1.", "Microsoft Foundry setup env: CLAUDE_CODE_USE_FOUNDRY=1, ANTHROPIC_FOUNDRY_RESOURCE, ANTHROPIC_FOUNDRY_API_KEY (omit for Entra ID auth); gateway adds ANTHROPIC_FOUNDRY_BASE_URL and CLAUDE_CODE_SKIP_FOUNDRY_AUTH=1.", "Env vars are set in shell or shell profile (.bashrc/.zshrc); /status verifies proxy and gateway configuration is applied correctly.", "Org-wide CLAUDE.md can be deployed to a system directory: on macOS, /Library/Application Support/ClaudeCode/CLAUDE.md, for company-wide standards.", "Cloud-provider model pinning uses ANTHROPIC_DEFAULT_FABLE_MODEL, ANTHROPIC_DEFAULT_OPUS_MODEL, ANTHROPIC_DEFAULT_SONNET_MODEL, ANTHROPIC_DEFAULT_HAIKU_MODEL; applies to Bedrock, Vertex, Foundry, and Claude Platform on AWS.", "Without model pinning, model aliases resolve to Claude Code's built-in default for that provider, which can lag the newest release and may not yet be enabled in your account.", "Security teams can configure managed permissions defining what Claude Code can/cannot do; these cannot be overwritten by local configuration.", "Documentation index for all pages is at https://code.claude.com/docs/llms.txt."]}, "Skills, hooks & commands": {"pages": ["commands", "hooks", "hooks-guide", "skills"], "bestPractices": ["First session in a repo: run `/init` to generate CLAUDE.md, `/memory` to refine it, `/mcp` and `/agents` to set up servers/subagents, and `/permissions` to set approval rules.", "Manage long conversations: use `/context` to see where the window is going, `/compact` to summarize it down, and `/btw` for asides that should not bloat history.", "Use `/compact` to free context while staying in the same conversation; use `/clear` to start a fresh task while keeping project memory.", "For team onboarding, run `/team-onboarding` to auto-generate a paste-ready setup guide (and share link) from your own 30-day usage history.", "Reduce repeated permission prompts across the team by running `/fewer-permission-prompts`, which writes an allowlist to project `.claude/settings.json` (shared, committable).", "For large codebase-wide changes, use `/batch` to parallelize into worktree-isolated subagents that each open a PR, rather than one serial pass.", "Before shipping, chain `/diff` → `/code-review` (or `/code-review ultra` for cloud multi-agent) → `/security-review`; use `/review [PR]` for read-only GitHub PR review.", "Tune cost/reasoning per task with `/model` and `/effort` (use session-only `s` in the model picker or `max`/`ultracode` effort to avoid changing defaults).", "When you add or change skills on disk mid-session, run `/reload-skills` rather than restarting; for plugins use `/reload-plugins` (add `--force` only if you accept invalidating the prompt cache).", "Commit team-standard hooks to .claude/settings.json (in-repo, shareable); keep personal/experimental hooks in ~/.claude/settings.json or gitignored .claude/settings.local.json so they don't impose on the team.", "Use exit code 2 (never exit 1) in hook scripts that must block a dangerous action; exit 0 with no JSON for normal flow.", "For hard policy enforcement (e.g. blocking rm -rf), rely on the permission system, not the if filter — the if filter fails open on unparseable commands.", "Treat all hook stdin JSON and tool outputs as untrusted: validate/sanitize before using in shell; never eval $(jq -r ...) directly.", "For org-wide governance, distribute vetted hooks via plugins in enabledPlugins plus allowManagedHooksOnly so only approved hooks run.", "Set explicit timeout on hooks that may run long (defaults are 600s command/http/mcp_tool, 30s prompt/UserPromptSubmit, 60s agent, 10s MessageDisplay).", "Use async:true for fire-and-forget side effects and asyncRewake:true for background monitors that should report back to Claude, so hooks don't stall the session.", "Persist environment for the session by appending export lines to $CLAUDE_ENV_FILE from a SessionStart hook rather than relying on per-command env.", "Use ${CLAUDE_PLUGIN_DATA} (not ${CLAUDE_PLUGIN_ROOT}) for plugin state that must survive updates, since the root path changes on update.", "Scope ephemeral hooks to skills/agents via frontmatter (with once:true where appropriate) instead of polluting global settings.", "Inspect effective hooks and their source with /hooks before debugging or onboarding teammates.", "For team-wide enforcement, put guardrail hooks (e.g. PreToolUse deny on dangerous commands or protected-file edits via exit 2) in managed policy settings — PreToolUse deny fires before permission-mode checks and cannot be bypassed by `--dangerously-skip-permissions` or bypassPermissions mode.", "Commit shareable team hooks to `.claude/settings.json` in the repo; keep machine-local hooks in `~/.claude/settings.json` and personal/gitignored ones in `.claude/settings.local.json`.", "Auto-format on edit: register a PostToolUse hook with matcher `Edit|Write` that extracts `.tool_input.file_path` via jq and runs the formatter (e.g. prettier --write).", "Re-inject critical context after compaction with a SessionStart hook using the `compact` matcher writing reminders to stdout; for every-session context prefer CLAUDE.md instead.", "Audit/compliance: use a ConfigChange hook to append config-file changes to an audit log, and/or a PostToolUse Bash hook (or a once-per-turn Stop hook scanning `git status --porcelain`) so file changes made via Bash are not missed.", "Keep PermissionRequest auto-approve matchers as narrow as possible (e.g. `ExitPlanMode`); matching `.*` or empty auto-approves every prompt including file writes and shell commands.", "Use the `if` field (v2.1.85+) to spawn a hook process only for specific argument shapes (e.g. `Bash(git *)`) instead of every Bash call, reducing overhead.", "Use prompt hooks (`type: prompt`) when the hook input alone suffices for a yes/no judgment; use agent hooks only when verification must inspect actual codebase/files (e.g. run the test suite before a Stop).", "Write hook diagnostics to stderr (not stdout) so stdout stays clean for JSON output and the message lands in the debug log.", "Use exec form by adding `\"args\": []` to spawn the script directly without a shell, avoiding shell quoting and profile-sourcing problems.", "For a Stop hook that may loop, always check `stop_hook_active` and exit 0 when true to avoid hitting the 8-block cap.", "Centralize team audit logic in an HTTP hook (`type: http`) pointing at a shared service, passing the token via `allowedEnvVars` rather than hardcoding secrets.", "Distribute skills by scope: commit .claude/skills/ to version control for project skills; bundle a skills/ directory in a plugin for cross-project; deploy org-wide via managed settings.", "Keep the SKILL.md body concise and under 500 lines — once invoked it stays in context across turns, so every line is a recurring token cost. State what to do, not how/why.", "Move large reference docs, API specs, and examples into separate supporting files and reference them from SKILL.md, so they load only when needed instead of every invocation.", "Write the description with keywords users would naturally say, and put the key use case first (combined description + when_to_use capped at 1,536 chars).", "Use disable-model-invocation:true for side-effecting workflows (/commit, /deploy, /send-slack-message) so Claude can't trigger them on its own; use user-invocable:false for background knowledge that isn't a meaningful user action.", "Review project skills before accepting the workspace trust dialog — a checked-in skill's allowed-tools can grant itself broad tool access.", "Use ${CLAUDE_SKILL_DIR} for script paths in bundled scripts so they resolve at personal/project/plugin level regardless of cwd.", "Set disableSkillShellExecution:true and disableBundledSkills in managed settings to govern teams; managed/bundled skills bypass the shell-execution lockdown, users can't override managed settings.", "Evaluate skills with a baseline comparison: run realistic prompts in fresh sessions with the skill enabled vs disabled (via skillOverrides off) — checking both that it triggers and that output is correct. Use the skill-creator plugin to automate the loop (evals.json, grading.json, benchmark.json).", "If a skill stops influencing behavior mid-session, the content is usually still present — strengthen the description/instructions, use hooks for deterministic enforcement, or re-invoke it after compaction to restore full content.", "Run /doctor to see how many skill descriptions are being shortened or dropped; free budget by setting low-priority skills to name-only in skillOverrides, or raise skillListingBudgetFraction.", "Run /run-skill-generator once per project (and again when build/launch changes) to record a reusable launch recipe at .claude/skills/run-<name>/ so /run and /verify and other agents stop rediscovering it.", "For forked skills (context:fork) that should run cheaply on read-only exploration, use agent: Explore so they skip CLAUDE.md and git status."], "gotchas": ["`/add-dir` grants file access to an extra directory but does NOT load that directory's `.claude/` configuration — config is not discovered from added directories.", "Switching `/model` mid-conversation (when there is prior output) re-reads full history WITHOUT cached context, which costs tokens; the picker confirms before doing this.", "`/reload-plugins` silently skips reloading when the change would alter loaded MCP tools and invalidate the prompt cache — you must pass `--force` to apply it.", "Effort levels `max` and `ultracode` are session-only and do not persist as a default.", "`/cd` requires v2.1.169+; on earlier versions it errors with `Unknown command: /cd`. Several commands are version-gated (e.g. `/run`,`/verify`,`/simplify`,`/fork`).", "Command availability is conditional on platform/plan/environment, so a command documented here may not appear in every user's `/` menu (e.g. Bedrock/Vertex setup wizards only show with their env var set).", "`/debug` only starts capturing logs from the point it is run mid-session (full-session debug requires launching with `claude --debug`).", "Exit code 1 does NOT block — it is non-blocking like any other non-2 code; only exit 2 blocks. A common mistake is using exit 1 to enforce policy.", "The if filter fails open: on commands it can't parse, the hook runs anyway — do not treat it as a security boundary.", "On exit 0, plain (non-JSON) stdout is only added as context for SessionStart; for other events plain stdout is not used as context.", "Exit 2 is non-blocking on PostToolUse/PostToolUseFailure/PermissionDenied/StopFailure/SessionStart/Setup/SessionEnd because the action already happened — you cannot block after the fact.", "Hook event names are case-sensitive and must match exactly (PreToolUse, not preToolUse).", "${CLAUDE_PLUGIN_ROOT} changes on every plugin update, so hardcoding paths/state under it breaks across updates.", "HTTP hook env var interpolation silently won't work unless the var is listed in allowedEnvVars.", "Managed-policy hooks cannot be turned off by user/project disableAllHooks — only managed-level disableAllHooks works.", "For subagents, Stop hooks silently auto-convert to SubagentStop, so a plain Stop hook won't fire as expected inside a subagent.", "terminalSequence only allows specific OSC sequences (0,1,2,9,99,777,BEL); CSI, OSC 8 hyperlinks, OSC 52 clipboard, OSC 1337 are blocked.", "PreToolUse exit 0 does NOT approve the tool call — the normal permission flow still runs. Only a JSON `permissionDecision: allow` skips the interactive prompt (and even that respects deny/ask rules).", "Hook `allow` cannot override deny rules from any settings scope (including managed settings); hooks tighten but never loosen permissions.", "Sibling hooks all run even if one returns deny — do not rely on a deny to suppress another hook's side effects (e.g. the log still gets written).", "Mixing exit 2 with JSON output silently fails: Claude Code ignores the JSON when the hook exits 2.", "Parallel PreToolUse hooks with `updatedInput` race — last to finish wins non-deterministically; never have two hooks rewrite the same tool's input.", "Stop hooks fire whenever Claude finishes responding, not only at task completion; they don't fire on user interrupts, and API errors fire StopFailure instead.", "A shell profile (~/.bashrc, ~/.zshrc, or BASH_ENV) that prints unconditional output prepends garbage to the hook's stdout, breaking JSON parsing — guard echoes with `if [[ $- == *i* ]]`.", "Matchers are case-sensitive; a mismatched-case tool name silently never fires.", "PermissionRequest hooks do not fire in `-p` non-interactive mode — automated permission logic must use PreToolUse instead.", "The `if` field filter fails open (runs the hook anyway) when a Bash command can't be parsed, so it is best-effort, not a security control — enforce hard allow/deny via the permission system.", "Adding the `if` field to a non-tool event prevents the hook from running at all.", "The `if` field is ignored by Claude Code versions before v2.1.85 (the hook runs on every matched call).", "FileChanged matcher values are split into literal filenames, not evaluated as regex (unlike tool-name matchers).", "Hooks that only match file-editing tools miss files changed via Bash; add a Bash matcher or a Stop-hook tree scan for full coverage.", "`disableAllHooks: true` in user/project settings does not stop hooks defined in managed settings unless disableAllHooks is also set there.", "If `/hooks` shows no hooks after editing settings, the file watcher may have missed the change — restart the session; also check for invalid JSON (trailing commas/comments not allowed) and correct file location.", "macOS osascript notifications fail silently if Script Editor lacks notification permission.", "The command name comes from the DIRECTORY name, not the frontmatter `name` field — `name` only changes the display label (except plugin-root SKILL.md). Renaming `name` won't change what you type.", "disable-model-invocation:true removes the skill's description from context entirely (Claude can't see it at all), AND blocks preloading into subagents — it's not just a soft preference.", "user-invocable:false only controls / menu visibility, NOT Skill-tool access; to block programmatic invocation you must use disable-model-invocation:true.", "Claude does NOT re-read the SKILL.md on later turns; one-time step language can be ignored. After compaction only the first 5,000 tokens per skill survive (25k combined budget), so large skills can lose their tail or be dropped.", "Skill descriptions can be silently shortened/dropped when you have many skills (budget = 1% of context), stripping the keywords Claude needs to match — a likely cause of a skill not triggering.", "permissions.additionalDirectories in settings.json does NOT load skills (only --add-dir / /add-dir does); easy to assume it would.", "Creating a brand-new top-level skills directory mid-session won't be watched until you restart Claude Code; only edits to already-watched dirs are picked up live.", "Malformed frontmatter YAML loads the skill body with EMPTY metadata: /skill-name still works but Claude has no description to auto-match. Use --debug to see the parse error.", "!`command` injection only fires when ! is at line start or after whitespace; KEY=!`cmd` is left as literal text and does not run. Output is inserted as plain text and not re-scanned for further placeholders.", "context:fork only makes sense for skills with an explicit task; a guidelines-only skill gives the subagent no actionable prompt and it returns nothing useful.", "Seeing a skill trigger only proves Claude found it, not that the output is correct — measure invocation accuracy and output quality separately.", "CLAUDE.md from --add-dir directories is not loaded unless CLAUDE_CODE_ADDITIONAL_DIRECTORIES_CLAUDE_MD=1 is set."], "claims": ["A slash command is only recognized at the start of a message; text after the command name is passed to it as arguments. Type `/` to list all available commands, or `/`+letters to filter.", "In the command table, `<arg>` indicates a required argument and `[arg]` an optional one. Not every command appears for every user — availability depends on platform, plan, and environment (e.g. `/desktop` only on macOS/Windows with subscription; `/upgrade` only on Pro/Max).", "`/init` generates a starter CLAUDE.md; set env `CLAUDE_CODE_NEW_INIT=1` for an interactive flow that also walks through skills, hooks, and personal memory files.", "`/memory` edits CLAUDE.md memory files, enables/disables auto-memory, and views auto-memory entries.", "`/permissions` (alias `/allowed-tools`) manages allow/ask/deny tool-permission rules in an interactive dialog: view rules by scope, add/remove rules, manage working directories, review recent auto-mode denials.", "`/mcp` manages MCP server connections and OAuth. Syntax: `/mcp [reconnect <server> | enable | disable [<server>|all]]`. No arg opens interactive list; `reconnect <server>` reconnects one disconnected server; `enable`/`disable` with a server name or `all` changes state without a dialog.", "MCP servers can expose prompts that appear as commands using the format `/mcp__<server>__<prompt>`, dynamically discovered from connected servers.", "`/plugin [subcommand]` manages plugins; subcommands include `list`, `install`, `enable`, `disable`. `/reload-plugins [--force]` reloads active plugins without restart; when the reload would change which MCP tools are loaded and invalidate the prompt cache it warns and skips unless `--force` is passed.", "`/reload-skills` (added v2.1.152) re-scans skill and command directories so skills added/changed on disk during a session become available without restarting.", "`/skills` lists available skills; press `t` to sort by token count, press `Space` to hide a skill from Claude or the `/` menu, then `Enter` to save.", "`/hooks` views hook configurations for tool events. `/agents` manages subagent configurations.", "`/context [all]` visualizes current context usage as a colored grid, showing optimization suggestions for context-heavy tools, memory bloat, and capacity warnings. `all` expands the per-item breakdown (collapsed by default in fullscreen).", "`/compact [instructions]` frees up context by summarizing the conversation; optional focus instructions. `/clear [name]` (aliases `/reset`,`/new`) starts a new conversation with empty context while keeping the previous in `/resume`. Use `/compact` to free context while continuing the same conversation; `/clear` for a new task.", "`/btw <question>` asks a quick side question without adding it to the conversation history.", "`/model [model]` switches model and saves it as default for new sessions; no arg opens a picker, press `s` on a row to switch for the current session only. The picker confirms when the conversation has prior output since the next response re-reads full history without cached context.", "`/effort [level|auto]` sets model effort: `low`,`medium`,`high`,`xhigh`,`max`,`ultracode`; `max` and `ultracode` are session-only. `ultracode` combines xhigh reasoning with automatic workflow orchestration. `auto` resets to model default. Takes effect immediately.", "`/config [key=value ...]` opens Settings or (from v2.1.181) sets settings directly, e.g. `/config thinking=false`; from v2.1.182 named shorthand keys like `/config theme=dark`, `/config model=sonnet`. The key=value form works in non-interactive mode (`-p`) and from Remote Control. `/config --help` lists every settable key. Alias `/settings`.", "`/usage` (aliases `/cost`,`/stats`) shows session cost, plan usage limits, and activity stats; on Pro/Max/Team/Enterprise includes a breakdown of usage by skill, subagent, plugin, and MCP server.", "`/code-review [low|medium|high|xhigh|max|ultra] [--fix] [--comment] [target]` reviews the current diff for correctness bugs and cleanups; `--fix` applies findings to working tree, `--comment` posts inline GitHub PR comments, `ultra` runs a deep cloud review (`/code-review ultra`). `/review [PR]` runs the same engine read-only on a GitHub PR. `/security-review` analyzes pending branch changes for security vulnerabilities.", "`/simplify [target]` (v2.1.154+) runs four review agents in parallel (reuse, simplification, efficiency, abstraction level) and applies fixes WITHOUT looking for correctness bugs; on earlier versions it equals `/code-review --fix`.", "`/batch <instruction>` (Skill) decomposes a large codebase change into 5-30 independent units and spawns one background subagent per unit in an isolated git worktree; each implements, tests, and opens a PR. Requires a git repository.", "`/fork <directive>` (v2.1.161+) spawns a forked background subagent inheriting the full conversation whose result returns when finished; `/branch [name]` switches you into a copy of the conversation. Before v2.1.161 `/fork` is an alias for `/branch`.", "`/add-dir <path>` adds a working directory for file access during the session, but most `.claude/` configuration is NOT discovered from the added directory.", "`/cd <path>` (v2.1.169+) moves the session to a new working directory; prompt cache is preserved (new dir CLAUDE.md is appended as a message instead of rebuilding the system prompt); session is relocated to the new dir's project storage. Restrict/disable targets with `Cd` permission rules. Earlier versions report `Unknown command: /cd`.", "`/team-onboarding` generates a team onboarding guide from the past 30 days of sessions, commands, and MCP server usage, as markdown a teammate can paste as a first message; claude.ai Pro/Max/Team/Enterprise subscribers also get a share link openable directly in Claude Code.", "`/fewer-permission-prompts` (Skill) scans transcripts for common read-only Bash and MCP tool calls and adds a prioritized allowlist to project `.claude/settings.json` to reduce permission prompts.", "`/goal [condition|clear]` sets a goal Claude keeps working toward across turns until met. `/plan [description]` enters plan mode directly. `/rewind` (aliases `/checkpoint`,`/undo`) rewinds conversation and/or code to a checkpoint.", "`/insights` generates a report analyzing sessions (project areas, interaction patterns, friction points). `/doctor` diagnoses installation and settings (press `f` to have Claude fix issues). `/debug [description]` enables debug logging mid-session (off by default unless started with `claude --debug`).", "`/privacy-settings` is only available for Pro and Max plan subscribers. `/passes` (share a free week) only visible if the account is eligible. `/ultrareview` includes 3 free runs on Pro/Max then requires usage credits.", "`/pr-comments` was removed in v2.1.91 (ask Claude directly to view PR comments). `/vim` was removed in v2.1.92 (use /config → Editor mode).", "Hook settings resolve in order user (~/.claude/settings.json) → project (.claude/settings.json) → local (.claude/settings.local.json) → managed policy; later layers override earlier.", ".claude/settings.json is the shareable team-standard location (commit to repo); .claude/settings.local.json is gitignored local overrides; ~/.claude/settings.json is personal/all-projects and not shareable.", "Admins can set allowManagedHooksOnly to block user, project, and plugin hooks; hooks from plugins listed in enabledPlugins bypass this restriction.", "Managed-policy hooks cannot be disabled by user/project settings; only a managed-level disableAllHooks:true can disable them.", "disableAllHooks:true turns off all hooks, respecting the precedence hierarchy (managed-level cannot be overridden by user/project).", "Exit code 0 = success: stdout JSON is parsed for decisions (plain stdout is added as context only on SessionStart). Exit code 2 = blocking error: stdout/JSON ignored, stderr used as error message, action blocked per event. Any other exit code (including 1) = non-blocking error: execution continues, first line of stderr shown in transcript.", "Exit code 1 is NON-blocking (proceeds). You must use exit code 2 to enforce policy/block an action.", "Exit 2 blocks on PreToolUse, PermissionRequest, UserPromptSubmit, UserPromptExpansion, Stop, SubagentStop, TeammateIdle, TaskCreated, TaskCompleted, ConfigChange, PreCompact, and WorktreeCreate. It is non-blocking (stderr shown only) on PostToolUse, PostToolUseFailure, PermissionDenied, StopFailure, SessionStart, Setup, SessionEnd.", "PreToolUse, PostToolUse, PostToolUseFailure, PermissionRequest, PermissionDenied match against tool name. MCP tools are named mcp__<server>__<tool>; match e.g. mcp__memory__.* or mcp__.*__write.*", "Matcher syntax: \"*\"/\"\"/omitted matches all; a value with only letters, digits, _, and | is exact string or pipe-separated list (e.g. Bash, Edit|Write); any other character makes it a JavaScript regex (e.g. ^Notebook, mcp__memory__.*).", "Five hook handler types: command (shell script, JSON on stdin), http (POST to endpoint), mcp_tool (call tool on connected MCP server), prompt (single-turn yes/no model eval), and agent (experimental subagent with tool access).", "Command hook: shell form (no args field) supports pipes/&&/globs; exec form (args present) spawns directly with no shell tokenization. async:true is fire-and-forget; asyncRewake:true runs in background and wakes Claude on exit 2 (stderr/stdout shown as system reminder on next model request).", "HTTP hook env var interpolation in headers requires listing the var in allowedEnvVars (e.g. \"allowedEnvVars\": [\"MY_TOKEN\"]).", "Default hook timeouts: 600s for command/http/mcp_tool, 30s for prompt, 60s for agent. UserPromptSubmit lowers command/http/mcp_tool to 30s; MessageDisplay to 10s. Override per-hook with the timeout field (seconds).", "The if field (tool events only) filters hook execution using permission-rule syntax e.g. \"Bash(git *)\", \"Edit(*.ts)\". It checks each subcommand and $() internals, strips FOO=bar assignments, but FAILS OPEN on unparseable commands (hook runs anyway).", "JSON output control fields (exit 0): continue (false stops Claude), stopReason, suppressOutput, systemMessage, terminalSequence, decision, reason, and hookSpecificOutput (with hookEventName, additionalContext, permissionDecision, updatedInput, updatedToolOutput, sessionTitle, watchPaths, reloadSkills, action, content).", "PreToolUse can deny via hookSpecificOutput.permissionDecision:\"deny\" with permissionDecisionReason; PermissionRequest can auto-approve and rewrite args via decision.behavior:\"allow\" + updatedInput; PostToolUse can rewrite results via updatedToolOutput and inject additionalContext.", "Path placeholders usable in command/args: ${CLAUDE_PROJECT_DIR} (project root), ${CLAUDE_PLUGIN_ROOT} (plugin dir, changes on update), ${CLAUDE_PLUGIN_DATA} (persistent plugin data dir, survives updates).", "Env vars set for hooks: CLAUDE_PROJECT_DIR (all), CLAUDE_PLUGIN_ROOT/CLAUDE_PLUGIN_DATA (plugin hooks), CLAUDE_ENV_FILE (SessionStart/Setup/CwdChanged/FileChanged — append export statements to persist env for Bash), CLAUDE_EFFORT (tool-context hooks: low/medium/high/xhigh/max), CLAUDE_CODE_REMOTE (\"true\" in web, unset in CLI).", "Every hook receives stdin JSON with session_id, transcript_path, cwd, permission_mode, hook_event_name; tool events also include effort.level; subagent context adds agent_id and agent_type.", "Hooks can be defined in skill/agent frontmatter under a hooks: key, scoped to the component lifecycle; the once:true field (frontmatter only) runs a hook once per session then removes it. For subagents, Stop hooks auto-convert to SubagentStop.", "Plugins ship hooks in hooks/hooks.json bundled with the plugin and active when enabled.", "The /hooks command opens a read-only browser listing all configured hooks by event with source (User, Project, Local, Plugin, Session, Built-in) and full details.", "allowManagedHooksOnly and managed-policy hook governance (force-enabling vetted plugin hooks via enabledPlugins) are enterprise/admin (managed settings) features.", "Reference reflects hooks v2.1.139+ (terminalSequence added v2.1.141+) with 30+ events, effort levels, and full MCP tool integration.", "Hooks are configured in a `hooks` block inside a settings file. Each hook event name is a key inside the single `hooks` object; multiple events are siblings, not separate hooks objects.", "Hook config scope by location: `~/.claude/settings.json` = all your projects (not shareable); `.claude/settings.json` = single project (committable/shareable); `.claude/settings.local.json` = single project (gitignored, not shareable); managed policy settings = organization-wide (admin-controlled, shareable); plugin `hooks/hooks.json` = active when plugin enabled (shareable); skill/agent frontmatter = active while skill/agent active (shareable).", "A hook entry has a `matcher` and a `hooks` array; each item has `type` (default `command`) and `command`. Other types: `http` (POST to URL), `mcp_tool` (call connected MCP server tool), `prompt` (single-turn LLM eval, Haiku by default), `agent` (multi-turn verification with tool access; experimental).", "Hook exit codes: exit 0 = no objection, action proceeds normally (does NOT auto-approve a PreToolUse call; normal permission flow still applies); exit 2 = block the action, stderr is fed back to Claude as feedback; any other exit code = action proceeds, transcript shows `<hook name> hook error` + first stderr line, full stderr to debug log.", "For UserPromptSubmit, UserPromptExpansion, and SessionStart hooks, stdout (exit 0) is added to Claude's context.", "exit 2 cannot block all events: for SessionStart, Setup, Notification, and others, exit 2 only shows stderr to the user and execution continues.", "Structured JSON output: exit 0 and print JSON to stdout for fine control. Do NOT mix exit 2 with JSON — Claude Code ignores JSON when you exit 2.", "PreToolUse permissionDecision values: `allow` (skip interactive prompt, but deny/ask rules including managed deny lists still apply), `deny` (cancel + send reason to Claude), `ask` (show prompt), `defer` (only in `-p` non-interactive mode, preserves tool call for Agent SDK resume).", "Deny rules from any settings scope, including managed settings, always take precedence over hook `allow`. Hooks can tighten restrictions but cannot loosen past what permission rules allow.", "PreToolUse hooks fire BEFORE any permission-mode check. A hook returning `permissionDecision: deny` blocks the tool even in `bypassPermissions` mode or with `--dangerously-skip-permissions` — enforces policy users cannot bypass by changing permission mode.", "When multiple hooks match one event, all run in parallel to completion, then results merge. Identical hook commands are auto-deduplicated. For PreToolUse permission decisions the most restrictive wins, order: deny > defer > ask > allow. `additionalContext` text is kept from every hook.", "One hook returning `deny` does NOT stop sibling hooks from executing; do not rely on a deny to suppress another hook's side effects.", "Hook events include: SessionStart, Setup, UserPromptSubmit, UserPromptExpansion, PreToolUse, PermissionRequest, PermissionDenied, PostToolUse, PostToolUseFailure, PostToolBatch, Notification, MessageDisplay, SubagentStart, SubagentStop, TaskCreated, TaskCompleted, Stop, StopFailure, TeammateIdle, InstructionsLoaded, ConfigChange, CwdChanged, FileChanged, WorktreeCreate, WorktreeRemove, PreCompact, PostCompact, Elicitation, ElicitationResult, SessionEnd.", "ConfigChange event fires when a config file changes during a session; matcher filters by source: `user_settings`, `project_settings`, `local_settings`, `policy_settings`, `skills`. Block a change with exit code 2 or `{\"decision\": \"block\"}` — usable for compliance audit logging.", "InstructionsLoaded fires when a CLAUDE.md or `.claude/rules/*.md` file is loaded into context (at session start and on lazy load); matcher values: session_start, nested_traversal, path_glob_match, include, compact.", "Matchers filter different fields per event: tool name for PreToolUse/PostToolUse/PostToolUseFailure/PermissionRequest/PermissionDenied (e.g. `Bash`, `Edit|Write`, `mcp__.*`); SessionStart on startup/resume/clear/compact; PreCompact/PostCompact on manual/auto. UserPromptSubmit, PostToolBatch, Stop, CwdChanged, and several others have no matcher support and always fire.", "Matchers are case-sensitive. An empty/absent matcher fires on every occurrence of the event.", "MCP tools are named `mcp__<server>__<tool>` (e.g. `mcp__github__search_repositories`). Match a server with regex like `mcp__github__.*` or cross-server with `mcp__.*__write.*`.", "The `if` field (requires Claude Code v2.1.85+) filters hooks by tool name AND arguments using permission-rule syntax (e.g. `Bash(git *)`, `Edit(*.ts)`); only spawns the hook process on match. Works only on tool events (PreToolUse, PostToolUse, PostToolUseFailure, PermissionRequest, PermissionDenied) — adding it to other events prevents the hook running. It checks subcommands inside `$()`/backticks and fails open (runs anyway) when the command can't be parsed, so use the permission system for hard allow/deny.", "`$CLAUDE_PROJECT_DIR` env var references the project root in hook commands (e.g. `\"$CLAUDE_PROJECT_DIR\"/.claude/hooks/script.sh`). `CLAUDE_ENV_FILE` is a file Claude Code runs as a script preamble before each Bash command — write env exports to it (used with direnv via SessionStart + CwdChanged).", "Hook scripts must be executable (`chmod +x`) on macOS/Linux or Claude Code won't run them.", "Hook timeouts by type: command/http/mcp_tool = 10 minutes (lowered to 30s for UserPromptSubmit, 10s for MessageDisplay); prompt = 30s; agent = 60s. Override per hook with the `timeout` field (seconds). Agent hooks allow up to 50 tool-use turns.", "`/hooks` menu is read-only (browse only); to add/modify/remove hooks edit settings JSON directly or ask Claude. Disable all hooks with `\"disableAllHooks\": true` — hooks in managed settings still run unless disableAllHooks is also set there.", "Stop hook block cap: Claude Code overrides a Stop hook after it blocks 8 times in a row without progress. Hook scripts should parse `stop_hook_active` from JSON input and exit 0 if true. Raise cap with env var `CLAUDE_CODE_STOP_HOOK_BLOCK_CAP`.", "Hook input arrives as JSON on stdin with common fields `session_id`, `cwd`, `hook_event_name`, plus event-specific data (e.g. PreToolUse adds `tool_name`, `tool_input`; UserPromptSubmit adds `prompt`; SessionStart adds `source`).", "HTTP hooks (`type: http`) POST the same JSON to a `url`; block via a 2xx response body with `hookSpecificOutput` (HTTP status codes alone cannot block). Header values support `$VAR`/`${VAR}` interpolation but only for vars listed in `allowedEnvVars`; all other `$VAR` references are empty.", "PermissionRequest hooks do NOT fire in non-interactive `-p` mode — use PreToolUse hooks for automated permission decisions there. PostToolUse hooks cannot undo actions (tool already executed).", "When multiple PreToolUse hooks return `updatedInput` to rewrite tool args, the last to finish wins; since hooks run in parallel the order is non-deterministic — avoid more than one hook modifying the same tool's input.", "`bypassPermissions` mode from a PermissionRequest hook's `setMode` only applies if the session was launched with bypass available (`--dangerously-skip-permissions`, `--permission-mode bypassPermissions`, `--allow-dangerously-skip-permissions`, or `permissions.defaultMode: bypassPermissions`) and not disabled by `permissions.disableBypassPermissionsMode`. It is never persisted as defaultMode.", "Skill file locations and applicability: Enterprise (managed settings) = all org users; Personal = ~/.claude/skills/<name>/SKILL.md = all your projects; Project = .claude/skills/<name>/SKILL.md = this project only; Plugin = <plugin>/skills/<name>/SKILL.md = where plugin enabled.", "Precedence for same-named skills across levels: enterprise overrides personal, personal overrides project. A skill at any level overrides a bundled skill of the same name. Plugin skills use plugin-name:skill-name namespace so they cannot conflict.", "If a skill and a .claude/commands/ command share the same name, the skill takes precedence. A file at .claude/commands/deploy.md and a skill at .claude/skills/deploy/SKILL.md both create /deploy.", "The command name comes from the skill's DIRECTORY name (.claude/skills/deploy-staging/ -> /deploy-staging), not the frontmatter `name` field. `name` only sets the display label, EXCEPT for a plugin-root SKILL.md where `name` (fallback: plugin dir name) sets the command.", "Nested .claude/skills/ directories below the working dir load on demand when Claude reads/edits files there (monorepo support). On name clash the nested one is directory-qualified, e.g. apps/web:deploy; invoke explicitly with /apps/web:deploy. /deploy runs the project-root variant.", "Project skills load from .claude/skills/ in the starting dir AND every parent dir up to the repo root.", "Frontmatter fields (all optional, only description recommended): name, description, when_to_use, argument-hint, arguments, disable-model-invocation, user-invocable, allowed-tools, disallowed-tools, model, effort, context, agent, hooks, paths, shell.", "Combined description + when_to_use text is truncated at 1,536 characters in the skill listing; put the key use case first. Cap configurable via maxSkillDescriptionChars setting.", "allowed-tools grants the listed tools without per-use approval while the skill is active; it does NOT restrict other tools (every tool remains callable, permission settings still govern). Accepts space/comma string or YAML list. Supports patterns like Bash(git add *).", "disallowed-tools removes tools from Claude's pool while the skill is active; the restriction clears on the user's next message.", "For project .claude/skills/ skills, allowed-tools takes effect only after accepting the workspace trust dialog, same as .claude/settings.json permission rules.", "disable-model-invocation:true: only user invokes; description NOT in context; also prevents preloading into subagents. user-invocable:false: only Claude invokes; hidden from / menu; description still always in context.", "context:fork runs the skill in a forked subagent; agent field selects the subagent type (Explore, Plan, general-purpose, or custom from .claude/agents/); default general-purpose. Explore/Plan agents skip CLAUDE.md and git status.", "String substitutions: $ARGUMENTS (all args), $ARGUMENTS[N]/$N (0-based positional), $name (declared in `arguments` frontmatter), ${CLAUDE_SESSION_ID}, ${CLAUDE_EFFORT}, ${CLAUDE_SKILL_DIR} (dir containing SKILL.md). If $ARGUMENTS absent but args passed, Claude Code appends 'ARGUMENTS: <value>'.", "Auto-compaction re-attaches the most recent invocation of each skill after the summary, keeping the first 5,000 tokens each, sharing a combined 25,000-token budget filled from most-recently-invoked; older skills can be dropped entirely.", "Skill description listing budget scales at 1% of the model's context window; raise via skillListingBudgetFraction (e.g. 0.02 = 2%) or SLASH_COMMAND_TOOL_CHAR_BUDGET env var (fixed char count). /doctor shows how many descriptions are shortened/dropped.", "Skill permission rules: deny the Skill tool to disable all skills; Skill(name) exact match, Skill(name *) prefix match with any args; allow/deny specific skills in /permissions.", "skillOverrides (settings.json / .claude/settings.local.json) values: on (name+description, in menu), name-only (name only, in menu), user-invocable-only (hidden from Claude, in menu), off (hidden everywhere). Absent = treated as on. /skills menu writes it (Space to cycle, Enter to save). Plugin skills NOT affected.", "Bundled skills (/code-review, /batch, /debug, /loop, /claude-api, /run, /verify, etc.) are available every session unless disabled via disableBundledSkills setting. They are prompt-based, invoked like any skill.", "disableSkillShellExecution:true disables !`command` shell injection for user/project/plugin/additional-dir skills (replaced with '[shell command execution disabled by policy]'); bundled and managed skills unaffected. Most useful in managed settings where users can't override.", "--add-dir and /add-dir are an exception: .claude/skills/ within an added dir IS loaded automatically. The permissions.additionalDirectories settings.json key grants file access only and does NOT load skills. Commands/output-styles from added dirs are not loaded.", "Live change detection: adding/editing/removing a SKILL.md under watched dirs takes effect within the session without restart. Creating a NEW top-level skills dir that didn't exist at session start requires a restart. Covers SKILL.md text only; plugin hooks/.mcp.json/agents/output-styles need /reload-plugins.", "paths frontmatter (glob patterns, comma-string or YAML list) limits automatic activation to files matching the patterns; same format as path-specific memory rules.", "A few built-in commands are available through the Skill tool: /init, /review, /security-review. /compact and most others are not.", "Adding a .claude-plugin/plugin.json to a skill folder makes it load as a plugin <name>@skills-dir that can bundle agents, hooks, MCP servers; in a project's .claude/skills/ this requires accepting the workspace trust dialog."]}, "Enterprise providers & gateways": {"pages": ["amazon-bedrock", "claude-platform-on-aws", "google-vertex-ai", "llm-gateway", "microsoft-foundry"], "bestPractices": ["For multi-user/team rollouts, pin specific Bedrock model IDs (ANTHROPIC_DEFAULT_OPUS/SONNET/HAIKU_MODEL) before distributing, so aliases like `sonnet`/`opus` don't silently resolve to Claude Code's built-in default (which can lag the newest release or be unavailable in your account).", "For scripted/CI/enterprise rollouts, use the manual env-var setup path rather than the interactive wizard; put secrets like AWS_PROFILE in settings files (not exported env) to avoid leaking them to other processes.", "Grant bedrock:GetInferenceProfile to avoid an extra round-trip per new model when resolving application-inference-profile ARNs — especially important for AWS_BEARER_TOKEN_BEDROCK deployments with narrow token policies.", "To expose multiple versions of one model family in the /model picker each routed to its own org-governed inference profile, use the `modelOverrides` settings map (ARN per version) so users can switch versions without bypassing the org's inference profiles.", "Use AWS Bedrock Guardrails (via ANTHROPIC_CUSTOM_HEADERS) for org-wide content filtering; enable Cross-Region inference on the Guardrail when using cross-region inference profiles.", "Create a dedicated AWS account for Claude Code to simplify cost tracking and access control.", "For corporate SSO/VPN/TLS-inspection environments, run `aws sso login` manually before launching Claude Code and remove `awsAuthRefresh` from settings to avoid the browser-tab auth loop.", "Tune cost vs latency with ANTHROPIC_BEDROCK_SERVICE_TIER (flex = cheaper, priority = lower latency); use ENABLE_PROMPT_CACHING_1H only when the higher billing rate is justified by reuse across >5 min.", "Use `/status` after setup to confirm the resolved region, provider (Bedrock vs Mantle), and region source before rolling out.", "Set ANTHROPIC_DEFAULT_HAIKU_MODEL to a Haiku model available in your account so background tasks (session titles, etc.) use a cheap small/fast model instead of defaulting to the primary model on Bedrock.", "For team deployments, pin all model IDs explicitly (ANTHROPIC_DEFAULT_*_MODEL) so a new model release doesn't move the whole team at once.", "Scope the workspace API key per-machine using the user settings file env block (~/.claude settings) rather than exporting ANTHROPIC_AWS_API_KEY globally; treat it like any production credential.", "Configure awsAuthRefresh in settings.json with your SSO login command so mid-session credential expiry auto-recovers instead of failing.", "Prefer SigV4 + IAM roles for CI runners (set AWS_REGION, attach a role) and reserve long-lived workspace API keys for cases where you don't want to manage federated AWS credentials.", "Run /status first when debugging to confirm the resolved provider, workspace ID, region, and auth settings before changing env vars.", "Use the AWS-linked org's workspace ID and keys — not credentials from a pre-existing Claude Console org — since they are separate orgs with non-transferable credentials.", "Set ENABLE_PROMPT_CACHING_1H=1 only when the higher 1-hour cache-write billing is justified by reuse; otherwise rely on the automatic 5-minute caching.", "Pin specific model versions (ANTHROPIC_DEFAULT_OPUS/SONNET/HAIKU_MODEL) before any multi-user rollout so users don't get aliases that lag or aren't enabled in your project, and you control upgrade timing.", "Use the manual env-var setup (CLAUDE_CODE_USE_VERTEX=1, CLOUD_ML_REGION, ANTHROPIC_VERTEX_PROJECT_ID) for CI and scripted enterprise rollouts rather than the interactive wizard.", "Create a dedicated GCP project for Claude Code to simplify cost tracking and access control.", "Grant the least privilege: roles/aiplatform.user, or a custom role limited to aiplatform.endpoints.predict.", "Explicitly set ANTHROPIC_DEFAULT_HAIKU_MODEL to a model enabled in your project so cheap background tasks (e.g. session titles) use Haiku instead of falling back to the costlier primary model.", "Prefer CLOUD_ML_REGION=global for better availability; for models lacking global endpoints, set per-model VERTEX_REGION_CLAUDE_* overrides instead of switching everything to a region.", "For team auth that must refresh unattended, configure gcpAuthRefresh in settings.json (note its 3-minute timeout and that project-scoped settings require accepting the workspace trust prompt).", "Set ENABLE_PROMPT_CACHING_1H=1 only when the latency/hit-rate benefit outweighs the higher 1-hour cache-write billing.", "If you rely on MCP-heavy setups on Sonnet 4.5+/Opus 4.5+, opt into ENABLE_TOOL_SEARCH=true to avoid loading all MCP tool defs upfront (it's off by default on Vertex).", "For team gateway use, prefer LiteLLM's unified Anthropic-format endpoint (ANTHROPIC_BASE_URL=host:4000) over pass-through endpoints: it provides load balancing, fallbacks, and consistent cost + end-user tracking.", "Use X-Claude-Code-Session-Id at the proxy to aggregate per-session usage, and X-Claude-Code-Agent-Id / X-Claude-Code-Parent-Agent-Id to attribute cost to individual parallel/nested subagents — all without parsing request bodies.", "For per-user auth or rotating keys, use apiKeyHelper (script generating a JWT with user/team claims) plus CLAUDE_CODE_API_KEY_HELPER_TTL_MS to set refresh cadence, rather than a single shared static key.", "Keep CLAUDE_CODE_ENABLE_GATEWAY_MODEL_DISCOVERY off (default) when the gateway is backed by a shared API key, so individual users do not see every model the key can access; enable it only for curated gateways.", "Ensure the gateway forwards anthropic-beta and anthropic-version headers (or preserves the body fields for Bedrock); not forwarding them silently degrades Claude Code features.", "If the gateway runs its own prompt cache keyed on the full request body, set CLAUDE_CODE_ATTRIBUTION_HEADER=0 so the per-conversation attribution block does not bust the cache.", "Distribute gateway env vars / settings to the team via the settings.json env block (or enterprise managed settings) rather than relying on per-developer shell exports.", "Before rolling Claude Code out to multiple users on Foundry, pin specific model versions for every deployment via ANTHROPIC_DEFAULT_OPUS/SONNET/HAIKU_MODEL — model aliases otherwise resolve to Claude Code's built-in Foundry default which can lag the newest release and may be unavailable in your account.", "When creating Azure deployments, select a specific model version rather than 'auto-update to latest' to guarantee the pinned ID exists and stays stable across the team.", "Set ANTHROPIC_DEFAULT_HAIKU_MODEL to an available Haiku deployment so cheap background tasks (session titles, etc.) don't fall back to running on the expensive primary model.", "For enterprise rollouts use Entra ID (DefaultAzureCredential) rather than static API keys, and grant the 'Azure AI User' or 'Cognitive Services User' role (or a custom role limited to Microsoft.CognitiveServices/accounts/providers/*) for least privilege.", "Set ENABLE_PROMPT_CACHING_1H=1 only when the higher per-write billing of a 1-hour TTL is justified by reuse patterns; otherwise rely on the automatic 5-minute caching."], "gotchas": ["Without model pinning, `sonnet`/`opus` aliases resolve to Claude Code's built-in Bedrock default which can lag the newest release and may not be enabled in your account; the `opus` alias defaults to Opus 4.6, not the latest.", "On Bedrock, the small/fast (background-task) model defaults to the PRIMARY model — not Haiku — because Haiku may not be enabled in every account/region; you pay primary-model rates for background tasks unless you set ANTHROPIC_DEFAULT_HAIKU_MODEL.", "On Claude Code v2.1.171 and earlier, the AWS config file's `region` is NOT read — you must set AWS_REGION explicitly or it falls back to us-east-1.", "`awsCredentialExport` runs on every credential reload (even when valid) and its output is silent; `awsAuthRefresh` only runs when creds are detected expired — choosing the wrong one causes either over-running commands or stale creds.", "AWS SSO behind corporate VPN/TLS-inspection proxies can cause an infinite auth loop (repeated browser tabs) with `awsAuthRefresh` because interrupted connections are treated as auth failures.", "WebSearch tool is unavailable on Bedrock; /logout is unavailable on Bedrock.", "Claude Code uses only the Bedrock Invoke API, not the Converse API; an 'on-demand throughput isn't supported' error means you must specify the model as an inference profile ID.", "Prompt caching may not be available in all Bedrock regions — silently no caching (cache token counts stay at zero); verify against Bedrock's supported regions list.", "Mantle has a separate model lineup: inference-profile IDs like us.anthropic.claude-sonnet-4-6 won't work on Mantle (400 naming the model ID); a 403 with valid creds means the account lacks access to that Mantle model.", "Mantle model IDs use the `anthropic.` prefix without a version suffix and differ from standard Bedrock catalog IDs; mixing them up routes requests to the wrong endpoint.", "Startup model checks require v2.1.94+; on older versions the auto-pin-update prompt and fallback behavior don't apply.", "Unpinned fallback to a previous model version is per-session and NOT persisted, so behavior can silently differ run-to-run depending on account model availability.", "Claude Platform on AWS is opt-in even when AWS credentials are present; Bedrock and Foundry silently take precedence in provider routing, so requests can go to the wrong provider if CLAUDE_CODE_USE_BEDROCK/FOUNDRY remain set.", "ANTHROPIC_AWS_API_KEY silently overrides SigV4 — a stale key produces 403s even with valid AWS credentials present.", "Workspace ID is not derived from AWS credentials; forgetting ANTHROPIC_AWS_WORKSPACE_ID causes a missing-workspace error on every request.", "AWS Marketplace subscription creates a brand-new Anthropic org separate from any existing one; using old-org API keys silently fails to authenticate.", "Default opus alias lags releases (resolves to Opus 4.7 without override), so unpinned teams may run an older model than expected.", "/login and /logout don't manage auth here (no Claude.ai subscription path); the only meaningful /login action is the awsAuthRefresh-driven 'refresh credentials' option.", "CLAUDE_CODE_USE_ANTHROPIC_AWS must parse as truthy (set to 1); a non-truthy value silently leaves requests going to api.anthropic.com.", "Model alias trap: without pinning, 'opus' on Vertex resolves to Opus 4.6 (not the latest 4.8), and aliases may resolve to a model not yet enabled in your project.", "ANTHROPIC_VERTEX_PROJECT_ID is the LOWEST-precedence project source — GCLOUD_PROJECT, GOOGLE_CLOUD_PROJECT, and the GOOGLE_APPLICATION_CREDENTIALS file all override it, so a stale env/credential file can silently send requests to the wrong project.", "On Vertex the small/fast model defaults to the PRIMARY (expensive) model, so background tasks cost more than expected unless you set ANTHROPIC_DEFAULT_HAIKU_MODEL.", "MCP tool search is off by default on Vertex; enabling ENABLE_TOOL_SEARCH=true on models older than Sonnet 4.5 / Opus 4.5 makes requests FAIL (they reject the beta header).", "CLOUD_ML_REGION=global causes 'model not found' 404s for models that don't support global endpoints — must specify a supported model or a VERTEX_REGION_* override.", "429 errors on regional endpoints often mean the primary or small/fast model isn't supported in that region; switching to global usually helps.", "/logout is unavailable under Vertex AI auth.", "Unpinned model fallback at startup is per-session and not persisted — behavior can silently change run-to-run as defaults/availability shift.", "Model Garden access approval can take 24-48 hours, so models aren't immediately invokable after requesting.", "Setup wizard and startup model checks require v2.1.98+; X.509 WIF requires v2.1.121+ — older clients silently lack these.", "gcpAuthRefresh does not support interactive input and times out after 3 minutes; project-level gcpAuthRefresh only runs after the workspace trust prompt is accepted.", "apiKeyHelper is silently overridden by ANTHROPIC_AUTH_TOKEN or ANTHROPIC_API_KEY (lower precedence) — a stray env var defeats dynamic per-user keys.", "Model discovery is off by default and requires v2.1.129+; even when on, it only surfaces models whose ID starts with 'claude'/'anthropic' and only for the Anthropic Messages format — Bedrock/Vertex pass-through and api.anthropic.com get no discovery.", "Gateway-discovered models that don't match the claude/anthropic ID prefix won't appear in /model; you must add them manually via model-config vars.", "Using Anthropic Messages format over Bedrock/Vertex can require CLAUDE_CODE_DISABLE_EXPERIMENTAL_BETAS=1, otherwise beta features may break.", "A gateway that drops anthropic-beta/anthropic-version headers causes reduced functionality with no obvious error.", "The attribution block prepended to the system prompt can invalidate a gateway's own full-body prompt cache unless CLAUDE_CODE_ATTRIBUTION_HEADER=0 is set (it does not affect first-party Anthropic caching).", "LiteLLM is third-party and unaudited by Anthropic; the 1.82.7/1.82.8 malware incident shows version pinning and supply-chain caution are required.", "Foundry performs NO startup model check — a missing/unavailable default model surfaces as a runtime request failure, not an early config error.", "If ANTHROPIC_DEFAULT_OPUS_MODEL is unset, `opus` silently resolves to Opus 4.6 (not the latest), so teams can unknowingly run an older model.", "Background/small-model tasks default to the PRIMARY (expensive) model on Foundry unless ANTHROPIC_DEFAULT_HAIKU_MODEL points to a real Haiku deployment — a silent cost inflation.", "/logout is unavailable on Foundry; auth is entirely via Azure credentials.", "No interactive setup wizard exists for Foundry (unlike Bedrock/Vertex), so missing env vars yield no guided prompts — all config must be in the environment.", "1-hour prompt cache TTL (ENABLE_PROMPT_CACHING_1H=1) is billed at a higher write rate than the default 5-minute cache."], "claims": ["Enable Bedrock with `export CLAUDE_CODE_USE_BEDROCK=1`. `AWS_REGION` is optional if the AWS profile already sets a region.", "Region resolution precedence (v2.1.172+): AWS_REGION > AWS_DEFAULT_REGION > region on active AWS profile (shared credentials file then shared config file) > us-east-1. Active profile is AWS_PROFILE if set, else `default`. On v2.1.171 and earlier Claude Code does NOT read AWS config files, so set AWS_REGION explicitly.", "Run `/status` to see the resolved region; it also notes the source when the region came from AWS config files or the default fallback.", "Set `AWS_SHARED_CREDENTIALS_FILE` or `AWS_CONFIG_FILE` to point at non-default AWS file paths.", "Credentials use the default AWS SDK credential chain. Auth options: `aws configure`; access key env vars (AWS_ACCESS_KEY_ID, AWS_SECRET_ACCESS_KEY, AWS_SESSION_TOKEN); SSO profile (`aws sso login --profile=<name>` + AWS_PROFILE); `aws login` (console creds); Bedrock API key via `export AWS_BEARER_TOKEN_BEDROCK=<key>`.", "`awsAuthRefresh` (settings) runs only when Claude Code detects expired AWS credentials (by timestamp or a Bedrock credential error), then retries. Use for commands that modify the .aws directory (SSO login). Output shown to user; no interactive input.", "`awsCredentialExport` (settings) runs at session start and on each credential reload even when current creds are valid. Use only when you can't modify .aws and must return cross-account creds directly. Output captured silently. Must output JSON with Credentials.{AccessKeyId,SecretAccessKey,SessionToken,Expiration}.", "As of v2.1.181, flat output from `aws configure export-credentials --format process` is accepted (keys at top level, not nested under Credentials).", "As of v2.1.176, when awsCredentialExport returns a valid ISO 8601 Expiration, creds are cached until 5 minutes before that time; without it (or earlier versions), creds cached for 1 hour. Expiration is optional.", "Pin models per family with env vars: ANTHROPIC_DEFAULT_OPUS_MODEL, ANTHROPIC_DEFAULT_SONNET_MODEL, ANTHROPIC_DEFAULT_HAIKU_MODEL. Example values: us.anthropic.claude-opus-4-8, us.anthropic.claude-sonnet-4-6, us.anthropic.claude-haiku-4-5-20251001-v1:0.", "Without pinning, the `opus` alias on Bedrock resolves to Opus 4.6; set ANTHROPIC_DEFAULT_OPUS_MODEL to the Opus 4.8 ID to use the latest.", "Default models when no pinning vars are set: primary model = us.anthropic.claude-sonnet-4-5-20250929-v1:0; small/fast model = same as primary model.", "Model IDs use cross-region inference profile prefix `us.`; in AWS GovCloud use `us-gov.` prefix.", "Override primary model with ANTHROPIC_MODEL (inference profile ID or application-inference-profile ARN). Background tasks (e.g. session titles) use the small/fast model; on Bedrock this defaults to the primary model because Haiku may not be enabled — set ANTHROPIC_DEFAULT_HAIKU_MODEL to use Haiku.", "`ANTHROPIC_SMALL_FAST_MODEL_AWS_REGION` overrides the AWS region for the small/fast model; on Bedrock it has no effect unless ANTHROPIC_DEFAULT_HAIKU_MODEL (or deprecated ANTHROPIC_SMALL_FAST_MODEL) is set.", "`ANTHROPIC_BEDROCK_BASE_URL` overrides the Bedrock endpoint URL for custom endpoints/gateways.", "Prompt caching: DISABLE_PROMPT_CACHING=1 disables it; ENABLE_PROMPT_CACHING_1H=1 requests a 1-hour cache TTL (billed higher than the 5-minute default). Caching may be unavailable in some Bedrock regions — if cache token counts stay at zero, check Bedrock supported models/regions.", "`modelOverrides` settings map maps specific model version IDs to distinct application-inference-profile ARNs so multiple versions of a family appear in the /model picker, each routed to its own ARN.", "Startup model checks require Claude Code v2.1.94+. If a pinned version is older than the current default and the account can invoke the newer version, Claude Code prompts to update the pin (writes to user settings + restarts). ARN-pinned models are skipped. If unpinned and the default is unavailable, it falls back to the previous version for the session (not persisted) with a notice.", "Required IAM actions: bedrock:InvokeModel, bedrock:InvokeModelWithResponseStream, bedrock:ListInferenceProfiles, bedrock:GetInferenceProfile on inference-profile/*, application-inference-profile/*, foundation-model/* ; plus aws-marketplace:ViewSubscriptions and aws-marketplace:Subscribe (conditioned on aws:CalledViaLast = bedrock.amazonaws.com).", "bedrock:GetInferenceProfile lets Claude Code resolve an application-inference-profile ARN to its backing foundation model (to pick the correct request shape). If missing, it retries once with the alternate shape (extra round-trip per new model). Most relevant for AWS_BEARER_TOKEN_BEDROCK deployments with narrow token policies.", "AWS Organizations: submit the use-case form once from the management account via the PutUseCaseForModelAccess API (requires bedrock:PutUseCaseForModelAccess); approval extends to child accounts automatically.", "1M token context window supported on Bedrock for Opus 4.6+ and Sonnet 4.6; auto-enabled when a 1M model variant is selected. For a manually pinned model, append `[1m]` to the model ID.", "Service tiers: set ANTHROPIC_BEDROCK_SERVICE_TIER to `default`, `flex`, or `priority` (sent as X-Amzn-Bedrock-Service-Tier header). Availability varies by model/region. Provisioned throughput uses a provisioned-throughput ARN as the model ID instead.", "AWS Guardrails: set via ANTHROPIC_CUSTOM_HEADERS in settings env block with `X-Amzn-Bedrock-GuardrailIdentifier: <id>` and `X-Amzn-Bedrock-GuardrailVersion: <n>`. Enable Cross-Region inference on the Guardrail if using cross-region inference profiles.", "Mantle endpoint (native Anthropic API shape, requires v2.1.94+): enable with CLAUDE_CODE_USE_MANTLE=1. Mantle model IDs are prefixed `anthropic.` without a version suffix (e.g. anthropic.claude-haiku-4-5). ANTHROPIC_BEDROCK_MANTLE_BASE_URL overrides the URL; CLAUDE_CODE_SKIP_MANTLE_AUTH=1 skips client-side SigV4/x-api-key auth for gateway setups.", "Setting both CLAUDE_CODE_USE_BEDROCK=1 and CLAUDE_CODE_USE_MANTLE=1 routes Mantle-format model IDs to Mantle and all others to the Bedrock Invoke API. Add Mantle model IDs to `availableModels` in settings to surface them in /model (this setting also restricts the picker to listed entries).", "On Bedrock, /logout is unavailable (auth via AWS credentials). The WebSearch tool is not available on Bedrock. Claude Code uses the Bedrock Invoke API and does NOT support the Converse API.", "Run `/setup-bedrock` any time to reopen the login wizard and change credentials, region, or model pins. The wizard saves results to the env block of the user settings file.", "Set CLAUDE_CODE_USE_ANTHROPIC_AWS=1 to route Claude Code through Claude Platform on AWS instead of the default Anthropic API.", "ANTHROPIC_AWS_WORKSPACE_ID is required and is sent on every request as the anthropic-workspace-id header; it is NOT implied by AWS credentials. Format example: wrkspc_01ABCDEFGHIJKLMN.", "The base URL is computed from AWS_REGION as https://aws-external-anthropic.{region}.api.aws. Override it directly with ANTHROPIC_AWS_BASE_URL.", "Two auth methods: (A) AWS credentials with SigV4 via the standard AWS credential chain (env vars, ~/.aws/credentials, IAM roles, AWS SSO); (B) workspace API key set as ANTHROPIC_AWS_API_KEY (sent as x-api-key).", "ANTHROPIC_AWS_API_KEY takes precedence over SigV4 — when set, any AWS credentials in the environment are ignored.", "Subscribing through AWS Marketplace provisions a NEW Anthropic organization tied to your AWS account, separate from any pre-existing Anthropic/Claude Console org. Credentials and API keys do NOT transfer between them; you must use the workspace ID and API keys from the AWS-linked org.", "Provider routing precedence: Bedrock (CLAUDE_CODE_USE_BEDROCK) and Foundry (CLAUDE_CODE_USE_FOUNDRY) take precedence over Claude Platform on AWS. Unset both if Claude Platform on AWS should be used.", "awsAuthRefresh in settings.json (e.g. {\"awsAuthRefresh\": \"aws sso login --profile my-profile\"}) re-runs the login command when SSO credentials expire mid-session and retries instead of failing; adds a 'refresh credentials' option under /login.", "For CI/automation: give the runner an IAM role with permission to invoke the Anthropic service and set AWS_REGION; the credential chain picks the role up automatically. The AWS CLI is only required for the SSO login flow.", "Default model aliases fable, opus, sonnet, haiku resolve to Claude Code's built-in defaults for Claude Platform on AWS, which can lag the newest release. Without ANTHROPIC_DEFAULT_OPUS_MODEL set, the opus alias resolves to Opus 4.7.", "Pin model versions for teams via ANTHROPIC_DEFAULT_FABLE_MODEL, ANTHROPIC_DEFAULT_OPUS_MODEL, ANTHROPIC_DEFAULT_SONNET_MODEL, ANTHROPIC_DEFAULT_HAIKU_MODEL (e.g. claude-opus-4-7, claude-sonnet-4-6, claude-haiku-4-5, claude-fable-5).", "Prompt caching is enabled automatically. Set ENABLE_PROMPT_CACHING_1H=1 to request a 1-hour cache TTL instead of the 5-minute default; 1-hour cache writes are billed at a higher rate.", "Corporate proxy / LLM gateway: set ANTHROPIC_AWS_BASE_URL to the proxy address. If the gateway signs requests itself, set CLAUDE_CODE_SKIP_ANTHROPIC_AWS_AUTH=1 so Claude Code sends unsigned requests. If the gateway requires its own token, set ANTHROPIC_AUTH_TOKEN.", "The Agent SDK (@anthropic-ai/claude-agent-sdk) reads the same env vars as the CLI; export CLAUDE_CODE_USE_ANTHROPIC_AWS, ANTHROPIC_AWS_WORKSPACE_ID, and either ANTHROPIC_AWS_API_KEY or AWS credentials before the call.", "/login and /logout do NOT sign into a Claude.ai subscription for Claude Platform on AWS; auth is purely via AWS credentials or workspace API key. The only /login action that works is the 'refresh credentials' option when awsAuthRefresh is configured.", "/status shows the resolved provider plus any configured workspace ID, region, base URL override, and auth-skip setting — fastest way to confirm Claude Code is targeting Claude Platform on AWS.", "403 Forbidden / AccessDenied on every request means the IAM principal lacks aws-external-anthropic invoke permissions, OR a stale ANTHROPIC_AWS_API_KEY (which takes precedence over SigV4).", "Requests still going to api.anthropic.com means CLAUDE_CODE_USE_ANTHROPIC_AWS is unset/non-truthy, or CLAUDE_CODE_USE_BEDROCK/CLAUDE_CODE_USE_FOUNDRY is set and taking precedence.", "Enable Vertex AI by setting env vars: CLAUDE_CODE_USE_VERTEX=1, CLOUD_ML_REGION=global (or a region/multi-region), ANTHROPIC_VERTEX_PROJECT_ID=YOUR-PROJECT-ID.", "CLOUD_ML_REGION accepts 'global', a multi-region location ('eu' or 'us'), or a specific region (e.g. 'us-east5'). Claude Code picks the correct Vertex hostname per form, including aiplatform.eu.rep.googleapis.com and aiplatform.us.rep.googleapis.com for multi-region.", "Project ID precedence for Vertex: GCLOUD_PROJECT, GOOGLE_CLOUD_PROJECT, and the credential file referenced by GOOGLE_APPLICATION_CREDENTIALS all take precedence over ANTHROPIC_VERTEX_PROJECT_ID. If none set, project resolves from gcloud config or attached service account.", "GOOGLE_APPLICATION_CREDENTIALS points to a service account key file or an X.509 Workload Identity Federation credential configuration file (X.509 WIF supported in Claude Code v2.1.121+).", "gcpAuthRefresh setting (settings.json) runs a command to refresh expired GCP credentials before retrying. Example: {\"gcpAuthRefresh\": \"gcloud auth application-default login\"}. No interactive input supported; times out after 3 minutes. In project settings (.claude/settings.json) it runs only after accepting the workspace trust prompt.", "ANTHROPIC_VERTEX_BASE_URL overrides the Vertex endpoint URL for custom endpoints or gateways (e.g. https://aiplatform.googleapis.com).", "Pin models for multi-user rollout: ANTHROPIC_DEFAULT_OPUS_MODEL, ANTHROPIC_DEFAULT_SONNET_MODEL, ANTHROPIC_DEFAULT_HAIKU_MODEL. Example: ANTHROPIC_DEFAULT_OPUS_MODEL='claude-opus-4-8', ANTHROPIC_DEFAULT_SONNET_MODEL='claude-sonnet-4-6', ANTHROPIC_DEFAULT_HAIKU_MODEL='claude-haiku-4-5@20251001'.", "Without ANTHROPIC_DEFAULT_OPUS_MODEL, the 'opus' alias on Vertex resolves to Opus 4.6; set it to the Opus 4.8 ID to use the latest.", "ANTHROPIC_MODEL overrides the primary model (e.g. 'claude-opus-4-8').", "Default models when no pinning vars set: primary = claude-sonnet-4-5@20250929; small/fast = same as primary. On Vertex, the small/fast (Haiku-class) model defaults to the PRIMARY model because Haiku may not be enabled in every project/region; set ANTHROPIC_DEFAULT_HAIKU_MODEL to use Haiku for background tasks (e.g. session title generation).", "When CLOUD_ML_REGION=global, override per-model regions with VERTEX_REGION_CLAUDE_* vars, e.g. VERTEX_REGION_CLAUDE_HAIKU_4_5=us-east5, VERTEX_REGION_CLAUDE_4_6_SONNET=europe-west1, for models that don't support global endpoints.", "Prompt caching is enabled automatically. DISABLE_PROMPT_CACHING=1 disables it. ENABLE_PROMPT_CACHING_1H=1 requests a 1-hour cache TTL instead of the 5-minute default; 1-hour TTL cache writes are billed at a higher rate.", "MCP tool search is DISABLED by default on Vertex AI, so MCP tool definitions load upfront. Set ENABLE_TOOL_SEARCH=true to enable it; supported only on Sonnet 4.5+ and Opus 4.5+. Enabling it on earlier Vertex models fails (they reject the required beta header).", "1M token context window supported on Vertex for Opus 4.6+ and Sonnet 4.6; auto-enabled for 1M model variants. For a manually pinned model, append [1m] to the model ID to enable it.", "IAM: roles/aiplatform.user grants the required aiplatform.endpoints.predict permission (model invocation + token counting). A custom role with only that permission also works.", "The Vertex setup wizard requires Claude Code v2.1.98+; it saves config to the env block of the user settings file. Re-run anytime with /setup-vertex. Startup model checks also require v2.1.98+.", "At startup Claude Code verifies pinned/default models are accessible. If a pinned version is older than the current default and the newer is invokable, it prompts to update the pin (writes new ID to user settings + restarts); declining is remembered until next default change. If unpinned and default unavailable, it falls back to the previous version for the session (not persisted).", "When using Vertex AI the /logout command is unavailable (auth is via Google Cloud credentials).", "Model access in Vertex AI Model Garden must be requested and approved (may take 24-48 hours) before models are invokable.", "Stated current model IDs/aliases (as of this doc): Opus 4.8 = claude-opus-4-8, Sonnet 4.6 = claude-sonnet-4-6, Haiku 4.5 = claude-haiku-4-5@20251001, default Sonnet = claude-sonnet-4-5@20250929; 'opus' alias defaults to Opus 4.6.", "For heightened rate limits on Vertex, contact Google Cloud support.", "A gateway must expose at least one of three API formats: Anthropic Messages (/v1/messages, /v1/messages/count_tokens), Bedrock InvokeModel (/invoke, /invoke-with-response-stream), or Vertex rawPredict (:rawPredict, :streamRawPredict, /count-tokens:rawPredict).", "Anthropic Messages and Vertex rawPredict gateways must forward request headers anthropic-beta and anthropic-version; Bedrock InvokeModel must preserve request body fields anthropic_beta and anthropic_version. Failure causes reduced functionality.", "When using Anthropic Messages format with Bedrock or Vertex, you may need to set CLAUDE_CODE_DISABLE_EXPERIMENTAL_BETAS=1.", "Claude Code sends header X-Claude-Code-Session-Id (unique per session) so proxies can aggregate all requests from a session without parsing the body.", "Header X-Claude-Code-Agent-Id identifies the subagent/teammate issuing a request (present only for in-process subagent/teammate requests); X-Claude-Code-Parent-Agent-Id identifies the spawning agent. Both are ephemeral per-spawn IDs, not persistent user/device IDs. Use them to attribute cost across nested parallel agents.", "Claude Code prepends a short attribution block to the system prompt (client version + conversation fingerprint). The Anthropic API strips it before processing so it does not affect first-party prompt caching. If your gateway has its own prompt cache keyed on the full request body, set CLAUDE_CODE_ATTRIBUTION_HEADER=0 to omit it.", "Gateway model discovery: when ANTHROPIC_BASE_URL points at an Anthropic Messages gateway, set CLAUDE_CODE_ENABLE_GATEWAY_MODEL_DISCOVERY=1 to query the gateway's /v1/models at startup and add models to the /model picker. Off by default. Requires Claude Code v2.1.129 or later.", "Model discovery only adds models whose ID begins with 'claude' or 'anthropic'; entries are labeled 'From gateway' using the response display_name. It only runs for Anthropic Messages format, not Bedrock/Vertex pass-through, and not when ANTHROPIC_BASE_URL is unset or points at api.anthropic.com.", "Discovery results are cached to ~/.claude/cache/gateway-models.json, refreshed each startup; on failure or no /v1/models endpoint the picker falls back to the cached list or the built-in model list.", "Discovery authenticates like inference: sends ANTHROPIC_AUTH_TOKEN as bearer token, or ANTHROPIC_API_KEY as x-api-key header when no auth token is set, plus any headers from ANTHROPIC_CUSTOM_HEADERS.", "For models whose names do not match the discovery filter, add them manually via the variables in Model configuration (/en/model-config).", "Static API key: set ANTHROPIC_AUTH_TOKEN (env or settings.json env block); this value is sent as the Authorization header.", "Dynamic key: configure apiKeyHelper in settings.json pointing to a script (e.g. fetch from vault or generate a JWT). Its output is sent as both Authorization and X-Api-Key headers.", "apiKeyHelper has LOWER precedence than ANTHROPIC_AUTH_TOKEN or ANTHROPIC_API_KEY.", "Set CLAUDE_CODE_API_KEY_HELPER_TTL_MS to control token refresh interval in milliseconds (e.g. 3600000 = 1 hour).", "LiteLLM unified endpoint (recommended): export ANTHROPIC_BASE_URL=https://litellm-server:4000 — gives load balancing, fallbacks, and consistent cost/end-user tracking versus pass-through.", "LiteLLM Anthropic pass-through: ANTHROPIC_BASE_URL=https://litellm-server:4000/anthropic.", "LiteLLM Bedrock pass-through: ANTHROPIC_BEDROCK_BASE_URL=https://litellm-server:4000/bedrock, CLAUDE_CODE_SKIP_BEDROCK_AUTH=1, CLAUDE_CODE_USE_BEDROCK=1.", "LiteLLM Vertex pass-through: ANTHROPIC_VERTEX_BASE_URL=https://litellm-server:4000/vertex_ai/v1, ANTHROPIC_VERTEX_PROJECT_ID=<gcp-project>, CLAUDE_CODE_SKIP_VERTEX_AUTH=1, CLAUDE_CODE_USE_VERTEX=1, CLOUD_ML_REGION=us-east5.", "Claude Platform on AWS via gateway: ANTHROPIC_AWS_BASE_URL=https://litellm-server:4000/anthropic-aws, ANTHROPIC_AWS_WORKSPACE_ID=wrkspc_..., CLAUDE_CODE_SKIP_ANTHROPIC_AWS_AUTH=1, CLAUDE_CODE_USE_ANTHROPIC_AWS=1.", "LiteLLM PyPI versions 1.82.7 and 1.82.8 were compromised with credential-stealing malware; do not install them, remove the package, rotate all credentials, and follow remediation in BerriAI/litellm#24518.", "Enterprise Desktop deployments can configure gateway providers via managed settings; Claude Desktop can run against a self-hosted gateway via Cowork on 3P research preview, which uses its own configuration keys.", "Set CLAUDE_CODE_USE_FOUNDRY=1 to enable the Microsoft Foundry integration.", "ANTHROPIC_FOUNDRY_RESOURCE={resource} specifies the Azure resource name; alternatively ANTHROPIC_FOUNDRY_BASE_URL=https://{resource}.services.ai.azure.com/anthropic gives the full base URL.", "Two auth methods: (A) API key via ANTHROPIC_FOUNDRY_API_KEY=<azure-api-key>; (B) Microsoft Entra ID via Azure SDK DefaultAzureCredential chain (used automatically when ANTHROPIC_FOUNDRY_API_KEY is not set), e.g. local `az login`.", "The /logout command is unavailable on Foundry because auth is handled through Azure credentials.", "Foundry has NO interactive setup wizard (unlike Bedrock and Vertex AI); environment variables are the only configuration path.", "Foundry has no startup model check, so requests fail at call time when the default/aliased model is unavailable in the account.", "Without ANTHROPIC_DEFAULT_OPUS_MODEL set, the `opus` alias on Foundry resolves to Opus 4.6; set ANTHROPIC_DEFAULT_OPUS_MODEL='claude-opus-4-8' to use the latest.", "Model alias env vars: ANTHROPIC_DEFAULT_OPUS_MODEL, ANTHROPIC_DEFAULT_SONNET_MODEL (e.g. 'claude-sonnet-4-6'), ANTHROPIC_DEFAULT_HAIKU_MODEL (e.g. 'claude-haiku-4-5'); values must match the Azure deployment names created in the portal.", "Background tasks (e.g. session title generation) use the small/fast model; on Foundry this defaults to the PRIMARY model because not every account has a Haiku deployment. Set ANTHROPIC_DEFAULT_HAIKU_MODEL to an available Haiku deployment to use Haiku for background tasks.", "Prompt caching is enabled automatically with a 5-minute default TTL. Set ENABLE_PROMPT_CACHING_1H=1 to request a 1-hour cache TTL; 1-hour TTL cache writes are billed at a higher rate.", "Azure RBAC: the built-in roles 'Azure AI User' and 'Cognitive Services User' include all permissions needed to invoke Claude models. A restrictive custom role needs dataAction Microsoft.CognitiveServices/accounts/providers/*.", "Setup requires creating deployments for Claude Opus, Sonnet, and Haiku models in the Microsoft Foundry portal (ai.azure.com).", "Token error 'Failed to get token from azureADTokenProvider: ChainedTokenCredential authentication failed' is resolved by configuring Entra ID on the environment or setting ANTHROPIC_FOUNDRY_API_KEY.", "Current Foundry defaults (as of this doc): opus alias -> Opus 4.6 by default; example latest IDs claude-opus-4-8, claude-sonnet-4-6, claude-haiku-4-5."]}};

// __CHUNK__ (injected)
const themes = Object.entries(CHUNK);
log(`synthesizing ${themes.length} themes`);

const OUT = {
  type: "object", additionalProperties: false, required: ["markdown"],
  properties: { markdown: { type: "string", description: "the clean compendium section in markdown" } },
};

const results = await pipeline(
  themes,
  ([theme, d]) => agent(
    `You are compiling the DEFINITIVE compendium section on "${theme}" for a lead setting up and optimally running Claude Code (+ Codex) for a team. Below are raw extractions pulled from every official docs page in this theme — they are redundant, unordered, and overlapping. Distill them into ONE clean, dense, well-organized reference section in markdown.\n\n` +
    `RULES:\n` +
    `- DEDUPLICATE hard — the raw is very repetitive; each point appears once, in the best-worded form.\n` +
    `- Organize with ## and ### sub-headings by sub-topic; lead with what matters most for a TEAM setup and optimal use.\n` +
    `- Keep EXACT facts: flag names, file paths, setting keys, precedence, limits, commands. Put config/commands/file names in \`\`\` code fences. Use a markdown table where it genuinely helps (e.g. settings keys, precedence).\n` +
    `- End with a "### Gotchas" subsection capturing the pitfalls.\n` +
    `- Be COMPENDIOUS: complete and dense, but zero filler — this is a reference, not a tutorial. Aim for thorough coverage of everything in the raw material that bears on team setup / optimal use / best practices.\n` +
    `- Start the section with a single \`## ${theme}\` heading.\n\n` +
    `SOURCE PAGES: ${d.pages.join(", ")}\n\n` +
    `RAW BEST PRACTICES (${(d.bestPractices || []).length}):\n` + (d.bestPractices || []).map((x) => `- ${x}`).join("\n") +
    `\n\nRAW GOTCHAS (${(d.gotchas || []).length}):\n` + (d.gotchas || []).map((x) => `- ${x}`).join("\n") +
    `\n\nRAW FACTS (${(d.claims || []).length}):\n` + (d.claims || []).map((x) => `- ${x}`).join("\n"),
    { agentType: "general-purpose", effort: "high", schema: OUT, label: theme.slice(0, 28), phase: "Synthesize" },
  ),
);

const out = {};
themes.forEach(([t], i) => { if (results[i]?.markdown) out[t] = results[i].markdown; });
log(`synthesized ${Object.keys(out).length} sections`);
return { sections: out };
